// Reaction is for the "enum" of ways to react to a post
type Reaction int

const (
	Gnod Reaction = iota
	MaxReaction
)

// A Post is a "thread" or a "reply" depending on context.
// A thread is a Post of a UserPosts that holds other replies.
// This is similar to boards.Post except that this doesn't have a title.
type Post struct {
	userPosts  *UserPosts
	id         PostID
	creator    address
	body       string
	replies    bptree.BPTree  // PostID -> *Post
	repliesAll bptree.BPTree  // PostID -> *Post (all replies, for top-level posts)
	reposts    bptree.BPTree  // UserPosts user address -> PostID
	threadID   PostID         // original PostID
	parentID   PostID         // parent PostID (if reply or repost)
	repostUser address        // UserPosts user address of original post (if repost)
	reactions  *bptree.BPTree // Reaction -> *bptree.BPTree of address -> "" (Use the bptree.BPTree keys as the "set" of addresses)
	createdAt  time.Time
}

func newPost(userPosts *UserPosts, id PostID, creator address, body string, threadID, parentID PostID, repostUser address) *Post {
	return &Post{
		userPosts:  userPosts,
		id:         id,
		creator:    creator,
		body:       body,
		replies:    bptree.BPTree{},
		repliesAll: bptree.BPTree{},
		reposts:    bptree.BPTree{},
		threadID:   threadID,
		parentID:   parentID,
		repostUser: repostUser,
		reactions:  bptree.NewBPTree32(),
		createdAt:  time.Now(),
	}
}

func (post *Post) IsThread() bool {
	return post.parentID == 0
}

func (post *Post) GetPostID() PostID {
	return post.id
}

func (post *Post) AddReply(creator address, body string) *Post {
	userPosts := post.userPosts
	pid := userPosts.incGetPostID()
	pidkey := postIDKey(pid)
	reply := newPost(userPosts, pid, creator, body, post.threadID, post.id, "")
	post.replies.Set(pidkey, reply)
	if post.threadID == post.id {
		post.repliesAll.Set(pidkey, reply)
	} else {
		thread := userPosts.GetThread(post.threadID)
		thread.repliesAll.Set(pidkey, reply)
	}
	return reply
}

func (post *Post) AddRepostTo(creator address, comment string, dst *UserPosts) *Post {
	if !post.IsThread() {
		panic("cannot repost non-thread post")
	}

	pid := dst.incGetPostID()
	pidkey := postIDKey(pid)
	repost := newPost(dst, pid, creator, comment, pid, post.id, post.userPosts.userAddr)
	dst.threads.Set(pidkey, repost)
	// Also add to the home posts.
	dst.homePosts.Set(pidkey, repost)
	post.reposts.Set(creator.String(), pid)
	return repost
}

func (post *Post) GetReply(pid PostID) *Post {
	pidkey := postIDKey(pid)
	replyI, ok := post.repliesAll.Get(pidkey)
	if !ok {
		return nil
	} else {
		return replyI.(*Post)
	}
}

// Add the userAddr to the posts.reactions for reaction.
// Create the reaction key in post.reactions if needed.
// If userAddr is already added, do nothing.
// If the userAddr is the post's creator, do nothing. (Don't react to one's own posts.)
// Return a boolean indicating whether the userAddr was added (false if it was already added).
func (post *Post) AddReaction(userAddr address, reaction Reaction) bool {
	validateReaction(reaction)

	if userAddr == post.creator {
		// Don't react to one's own posts.
		return false
	}
	value := getOrCreateReactionValue(post.reactions, reaction)
	if value.Has(userAddr.String()) {
		// Already added.
		return false
	}

	value.Set(userAddr.String(), "")
	return true
}

// Remove the userAddr from the posts.reactions for reaction.
// If userAddr is already removed, do nothing.
// Return a boolean indicating whether the userAddr was found and removed.
func (post *Post) RemoveReaction(userAddr address, reaction Reaction) bool {
	validateReaction(reaction)

	if !post.reactions.Has(reactionKey(reaction)) {
		// There is no entry for reaction, so don't create one.
		return false
	}

	_, removed := getOrCreateReactionValue(post.reactions, reaction).Remove(userAddr.String())
	return removed
}

// Return the count of reactions for the reaction.
func (post *Post) GetReactionCount(reaction Reaction) int {
	key := reactionKey(reaction)
	valueI, exists := post.reactions.Get(key)
	if exists {
		return valueI.(*bptree.BPTree).Size()
	} else {
		return 0
	}
}

func validateReaction(reaction Reaction) {
	if reaction < 0 || reaction >= MaxReaction {
		panic("invalid Reaction value: " + strconv.Itoa(int(reaction)))
	}
}

func (post *Post) GetSummary() string {
	return summaryOf(post.body, 80)
}

func (post *Post) GetURL() string {
	if post.IsThread() {
		return post.userPosts.GetURLFromThreadAndReplyID(
			post.id, 0)
	} else {
		return post.userPosts.GetURLFromThreadAndReplyID(
			post.threadID, post.id)
	}
}

func (post *Post) GetGnodFormURL() string {
	return txlink.Call("AddReaction",
		"userPostsAddr", post.userPosts.userAddr.String(),
		"threadid", post.threadID.String(),
		"postid", post.id.String(),
		"reaction", strconv.Itoa(int(Gnod)))
}

func (post *Post) GetReplyFormURL() string {
	return txlink.Call("PostReply",
		"userPostsAddr", post.userPosts.userAddr.String(),
		"threadid", post.threadID.String(),
		"postid", post.id.String())
}

func (post *Post) GetRepostFormURL() string {
	return txlink.Call("RepostThread",
		"userPostsAddr", post.userPosts.userAddr.String(),
		"threadid", post.threadID.String(),
		"postid", post.id.String())
}

func (post *Post) RenderSummary() string {
	if post.repostUser != "" {
		dstUserPosts := getUserPosts(post.repostUser)
		if dstUserPosts == nil {
			panic("repost user does not exist")
		}
		thread := dstUserPosts.GetThread(PostID(post.parentID))
		if thread == nil {
			return "reposted post does not exist"
		}
		return "Repost: " + post.GetSummary() + "\n\n" + thread.RenderSummary()
	}
	str := ""
	str += post.GetSummary() + "\n"
	str += "\\- " + displayAddressMD(post.creator) + ","
	str += " [" + post.createdAt.Format("2006-01-02 3:04pm MST") + "](" + post.GetURL() + ")"
	str += " (" + strconv.Itoa(post.GetReactionCount(Gnod)) + " gnods)"
	str += " (" + strconv.Itoa(post.replies.Size()) + " replies)"
	str += " (" + strconv.Itoa(post.reposts.Size()) + " reposts)" + "\n"
	return str
}

func (post *Post) RenderPost(indent string, levels int) string {
	if post == nil {
		return "nil post"
	}
	str := ""
	str += indentBody(indent, post.body) + "\n" // TODO: indent body lines.
	str += indent + "\\- " + displayAddressMD(post.creator) + ", "
	str += "[" + post.createdAt.Format("2006-01-02 3:04pm (MST)") + "](" + post.GetURL() + ")"
	str += " - (" + strconv.Itoa(post.GetReactionCount(Gnod)) + " gnods) - "
	str += " \\[[gnod](" + post.GetGnodFormURL() + ")]"
	str += " \\[[reply](" + post.GetReplyFormURL() + ")]"
	if post.IsThread() {
		str += " \\[[repost](" + post.GetRepostFormURL() + ")]"
	}
	str += "\n"
	if levels > 0 {
		if post.replies.Size() > 0 {
			post.replies.ReverseIterate("", "", func(key string, value interface{}) bool {
				str += indent + "\n"
				str += value.(*Post).RenderPost(indent+"> ", levels-1)
				return false
			})
		}
	} else {
		if post.replies.Size() > 0 {
			str += indent + "\n"
			str += indent + "_[see all " + strconv.Itoa(post.replies.Size()) + " replies](" + post.GetURL() + ")_\n"
		}
	}
	return str
}

// render reply and link to context thread
func (post *Post) RenderInner() string {
	if post.IsThread() {
		panic("unexpected thread")
	}
	threadID := post.threadID
	// replyID := post.id
	parentID := post.parentID
	str := ""
	str += "_[see thread](" + post.userPosts.GetURLFromThreadAndReplyID(
		threadID, 0) + ")_\n\n"
	thread := post.userPosts.GetThread(post.threadID)
	var parent *Post
	if thread.id == parentID {
		parent = thread
	} else {
		parent = thread.GetReply(parentID)
	}
	str += parent.RenderPost("", 0)
	str += "\n"
	str += post.RenderPost("> ", 5)
	return str
}

// MarshalJSON implements the json.Marshaler interface.
func (post *Post) MarshalJSON() ([]byte, error) {
	createdAt, err := post.createdAt.MarshalJSON()
	if err != nil {
		return nil, err
	}

	json := new(bytes.Buffer)

	json.WriteString(ufmt.Sprintf(`{"id": %d, "createdAt": %s, "creator": "%s", "n_gnods": %d, "n_replies": %d, "n_replies_all": %d, "parent_id": %d`,
		uint64(post.id), string(createdAt), post.creator.String(), post.GetReactionCount(Gnod), post.replies.Size(), post.repliesAll.Size(),
		uint64(post.parentID)))
	if post.repostUser != "" {
		json.WriteString(ufmt.Sprintf(`, "repost_user": %s`, strconv.Quote(post.repostUser.String())))
	}
	json.WriteString(ufmt.Sprintf(`, "body": %s}`, strconv.Quote(post.body)))

	return json.Bytes(), nil
}

func getPosts(posts bptree.BPTree, startIndex int, endIndex int) string {
	json := ufmt.Sprintf("{\"n_threads\": %d, \"posts\": [\n  ", posts.Size())

	for i := startIndex; i < endIndex && i < posts.Size(); i++ {
		if i > startIndex {
			json += ",\n  "
		}

		_, postI := posts.GetByIndex(i)
		post := postI.(*Post)
		postJson, err := post.MarshalJSON()
		if err != nil {
			panic("can't get post JSON")
		}
		json += ufmt.Sprintf("{\"index\": %d, \"post\": %s}", i, string(postJson))
	}

	json += "]}"
	return json
}

package social

import (
	"strconv"

	"gno.land/p/nt/bptree/v0"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/r/sys/users"
)

type UserAndPostID struct {
	UserPostAddr address
	PostID       PostID
}

// Post a message to the caller's main user posts.
// The caller must already be registered with /r/gnoland/users/v1 Register.
// Return the "thread ID" of the new post.
// (This is similar to boards.CreateThread, but no message title)
func PostMessage(cur realm, body string) PostID {
	caller := cur.Previous().Address()
	userPosts := getOrCreateUserPosts(caller, usernameOf(caller))
	thread := userPosts.AddThread(body)
	return thread.id
}

// Post a reply to the user posts of userPostsAddr where threadid is the ID returned by
// the original call to PostMessage. If postid == threadid then create another top-level
// post for the threadid, otherwise post a reply to the postid "sub reply".
// The caller must already be registered with /r/gnoland/users/v1 Register.
// Return the new post ID.
// (This is similar to boards.CreateReply.)
func PostReply(cur realm, userPostsAddr address, threadid, postid PostID, body string) PostID {
	caller := cur.Previous().Address()
	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}
	thread := userPosts.GetThread(threadid)
	if thread == nil {
		panic("threadid in user posts does not exist")
	}
	if postid == threadid {
		reply := thread.AddReply(caller, body)
		return reply.id
	} else {
		post := thread.GetReply(postid)
		if post == nil {
			panic("postid does not exist")
		}
		reply := post.AddReply(caller, body)
		return reply.id
	}
}

// Repost the message from the user posts of userPostsAddr where threadid is the ID returned by
// the original call to PostMessage. This must be a top-level thread (not a reply).
// Return the new post ID.
// (This is similar to boards.CreateRepost.)
func RepostThread(cur realm, userPostsAddr address, threadid PostID, comment string) PostID {
	caller := cur.Previous().Address()
	if userPostsAddr == caller {
		panic("Cannot repost a user's own message")
	}

	dstUserPosts := getOrCreateUserPosts(caller, usernameOf(caller))

	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}
	thread := userPosts.GetThread(threadid)
	if thread == nil {
		panic("threadid in user posts does not exist")
	}
	repost := thread.AddRepostTo(caller, comment, dstUserPosts)
	return repost.id
}

// For each address/PostID in addrAndIDs, get the thread post. The Post ID must be
// for a a top-level thread (not a reply; to get reply posts, use GetThreadPosts).
// If the Post ID is not found, set the result for that Post ID to {}.
// The response is a JSON string.
func GetJsonTopPostsByID(addrAndIDs []UserAndPostID) string {
	json := "[ "
	for _, addrAndID := range addrAndIDs {
		if len(json) > 2 {
			json += ",\n  "
		}

		userPosts := getUserPosts(addrAndID.UserPostAddr)
		if userPosts == nil {
			json += "{}"
			continue
		}

		post := userPosts.GetThread(PostID(addrAndID.PostID))
		if post == nil {
			json += "{}"
			continue
		}

		postJson, err := post.MarshalJSON()
		if err != nil {
			panic("can't get post JSON")
		}
		json += string(postJson)
	}
	json += "]"

	return json
}

// Get posts in a thread for a user. A thread is the sequence of posts without replies.
// While each post has an an arbitrary id, it also has an index within the thread starting from 0.
// Limit the response to posts from startIndex up to (not including) endIndex within the thread.
// If you just want the total count, set startIndex and endIndex to 0 and see the response "n_threads".
// If threadID is 0 then return the user's top-level posts. (Like render args "user".)
// If threadID is X and replyID is 0, then return the posts (without replies) in that thread. (Like render args "user/2".)
// If threadID is X and replyID is Y, then return the posts in the thread starting with replyID. (Like render args "user/2/5".)
// The response includes reposts by this user (only if threadID is 0), but not messages of other
// users that are being followed. (See GetHomePosts.) The response is a JSON string.
func GetThreadPosts(userPostsAddr address, threadID int, replyID int, startIndex int, endIndex int) string {
	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}

	if threadID == 0 {
		return getPosts(userPosts.threads, startIndex, endIndex)
	}

	thread := userPosts.GetThread(PostID(threadID))
	if thread == nil {
		panic(ufmt.Sprintf("thread does not exist with id %d", threadID))
	}

	if replyID == 0 {
		return getPosts(thread.replies, startIndex, endIndex)
	} else {
		reply := thread.GetReply(PostID(replyID))
		if reply == nil {
			panic(ufmt.Sprintf("reply does not exist with id %d in thread with id %d", replyID, threadID))
		}

		return getPosts(reply.replies, startIndex, endIndex)
	}
}

// Update the home posts by scanning all posts from all followed users and adding the
// followed posts since the last call to RefreshHomePosts (or since started following the user).
// Return the new count of home posts. The result is something like "(12 int)".
func RefreshHomePosts(_ realm, userPostsAddr address) int {
	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}
	userPosts.refreshHomePosts()

	return userPosts.homePosts.Size()
}

// Get the number of posts which GetHomePosts or GetJsonHomePosts will return.
// The result is something like "(12 int)".
// This returns the current count of the home posts (without need to pay gas). To include the
// latest followed posts, call RefreshHomePosts.
func GetHomePostsCount(userPostsAddr address) int {
	return GetHomePosts(userPostsAddr).Size()
}

// Get home posts for a user, which are the user's top-level posts plus all posts of all
// users being followed.
// The response is a map of postID -> *Post. The bptree.BPTree sorts by the post ID which is
// unique for every post and increases in time.
// If you just want the total count, use GetHomePostsCount.
// This returns the current state of the home posts (without need to pay gas). To include the
// latest followed posts, call RefreshHomePosts.
func GetHomePosts(userPostsAddr address) *bptree.BPTree {
	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}
	return &userPosts.homePosts
}

// Get home posts for a user (using GetHomePosts), which are the user's top-level posts plus all
// posts of all users being followed.
// Limit the response to posts from startIndex up to (not including) endIndex within the home posts.
// If you just want the total count, use GetHomePostsCount.
// The response is a JSON string.
// This returns the current state of the home posts (without need to pay gas). To include the
// latest posts, call RefreshHomePosts.
func GetJsonHomePosts(userPostsAddr address, startIndex int, endIndex int) string {
	allPosts := GetHomePosts(userPostsAddr)
	postsJson := ""
	for i := startIndex; i < endIndex && i < allPosts.Size(); i++ {
		_, postI := allPosts.GetByIndex(i)
		if postsJson != "" {
			postsJson += ",\n  "
		}

		postJson, err := postI.(*Post).MarshalJSON()
		if err != nil {
			panic("can't get post JSON")
		}
		postsJson += ufmt.Sprintf("{\"index\": %d, \"post\": %s}", int(i), string(postJson))
	}

	return ufmt.Sprintf("{\"n_posts\": %d, \"posts\": [\n  %s]}", allPosts.Size(), postsJson)
}

// Update the caller to follow the user with followedAddr. See UserPosts.Follow.
func Follow(cur realm, followedAddr address) PostID {
	caller := cur.Previous().Address()
	if followedAddr == caller {
		panic("you can't follow yourself")
	}

	// A user can follow someone before doing any posts, so create the UserPosts if needed.
	userPosts := getOrCreateUserPosts(caller, usernameOf(caller))
	return userPosts.Follow(followedAddr)
}

// Update the caller to unfollow the user with followedAddr. See UserPosts.Unfollow.
func Unfollow(cur realm, followedAddr address) {
	caller := cur.Previous().Address()
	userPosts := getUserPosts(caller)
	if userPosts == nil {
		// We don't expect this, but just do nothing.
		return
	}

	userPosts.Unfollow(followedAddr)
}

// Add the reaction by the caller to the post of userPostsAddr, where threadid is the ID
// returned by the original call to PostMessage. If postid == threadid then add the reaction
// to a top-level post for the threadid, otherwise add the reaction to the postid "sub reply".
// (This function's arguments are similar to PostReply.)
// The caller must already be registered with /r/gnoland/users/v1 Register.
// Return a boolean indicating whether the userAddr was added. See Post.AddReaction.
func AddReaction(cur realm, userPostsAddr address, threadid, postid PostID, reaction Reaction) bool {
	caller := cur.Previous().Address()
	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}
	thread := userPosts.GetThread(threadid)
	if thread == nil {
		panic("threadid in user posts does not exist")
	}
	if postid == threadid {
		return thread.AddReaction(caller, reaction)
	} else {
		post := thread.GetReply(postid)
		if post == nil {
			panic("postid does not exist")
		}
		return post.AddReaction(caller, reaction)
	}
}

// Remove the reaction by the caller to the post of userPostsAddr, where threadid is the ID
// returned by the original call to PostMessage. If postid == threadid then remove the reaction
// from a top-level post for the threadid, otherwise remove the reaction from the postid "sub reply".
// (This function's arguments are similar to PostReply.)
// The caller must already be registered with /r/gnoland/users/v1 Register.
// Return a boolean indicating whether the userAddr was removed. See Post.RemoveReaction.
func RemoveReaction(cur realm, userPostsAddr address, threadid, postid PostID, reaction Reaction) bool {
	caller := cur.Previous().Address()
	userPosts := getUserPosts(userPostsAddr)
	if userPosts == nil {
		panic("posts for userPostsAddr do not exist")
	}
	thread := userPosts.GetThread(threadid)
	if thread == nil {
		panic("threadid in user posts does not exist")
	}
	if postid == threadid {
		return thread.RemoveReaction(caller, reaction)
	} else {
		post := thread.GetReply(postid)
		if post == nil {
			panic("postid does not exist")
		}
		return post.RemoveReaction(caller, reaction)
	}
}

// Call users.ResolveAddress and return the result as JSON, or "" if not found.
// (This is a temporary utility until gno.land supports returning structured data directly.)
func GetJsonUserByAddress(addr address) string {
	user := users.ResolveAddress(addr)
	if user == nil {
		return ""
	}

	return marshalJsonUser(user)
}

// Call users.ResolveName and return the result as JSON, or "" if not found.
// (This is a temporary utility until gno.land supports returning structured data directly.)
func GetJsonUserByName(name string) string {
	user, _ := users.ResolveName(name)
	if user == nil {
		return ""
	}

	return marshalJsonUser(user)
}

// Get the UserPosts info for the user with the given address, including
// url, n_threads, n_followers and n_following. If the user address is not
// found, return "". The name of this function has "Info" because it just returns
// the number of items, not the items themselves. To get the items, see
// GetJsonFollowers, etc.
// The response is a JSON string.
func GetJsonUserPostsInfo(address address) string {
	userPosts := getUserPosts(address)
	if userPosts == nil {
		return ""
	}

	json, err := userPosts.MarshalJSON()
	if err != nil {
		panic("can't get UserPosts JSON")
	}

	return string(json)
}

// Get the UserPosts for the user with the given address, and return
// the list of followers. If the user address is not found, return "".
// Limit the response to entries from startIndex up to (not including) endIndex.
// The response is a JSON string.
func GetJsonFollowers(address address, startIndex int, endIndex int) string {
	userPosts := getUserPosts(address)
	if userPosts == nil {
		return ""
	}

	json := ufmt.Sprintf("{\"n_followers\": %d, \"followers\": [\n  ", userPosts.followers.Size())
	for i := startIndex; i < endIndex && i < userPosts.followers.Size(); i++ {
		addr, _ := userPosts.followers.GetByIndex(i)

		if i > startIndex {
			json += ",\n  "
		}
		json += ufmt.Sprintf(`{"address": "%s"}`, addr)
	}
	json += "]}"

	return json
}

// Get the UserPosts for the user with the given address, and return
// the list of other users that this user is following.
// If the user address is not found, return "".
// Limit the response to entries from startIndex up to (not including) endIndex.
// The response is a JSON string.
func GetJsonFollowing(address address, startIndex int, endIndex int) string {
	userPosts := getUserPosts(address)
	if userPosts == nil {
		return ""
	}

	json := ufmt.Sprintf("{\"n_following\": %d, \"following\": [\n  ", userPosts.following.Size())
	for i := startIndex; i < endIndex && i < userPosts.following.Size(); i++ {
		addr, infoI := userPosts.following.GetByIndex(i)

		if i > startIndex {
			json += ",\n  "
		}
		startedAt, err := infoI.(*FollowingInfo).startedFollowingAt.MarshalJSON()
		if err != nil {
			panic("can't get startedFollowingAt JSON")
		}
		json += ufmt.Sprintf(`{"address": "%s", "started_following_at": %s}`,
			addr, string(startedAt))
	}
	json += "]}"

	return json
}

// Get a list of user names starting from the given prefix. Limit the
// number of results to maxResults.
func ListUsersByPrefix(prefix string, maxResults int) []string {
	return listByteStringKeysByPrefix(&gUserAddressByName, prefix, maxResults)
}

// Get a list of user names starting from the given prefix. Limit the
// number of results to maxResults.
// The response is a JSON string.
func ListJsonUsersByPrefix(prefix string, maxResults int) string {
	names := ListUsersByPrefix(prefix, maxResults)

	json := "["
	for i, name := range names {
		if i > 0 {
			json += ", "
		}
		json += strconv.Quote(name)
	}
	json += "]"
	return json
}

package social

import (
	"strconv"
	"strings"

	"gno.land/r/sys/users"
)

// resolveAddr looks up an address by registered name first, then falls back
// to treating the input as a raw address. This allows unregistered users to
// be found by their address string.
func resolveAddr(nameOrAddr string) address {
	user, _ := users.ResolveName(nameOrAddr)
	if user != nil {
		return user.Addr()
	}
	return address(nameOrAddr)
}

func Render(path string) string {
	if path == "" {
		str := "Welcome to dSocial!\n\n"

		// List the users who have posted. gUserAddressByName is already sorted by name.
		gUserAddressByName.Iterate("", "", func(name string, value interface{}) bool {
			str += " * [@" + name + "](" + gRealmPath + ":" + name + ")" + "\n"
			return false
		})

		return str
	}

	parts := strings.Split(path, "/")
	if len(parts) == 1 {
		// /r/berty/social:USER_NAME_OR_ADDR
		userAddr := resolveAddr(path)
		userPosts := getUserPosts(userAddr)
		if userPosts == nil {
			return "No posts by: " + path
		}

		return userPosts.RenderUserPosts(false)
	} else if len(parts) == 2 {
		userAddr := resolveAddr(parts[0])
		userPosts := getUserPosts(userAddr)
		if userPosts == nil {
			return "No posts by: " + parts[0]
		}

		if parts[1] == "home" {
			// /r/berty/social:USER_NAME_OR_ADDR/home
			return userPosts.RenderUserPosts(true)
		} else if parts[1] == "followers" {
			// /r/berty/social:USER_NAME_OR_ADDR/followers
			return userPosts.RenderFollowers()
		} else if parts[1] == "following" {
			// /r/berty/social:USER_NAME_OR_ADDR/following
			return userPosts.RenderFollowing()
		} else {
			// /r/berty/social:USER_NAME_OR_ADDR/THREAD_ID
			pid, err := strconv.Atoi(parts[1])
			if err != nil {
				return "invalid thread id: " + parts[1]
			}
			thread := userPosts.GetThread(PostID(pid))
			if thread == nil {
				return "thread does not exist with id: " + parts[1]
			}
			return thread.RenderPost("", 5)
		}
	} else if len(parts) == 3 {
		// /r/berty/social:USER_NAME_OR_ADDR/THREAD_ID/REPLY_ID
		userAddr := resolveAddr(parts[0])
		userPosts := getUserPosts(userAddr)
		if userPosts == nil {
			return "No posts by: " + parts[0]
		}
		pid, err := strconv.Atoi(parts[1])
		if err != nil {
			return "invalid thread id: " + parts[1]
		}
		thread := userPosts.GetThread(PostID(pid))
		if thread == nil {
			return "thread does not exist with id: " + parts[1]
		}
		rid, err := strconv.Atoi(parts[2])
		if err != nil {
			return "invalid reply id: " + parts[2]
		}
		reply := thread.GetReply(PostID(rid))
		if reply == nil {
			return "reply does not exist with id: " + parts[2]
		}
		return reply.RenderInner()
	} else {
		return "unrecognized path: " + path
	}
}

package social

import (
	"strings"

	"gno.land/p/nt/bptree/v0"
)

var (
	gUserPostsByAddress bptree.BPTree // user's address -> *UserPosts
	gUserAddressByName  bptree.BPTree // user's username -> address
	postsCtr            uint64   // increments Post.id globally

	// gRealmPath is the realm's relative URL path (e.g. "/r/g1.../social"),
	// derived from the deployed package path at init time.
	gRealmPath string
)

func init(cur realm) {
	pkgPath := cur.PkgPath()
	// Strip the chain domain (everything before the first "/") to get the
	// relative path suitable for markdown links: "/r/g1.../social".
	if idx := strings.Index(pkgPath, "/"); idx >= 0 {
		gRealmPath = pkgPath[idx:]
	}
}

package social

import (
	"bytes"
	"sort"
	"strconv"
	"strings"
	"time"

	"gno.land/p/moul/txlink"
	"gno.land/p/nt/bptree/v0"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/r/sys/users"
)

type FollowingInfo struct {
	startedFollowingAt time.Time
	startedPostsCtr    PostID
}

// UserPosts is similar to boards.Board where each user has their own "board" for
// posts which come from the user. The list of posts is identified by the user's address .
// A user's "home feed" may contain other posts (from followed users, etc.) but this only
// has the top-level posts from the user (not replies to other user's posts).
type UserPosts struct {
	url           string
	userAddr      address
	threads       bptree.BPTree // PostID -> *Post
	homePosts     bptree.BPTree // PostID -> *Post. Includes this user's threads posts plus posts of users being followed.
	lastRefreshId PostID        // Updated by refreshHomePosts
	followers     bptree.BPTree // address -> ""
	following     bptree.BPTree // address -> *FollowingInfo
}

// Create a new userPosts for the user. Panic if there is already a userPosts for the user.
func newUserPosts(url string, userAddr address) *UserPosts {
	if gUserPostsByAddress.Has(userAddr.String()) {
		panic("userPosts already exists")
	}
	return &UserPosts{
		url:           url,
		userAddr:      userAddr,
		threads:       bptree.BPTree{},
		homePosts:     bptree.BPTree{},
		lastRefreshId: PostID(postsCtr), // Ignore past messages of followed users.
		followers:     bptree.BPTree{},
		following:     bptree.BPTree{},
	}
}

func (userPosts *UserPosts) GetThread(pid PostID) *Post {
	pidkey := postIDKey(pid)
	postI, exists := userPosts.threads.Get(pidkey)
	if !exists {
		return nil
	}
	return postI.(*Post)
}

// Add a new top-level thread to the userPosts. Return the new Post.
func (userPosts *UserPosts) AddThread(body string) *Post {
	pid := userPosts.incGetPostID()
	pidkey := postIDKey(pid)
	thread := newPost(userPosts, pid, userPosts.userAddr, body, pid, 0, "")
	userPosts.threads.Set(pidkey, thread)
	// Also add to the home posts.
	userPosts.homePosts.Set(pidkey, thread)
	return thread
}

// If already following followedAddr, then do nothing and return 0.
// If there is a UserPosts for followedAddr, then add it to following,
// and add this user to its followers.
// If there is no UserPosts for followedAddr, then do nothing and return 0. (We don't expect
// this because this is usually called by clicking on the display page of followedAddr.)
// Return the value of startedPostsCtr in the added FollowingInfo.
func (userPosts *UserPosts) Follow(followedAddr address) PostID {
	if userPosts.following.Has(followedAddr.String()) {
		// Already following.
		return PostID(0)
	}

	followedUserPosts := getUserPosts(followedAddr)
	if followedUserPosts != nil {
		userPosts.following.Set(followedAddr.String(), &FollowingInfo{
			startedFollowingAt: time.Now(),
			startedPostsCtr:    PostID(postsCtr), // Ignore past messages.
		})
		followedUserPosts.followers.Set(userPosts.userAddr.String(), "")
		return PostID(postsCtr)
	}

	return PostID(0)
}

// Remove followedAddr from following.
// If there is a UserPosts for followedAddr, then remove this user from its followers.
// If there is no UserPosts for followedAddr, then do nothing. (We don't expect this usually.)
func (userPosts *UserPosts) Unfollow(followedAddr address) {
	userPosts.following.Remove(followedAddr.String())

	followedUserPosts := getUserPosts(followedAddr)
	if followedUserPosts != nil {
		followedUserPosts.followers.Remove(userPosts.userAddr.String())
	}
}

// Renders the userPosts for display suitable as plaintext in
// console.  This is suitable for demonstration or tests,
// but not for prod.
func (userPosts *UserPosts) RenderUserPosts(includeFollowed bool) string {
	str := ""
	followers := strconv.Itoa(userPosts.followers.Size()) + " Followers"
	following := "Following " + strconv.Itoa(userPosts.following.Size())
	user := users.ResolveAddress(userPosts.userAddr)
	nameOrAddr := userPosts.userAddr.String()
	if user != nil {
		nameOrAddr = user.Name()
	}
	followers = "[" + followers + "](" + gRealmPath + ":" + nameOrAddr + "/followers)"
	following = "[" + following + "](" + gRealmPath + ":" + nameOrAddr + "/following)"
	str += followers + " &nbsp;" + following + "\n\n"

	str += "\\[[post](" + userPosts.GetPostFormURL() + ")] \\[[follow](" + userPosts.GetFollowFormURL() + ")]"
	if includeFollowed {
		str += " \\[[refresh](" + userPosts.GetRefreshFormURL() + ")]"
	}
	str += "\n\n"

	var posts *bptree.BPTree
	if includeFollowed {
		posts = &userPosts.homePosts
	} else {
		posts = &userPosts.threads
	}
	posts.ReverseIterate("", "", func(key string, postI interface{}) bool {
		str += "----------------------------------------\n"
		str += postI.(*Post).RenderSummary() + "\n"
		return false
	})

	return str
}

func (userPosts *UserPosts) RenderFollowers() string {
	str := ""
	user := users.ResolveAddress(userPosts.userAddr)
	ownerRef := userPosts.userAddr.String()
	if user != nil {
		ownerRef = user.Name()
	}
	str += "[@" + ownerRef + "](" + gRealmPath + ":" + ownerRef + ") Followers\n\n"

	// List the followers, sorted by name/addr.
	names := []string{}
	userPosts.followers.Iterate("", "", func(key string, value interface{}) bool {
		if u := users.ResolveAddress(address(key)); u != nil {
			names = append(names, u.Name())
		} else {
			names = append(names, key)
		}
		return false
	})
	sort.Strings(names)
	for _, name := range names {
		str += " * [@" + name + "](" + gRealmPath + ":" + name + ")" + "\n"
	}

	return str
}

func (userPosts *UserPosts) RenderFollowing() string {
	str := ""
	user := users.ResolveAddress(userPosts.userAddr)
	ownerRef := userPosts.userAddr.String()
	if user != nil {
		ownerRef = user.Name()
	}
	str += "[@" + ownerRef + "](" + gRealmPath + ":" + ownerRef + ") Following\n\n"

	// List the following, sorted by name/addr.
	nameAddrs := []string{}
	userPosts.following.Iterate("", "", func(addr string, infoI interface{}) bool {
		info := infoI.(*FollowingInfo)
		ref := addr
		if u := users.ResolveAddress(address(addr)); u != nil {
			ref = u.Name()
		}
		nameAddrs = append(nameAddrs, ref+"/"+addr+"/"+info.startedFollowingAt.Format("2006-01-02"))
		return false
	})
	sort.Strings(nameAddrs)
	for _, nameAddr := range nameAddrs {
		parts := strings.Split(nameAddr, "/")
		name := parts[0]
		addr := parts[1]
		since := parts[2]
		str += " * [@" + name + "](" + gRealmPath + ":" + name + ") since " + since +
			"  \\[[unfollow](" + userPosts.GetUnfollowFormURL(address(addr)) + ")]\n"
	}

	return str
}

func (userPosts *UserPosts) incGetPostID() PostID {
	postsCtr++
	return PostID(postsCtr)
}

func (userPosts *UserPosts) GetURLFromThreadAndReplyID(threadID, replyID PostID) string {
	if replyID == 0 {
		return userPosts.url + "/" + threadID.String()
	} else {
		return userPosts.url + "/" + threadID.String() + "/" + replyID.String()
	}
}

func (userPosts *UserPosts) GetPostFormURL() string {
	return txlink.Call("PostMessage")
}

func (userPosts *UserPosts) GetFollowFormURL() string {
	return txlink.Call("Follow", "followedAddr", userPosts.userAddr.String())
}

func (userPosts *UserPosts) GetUnfollowFormURL(followedAddr address) string {
	return txlink.Call("Unfollow", "followedAddr", followedAddr.String())
}

func (userPosts *UserPosts) GetRefreshFormURL() string {
	return txlink.Call("RefreshHomePosts", "userPostsAddr", userPosts.userAddr.String())
}

// Scan userPosts.following for all posts from all followed users starting from lastRefreshId+1 .
// Add the posts to the homePosts bptree.BPTree, which is sorted by the post ID which is unique for every post and
// increases in time. When finished, update lastRefreshId.
func (userPosts *UserPosts) refreshHomePosts() {
	minStartKey := postIDKey(userPosts.lastRefreshId + 1)

	userPosts.following.Iterate("", "", func(followedAddr string, infoI interface{}) bool {
		followedUserPosts := getUserPosts(address(followedAddr))
		if followedUserPosts == nil {
			return false
		}

		info := infoI.(*FollowingInfo)
		startKey := minStartKey
		if info.startedPostsCtr > userPosts.lastRefreshId {
			// Started following after the last refresh. Ignore messages before started following.
			startKey = postIDKey(info.startedPostsCtr + 1)
		}

		followedUserPosts.threads.Iterate(startKey, "", func(id string, postI interface{}) bool {
			userPosts.homePosts.Set(id, postI.(*Post))
			return false
		})

		return false
	})

	userPosts.lastRefreshId = PostID(postsCtr)
}

// MarshalJSON implements the json.Marshaler interface.
func (userPosts *UserPosts) MarshalJSON() ([]byte, error) {
	json := new(bytes.Buffer)
	json.WriteString(ufmt.Sprintf(`{"address": "%s", "url": %s, "n_threads": %d, "n_followers": %d, "n_following": %d}`,
		userPosts.userAddr.String(), strconv.Quote(userPosts.url), userPosts.threads.Size(),
		userPosts.followers.Size(), userPosts.following.Size()))

	return json.Bytes(), nil
}

package social

import (
	"strconv"
	"strings"

	"gno.land/p/nt/bptree/v0"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/r/sys/users"
)

//----------------------------------------
// private utility methods

// Get the UserPosts for the user.
func getUserPosts(userAddr address) *UserPosts {
	userPosts, exists := gUserPostsByAddress.Get(userAddr.String())
	if !exists {
		return nil
	}

	return userPosts.(*UserPosts)
}

// Get the UserPosts for the userAddr. If not found, add a new UserPosts to
// gUserPostsByAddress and update gUserAddressByName with the username.
// (The caller usually has already called usernameOf to get the username, but if
// it is "" then this will get it.)
func getOrCreateUserPosts(userAddr address, username string) *UserPosts {
	userPosts := getUserPosts(userAddr)
	if userPosts != nil {
		return userPosts
	}

	if username == "" {
		username = usernameOf(userAddr)
	}
	if username == "" {
		username = userAddr.String()
	}

	userPosts = newUserPosts(gRealmPath+":"+username, userAddr)
	gUserPostsByAddress.Set(userAddr.String(), userPosts)
	gUserAddressByName.Set(username, userAddr)

	return userPosts
}

func padZero(u64 uint64, length int) string {
	str := strconv.Itoa(int(u64))
	if len(str) >= length {
		return str
	} else {
		return strings.Repeat("0", length-len(str)) + str
	}
}

func postIDKey(pid PostID) string {
	return padZero(uint64(pid), 10)
}

func reactionKey(reaction Reaction) string {
	return strconv.Itoa(int(reaction))
}

// If reactions has an value for the given reaction, then return it.
// Otherwise, add the reaction key to reactions, set the value to an empty bptree.BPTree and return it.
func getOrCreateReactionValue(reactions *bptree.BPTree, reaction Reaction) *bptree.BPTree {
	key := reactionKey(reaction)
	valueI, exists := reactions.Get(key)
	if exists {
		return valueI.(*bptree.BPTree)
	} else {
		value := bptree.NewBPTree32()
		reactions.Set(key, value)
		return value
	}
}

// listByteStringKeysByPrefix returns up to maxResults keys from tree that start
// with the given prefix, treating keys as byte strings (not Unicode runes).
// Inlined from gno.land/p/jefft0/avlhelpers which is not yet deployed.
func listByteStringKeysByPrefix(tree bptree.ITree, prefix string, maxResults int) []string {
	result := []string{}
	end := ""
	n := len(prefix)
	for n > 0 {
		if ascii := int(prefix[n-1]); ascii < 0xff {
			end = prefix[0:n-1] + string(ascii+1)
			break
		}
		n--
	}
	tree.Iterate(prefix, end, func(key string, value any) bool {
		result = append(result, key)
		return len(result) >= maxResults
	})
	return result
}

func indentBody(indent string, body string) string {
	lines := strings.Split(body, "\n")
	res := ""
	for i, line := range lines {
		if i > 0 {
			res += "\n"
		}
		res += indent + line
	}
	return res
}

// NOTE: length must be greater than 3.
func summaryOf(str string, length int) string {
	lines := strings.SplitN(str, "\n", 2)
	line := lines[0]
	if len(line) > length {
		line = line[:(length-3)] + "..."
	} else if len(lines) > 1 {
		// len(line) <= 80
		line = line + "..."
	}
	return line
}

func displayAddressMD(addr address) string {
	user := users.ResolveAddress(addr)
	if user == nil {
		return "[" + addr.String() + "](/r/gnoland/users/v1:" + addr.String() + ")"
	} else {
		return "[@" + user.Name() + "](" + gRealmPath + ":" + user.Name() + ")"
	}
}

func usernameOf(addr address) string {
	user := users.ResolveAddress(addr)
	if user == nil {
		return ""
	} else {
		return user.Name()
	}
}

// Return the User info as a JSON string.
// (This is a temporary utility until gno.land supports returning structured data directly.)
func marshalJsonUser(user *users.UserData) string {
	return ufmt.Sprintf(
		"{\"address\": \"%s\", \"name\": \"%s\", \"deleted\": %t}",
		user.Addr().String(), user.Name(), user.IsDeleted())
}

