package daokit

// Extensions system enables DAOs to expose additional functionality that can be
// accessed by other packages or realms. It provides a secure way to make
// specific DAO capabilities available without exposing internal implementation details.

import "gno.land/p/nt/avl/v0"

// Interface must be implemented by any object that wants to be
// registered as a DAO extension. Extensions expose functionality through
// well-defined interfaces while maintaining encapsulation.
type Extension interface {
	// Returns metadata about this extension including its path, version,
	// query path for external access, and privacy settings.
	Info() ExtensionInfo
}

type ExtensionInfo struct {
	Path      string // Unique extension identifier (e.g., "gno.land/p/demo/basedao.MembersView")
	Version   string // Extension version (e.g., "1", "2.0", etc.)
	QueryPath string // Path for external queries to access this extension's data
	Private   bool   // If true, extension is only accessible from the same realm that registered it
}

type ExtensionsList interface {
	// Returns the total number of registered extensions.
	Len() int
	// Returns extension info at the specified index, or nil if index is out of bounds.
	Get(index int) *ExtensionInfo
	// Returns a slice of ExtensionInfo from startIndex to endIndex.
	Slice(startIndex, endIndex int) []ExtensionInfo
	// Iterates over all extensions, calling fn for each one.
	// Iteration stops if fn returns true.
	ForEach(fn func(index int, value ExtensionInfo) bool)
}

type ExtensionsStore struct {
	Tree avl.Tree
}

// Registers a new extension using its path as the key.
// Returns true if the extension was successfully registered.
// If an extension with the same path already exists, it will be replaced.
func (es *ExtensionsStore) Set(ext Extension) bool {
	info := ext.Info()
	return es.Tree.Set(info.Path, ext)
}

func (es *ExtensionsStore) Get(path string) (Extension, bool) {
	iface, ok := es.Tree.Get(path)
	if !ok {
		return nil, false
	}
	return iface.(Extension), true
}

// Remove unregisters an extension by its path.
// Returns the removed extension and true if found, nil and false otherwise.
func (es *ExtensionsStore) Remove(path string) (Extension, bool) {
	iface, ok := es.Tree.Remove(path)
	if !ok {
		return nil, false
	}
	return iface.(Extension), true
}

// Returns an ExtensionsList interface for iterating over all registered extensions.
// This provides read-only access to the extensions registry.
func (es *ExtensionsStore) List() ExtensionsList {
	return &extensionsList{es: es}
}

type extensionsList struct {
	es *ExtensionsStore
}

// Iterates over all extensions, calling fn for each extension with its index and info.
// Iteration stops early if fn returns true.
func (e *extensionsList) ForEach(fn func(index int, value ExtensionInfo) bool) {
	if e.es.Tree.Size() == 0 {
		return
	}

	index := 0
	e.es.Tree.IterateByOffset(0, e.es.Tree.Size(), func(_ string, value any) bool {
		result := fn(index, value.(Extension).Info())
		index++
		return result
	})
}

// Returns the ExtensionInfo at the specified index.
func (e *extensionsList) Get(index int) *ExtensionInfo {
	if index < 0 || index >= e.es.Tree.Size() {
		return nil
	}

	_, value := e.es.Tree.GetByIndex(index)
	info := value.(Extension).Info()
	return &info
}

// Returns the total number of registered extensions.
func (e *extensionsList) Len() int {
	return e.es.Tree.Size()
}

// Returns a slice of ExtensionInfo from startIndex (inclusive) to endIndex (exclusive).
// Bounds are automatically normalized: negative startIndex becomes 0, endIndex beyond size becomes size.
func (e *extensionsList) Slice(startIndex int, endIndex int) []ExtensionInfo {
	size := e.es.Tree.Size()

	// Normalize bounds
	if startIndex < 0 {
		startIndex = 0
	}

	if endIndex > size {
		endIndex = size
	}

	if startIndex >= endIndex {
		return nil
	}

	count := endIndex - startIndex
	result := make([]ExtensionInfo, count)

	i := 0
	e.es.Tree.IterateByOffset(startIndex, count, func(_ string, value any) bool {
		result[i] = value.(Extension).Info()
		i++
		return false
	})

	return result
}

package daokit

// Handles DAO governance through proposal voting and execution.
// They contain actions that run when voting requirements are satisfied.
//
// Common use cases: member management, treasury operations, rule updates.

import (
	"chain/runtime"
	"errors"
	"time"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/seqid/v0"
	"gno.land/p/onbloc/json"
	"gno.land/p/samcrew/daocond"
)

type ProposalStatus int

const (
	ProposalStatusOpen     ProposalStatus = iota // Currently accepting votes
	ProposalStatusPassed                         // Met conditions, ready for execution
	ProposalStatusExecuted                       // Successfully executed
)

func (s ProposalStatus) String() string {
	switch s {
	case ProposalStatusOpen:
		return "Open"
	case ProposalStatusPassed:
		return "Passed"
	case ProposalStatusExecuted:
		return "Executed"
	default:
		return "Unknown"
	}
}

type Proposal struct {
	ID            seqid.ID
	Title         string
	Description   string
	CreatedAt     time.Time
	CreatedHeight int64
	ProposerID    string

	Action     Action            // What to execute if passed
	Condition  daocond.Condition // Voting conditions for this proposal
	Status     ProposalStatus
	ExecutorID string
	ExecutedAt time.Time

	Ballot daocond.Ballot // All votes cast on this proposal
}

type ProposalsStore struct {
	Tree  *avl.Tree // int -> Proposal
	genID seqid.ID
}

// Data needed to create a new proposal.
type ProposalRequest struct {
	Title       string
	Description string
	Action      Action
}

func NewProposalsStore() *ProposalsStore {
	return &ProposalsStore{
		Tree: avl.NewTree(),
	}
}

func (p *ProposalsStore) GetProposal(id uint64) *Proposal {
	value, ok := p.Tree.Get(seqid.ID(id).String())
	if !ok {
		return nil
	}
	proposal := value.(*Proposal)
	return proposal
}

// Returns all proposals that match the given filter function.
func (p *ProposalsStore) GetProposals(filter func(Proposal) bool) *ProposalsStore {
	proposals := NewProposalsStore()
	p.Tree.Iterate("", "", func(key string, value interface{}) bool {
		prop, ok := value.(*Proposal)
		if !ok {
			panic(errors.New("unexpected invalid proposal type"))
		}
		prop.UpdateStatus() // XXX: costly and probably insecure
		if filter(*prop) {
			proposals.Tree.Set(key, prop)
		}
		return false
	})
	return proposals
}

// Updates proposal status based on current voting condition results.
func (p *Proposal) UpdateStatus() {
	conditionsAreMet := p.Condition.Eval(p.Ballot)
	if p.Status == ProposalStatusOpen && conditionsAreMet {
		p.Status = ProposalStatusPassed
	}
}

// Returns all proposals as a JSON string.
func (p *ProposalsStore) GetProposalsJSON() string {
	props := make([]*json.Node, 0, p.Tree.Size())
	// XXX: pagination
	p.Tree.Iterate("", "", func(key string, value interface{}) bool {
		prop, ok := value.(*Proposal)
		if !ok {
			panic(errors.New("unexpected invalid proposal type"))
		}
		prop.UpdateStatus()
		props = append(props, json.ObjectNode("", map[string]*json.Node{
			"id":          json.NumberNode("", float64(prop.ID)),
			"title":       json.StringNode("", prop.Title),
			"description": json.StringNode("", prop.Description),
			"proposer":    json.StringNode("", prop.ProposerID),
			"status":      json.StringNode("", prop.Status.String()),
			"startHeight": json.NumberNode("", float64(prop.CreatedHeight)),
			"signal":      json.NumberNode("", prop.Condition.Signal(prop.Ballot)),
		}))
		return false
	})
	bz, err := json.Marshal(json.ArrayNode("", props))
	if err != nil {
		panic(err)
	}
	return string(bz)
}

func (p *ProposalsStore) newProposal(proposer string, req ProposalRequest, condition daocond.Condition) *Proposal {
	id := p.genID.Next()
	proposal := &Proposal{
		ID:            id,
		Title:         req.Title,
		Description:   req.Description,
		ProposerID:    proposer,
		Status:        ProposalStatusOpen,
		Action:        req.Action,
		Condition:     condition,
		Ballot:        daocond.NewBallot(),
		CreatedAt:     time.Now(),
		CreatedHeight: runtime.ChainHeight(),
	}
	p.Tree.Set(id.String(), proposal)
	return proposal
}

package daokit

// Maps action types to their handlers and conditions.
//
// Example: "transfer" action requires 3 member votes for execution.

import (
	"gno.land/p/nt/avl/v0"
	"gno.land/p/samcrew/daocond"
)

type ResourcesStore struct {
	Tree *avl.Tree // string -> daocond.Condition
}

type Resource struct {
	Handler     ActionHandler     // Executes the action when proposal passes
	Condition   daocond.Condition // Voting rules required for approval
	DisplayName string
	Description string
}

func NewResourcesStore() *ResourcesStore {
	return &ResourcesStore{
		Tree: avl.NewTree(),
	}
}

// Retrieves a resource by its handler type name.
func (r *ResourcesStore) Get(name string) *Resource {
	value, ok := r.Tree.Get(name)
	if !ok {
		return nil
	}
	res := value.(*Resource)
	return res
}

// Registers a new resource with its handler type as key.
func (r *ResourcesStore) Set(resource *Resource) {
	r.Tree.Set(resource.Handler.Type(), resource)
}

# basedao: Membership and Role Management for DAOs

`basedao` is a gnolang package that extends the DAOkit framework with comprehensive membership and role management capabilities. It serves as the foundation for most DAO implementation.

## 1. Core Components

Provides three main types for managing DAO membership and roles:

```go
// DAO member with assigned roles
type Member struct { 
    Address string    
    Roles   []string  
}

// Contains metadata about DAO roles
type RoleInfo struct { 
    Name        string 
    Description string 
    Color       string 
}

// Central component for managing members and roles
type MembersStore struct { 
    Roles   *avl.Tree 
    Members *avl.Tree 
}
```

### MembersStore Usage

**Creating and initializing**:
```go
// Create with initial data
store := basedao.NewMembersStore(
    []basedao.RoleInfo{
        {Name: "admin", Description: "Administrators", Color: "#329175"},
        {Name: "treasurer", Description: "Treasury management", Color: "#F3D3BC"},
    },
    []basedao.Member{
        {Address: "g1admin...", Roles: []string{"admin"}},
        {Address: "g1user...", Roles: []string{}},
    },
)

// Create empty store for dynamic management
store := basedao.NewMembersStore(nil, nil)
```

**Common operations**:
```go
// Member operations
store.AddMember("g1new...", []string{"moderator"})
store.RemoveMember("g1former...")
isMember := store.IsMember("g1user...")
count := store.MembersCount()

// Role operations  
store.AddRole(basedao.RoleInfo{Name: "secretary", Description: "Records keeper", Color: "#4A90E2"})
store.RemoveRole("obsolete-role")
store.AddRoleToMember("g1user...", "secretary")
store.RemoveRoleFromMember("g1user...", "moderator")

// Query operations
hasRole := store.HasRole("g1user...", "admin")
memberRoles := store.GetMemberRoles("g1user...")
roleMembers := store.GetMembersWithRole("admin")
adminCount := store.CountMembersWithRole("admin")
membersWithoutRoles := store.GetMembersWithoutRole()
roleInfo := store.RoleInfo("admin")  // Get role metadata
membersJSON := store.GetMembersJSON() // Export as JSON
```

## 2. Built-in Actions

Provides built-in actions for common DAO operations. Each action has a unique type identifier:

### Action Type Constants
```go
const ActionAddMemberKind = "gno.land/p/samcrew/basedao.AddMember"
const ActionRemoveMemberKind = "gno.land/p/samcrew/basedao.RemoveMember"  
const ActionAssignRoleKind = "gno.land/p/samcrew/basedao.AssignRole"
const ActionUnassignRoleKind = "gno.land/p/samcrew/basedao.UnassignRole"
const ActionEditProfileKind = "gno.land/p/samcrew/basedao.EditProfile"
const ActionChangeDAOImplementationKind = "gno.land/p/samcrew/basedao.ChangeDAOImplementation"
```

### Creating Actions
```go
// Add a member with roles
action := basedao.NewAddMemberAction(&basedao.ActionAddMember{
    Address: address("g1newmember..."),
    Roles:   []string{"moderator", "treasurer"},
})

// Remove member
action := basedao.NewRemoveMemberAction(address("g1member..."))

// Assign role to member
action := basedao.NewAssignRoleAction(&basedao.ActionAssignRole{
    Address: address("g1member..."),
    Role:    "admin",
})

// Remove role from member
action := basedao.NewUnassignRoleAction(&basedao.ActionUnassignRole{
    Address: address("g1member..."),
    Role:    "moderator",
})

// Edit DAO profile
action := basedao.NewEditProfileAction(
    [2]string{"DisplayName", "My Updated DAO Name"},
    [2]string{"Bio", "An improved description of our DAO"},
    [2]string{"Avatar", "https://example.com/new-logo.png"},
)
```

## 3. Core Governance Interface

Allow DAO's members to interact through proposals and voting.

### Creating Proposals
```go
// Create a new proposal for members to vote on
// Returns its proposal ID
func Propose(req daokit.ProposalRequest) uint64 {...}

type ProposalRequest struct {
	Title       string 
	Description string 
	Action      Action
}
```

**Example - Adding a new member:**
```go
addMemberAction := basedao.NewAddMemberAction(&basedao.ActionAddMember{
    Address: "g1alice...",
    Roles:   []string{"treasurer"},
})

proposal := daokit.ProposalRequest{
    Title:       "Add new treasurer",
    Description: "Proposal to add Alice as treasurer for better fund management",
    Action:      addMemberAction,
}
proposalID := Propose(proposal)
```

#### Voting on Proposals
```go
// Cast your vote on an active proposal
// Available vote: VoteYes, VoteNo, VoteAbstain
func Vote(proposalID uint64, vote daocond.Vote) {...}

Vote(1, daocond.VoteYes) // Vote yes on proposal #1
Vote(2, daocond.VoteNo) // Vote no on proposal #2
Vote(3, daocond.VoteAbstain) // Vote abstain on proposal #3
```

#### Executing Proposals  
```go
// Execute a proposal that has passed its voting requirements.
// cur is threaded down to the action handler so it can perform cross-realm calls.
func Execute(cur realm, proposalID uint64) {...}

Execute(cross(cur), 1) // Execute proposal #1 -- only works if it has enough votes
```

#### Instant Execution

Skip the voting process and execute a proposal immediately if you have the required permissions:

```go
// This performs: Propose() -> Vote(VoteYes) -> Execute()
proposalID := daokit.InstantExecute(DAO, proposal, cur)
```

Useful for admin actions, migrations, and emergency procedures.

### Rendering DAO Information

**Built-in render paths**:
- `/` - Main DAO overview with basic info
- `/members` - Member list with roles and permissions
- `/proposals` - Proposal list with their status and voting progress  
- `/proposals/{id}` - Detailed view of a proposal with vote breakdown
- `/config` - DAO configuration and governance rules
- `/roles` - Available roles and their descriptions

You can add or overwrite renders by providing a custom `RenderFn` in the DAO configuration.

## 4. Creating a DAO with basedao

### 4.1 Basic DAO Setup

```go
package my_dao

import (
    "gno.land/p/samcrew/basedao"
    "gno.land/p/samcrew/daocond"
    "gno.land/p/samcrew/daokit"
)

var (
	localDAO   daokit.DAO          // Local interface for DAO interaction
	daoPrivate *basedao.DAOPrivate // Full access to internal DAO state
)

func init(cur realm) {
    // Set up roles
    roles := []basedao.RoleInfo{
        {Name: "admin", Description: "Administrators", Color: "#329175"},
        {Name: "member", Description: "Regular members", Color: "#21577A"},
    }

    // Add initial members
    members := []basedao.Member{
        {Address: "g1admin...", Roles: []string{"admin"}},
        {Address: "g1user1...", Roles: []string{"member"}},
        {Address: "g1user2...", Roles: []string{"member"}},
    }

    store := basedao.NewMembersStore(roles, members)

    // Require 60% of members to approve proposals
    condition := daocond.MembersThreshold(0.6, store.IsMember, store.MembersCount)

    // Create the DAO (cur is threaded so the DAO can perform cross-realm calls)
    localDAO, daoPrivate = basedao.New(&basedao.Config{
        Name:             "My DAO",
        Description:      "A simple DAO example",
        Members:          store,
        InitialCondition: condition,
    }, cur)
}

// Create a new Proposal to be voted on
// To execute this function, you must use a MsgRun (maketx run)
// See why it is necessary in Gno Documentation: https://docs.gno.land/users/interact-with-gnokey#run
func Propose(cur realm, req daokit.ProposalRequest) {
	localDAO.Propose(req)
}

// Allows DAO members to cast their vote on a specific proposal
func Vote(cur realm, proposalID uint64, vote daocond.Vote) {
    localDAO.Vote(proposalID, vote)
}

// Triggers the implementation of a proposal's actions
func Execute(cur realm, proposalID uint64) {
	localDAO.Execute(proposalID, cur)
}

// Render generates a UI representation of the DAO's state
func Render(path string) string {
	return localDAO.Render(path)
}
```

### 4.2 Configuration Options

```go
type Config struct {
	// Basic DAO information
	Name        string
	Description string
	ImageURI    string

	// Core components
	Members *MembersStore

	// Feature toggles
	NoDefaultHandlers  bool // Skips registration of default management actions (add/remove members, etc.)
	NoDefaultRendering bool // Skips setup of default web UI rendering routes
	NoCreationEvent    bool // Skips emitting the DAO creation event

	// Governance configuration
	InitialCondition daocond.Condition // Default condition for all built-in actions, defaults to 60% member majority

	// Profile integration (optional)
	SetProfileString ProfileStringSetter // Function to update profile fields (DisplayName, Bio, Avatar)
	GetProfileString ProfileStringGetter // Function to retrieve profile fields for members

	// Advanced customization hooks
	SetImplemFn       SetImplemRaw      // Function called when DAO implementation changes via governance
	MigrationParamsFn MigrationParamsFn // Function providing parameters for DAO upgrades
	RenderFn          RenderFn          // Rendering function for Gnoweb
	CallerID          CallerIDFn        // Custom function to identify the current caller, defaults to realmid.Previous

	// Internal configuration
	PrivateVarName string // Name of the private DAO variable for member querying extensions
}
```

## 5. DAO Upgrades and Migration

Supports upgrading DAO implementations through governance proposals, allowing DAOs to evolve over time.

### 5.1 Configuration for Upgrades

```go
DAO, daoPrivate = basedao.New(&basedao.Config{
    // ... other config
    MigrationParamsFn: func() []any { return nil }, // Parameters passed to migration function

    SetImplemFn: setImplem,
}, cur)

// Update DAO variable after migration
func setImplem(newDAO daokit.DAO) {
    DAO = newDAO
}
```

### 5.2 Migration Process

```go
// Migration function signature (rlm is threaded so the migration can create a new DAO)
type MigrateFn = func(prev *DAOPrivate, params []any, rlm realm) daokit.DAO

// Parameters function signature  
type MigrationParamsFn = func() []any

// 1. Define migration function
// params contains data from MigrationParamsFn - use for config, settings, etc.
func migrateTo2_0(prev *basedao.DAOPrivate, params []any, rlm realm) daokit.DAO {
    // Preserve existing member store
    memberStore := prev.Members

    // Add new roles for v2.0
    memberStore.AddRole(basedao.RoleInfo{
        Name: "auditor", 
        Description: "Financial oversight",
    })

    // Create new DAO with enhanced features
    newLocalDAO, newPrivate := basedao.New(&basedao.Config{
        Name:             prev.InitialConfig.Name + " v2.0",
        Description:      "Upgraded DAO with audit capabilities",
        Members:          memberStore,
        InitialCondition: prev.InitialConfig.InitialCondition,
        // ... other configuration
    }, rlm)

    return newLocalDAO
}

// 2. Create and submit upgrade proposal
action := basedao.NewChangeDAOImplementationAction(migrateTo2_0)
proposal := daokit.ProposalRequest{
    Title:       "Upgrade to DAO v2.0",
    Description: "Adds auditor role and enhanced governance",
    Action:      action,
}
proposalID := DAO.Propose(proposal)

// 3. Execute Migration
DAO.Execute(proposalID, cur)

// Alternatively, you can use InstantExecute to skip the voting process
// if you have sufficient permissions to execute the action directly
daokit.InstantExecute(DAO, proposal, cur) 
```

## 6. Event System

Events are emitted when actions happen in your DAO. This helps track activities.

```go
// DAO creation (only if NoCreationEvent is false)
chain.Emit("BaseDAOCreated")

// Member management
chain.Emit("BaseDAOAddMember", "address", memberAddr)
chain.Emit("BaseDAORemoveMember", "address", memberAddr)
```

## 7. Membership Extension

Allows other packages and realms to check if an address is a member of your DAO.

### Usage

```go
import "gno.land/p/samcrew/basedao"

// Check if someone is a DAO member
ext := basedao.MustGetMembersViewExtension(localDAO)
if ext.IsMember("g1user...") {
    // User is a member
}
```

### Example: Member-Only action

The DAO value is kept unexported in the DAO realm, so expose a read-only membership check for other realms:

```go
package my_dao

// IsMember reports whether addr is a member of this DAO.
func IsMember(addr string) bool {
    return basedao.MustGetMembersViewExtension(localDAO).IsMember(addr)
}
```

Other realms can then gate actions on membership:

```go
package my_content

import (
    "chain/runtime/unsafe"

    "gno.land/r/some/dao"
)

func Post(title, content string) {
    caller := unsafe.PreviousRealm().Address()

    if !dao.IsMember(caller.String()) {
        panic("Only DAO members can post")
    }

    createPost(title, content)
}
```

The extension is automatically registered when you create a DAO with `basedao.New()`.

