package escrow_v2

// Milestone-based Escrow — On-chain freelance service contracts for Memba.
//
// Flow: CreateContract → FundMilestone → CompleteMilestone → ReleaseFunds
// Disputes: RaiseDispute → admin resolves (or auto-resolves after timeout)
// Timeouts: ClaimRefund (auto-refund if milestone not completed after N blocks)
//           ClaimDisputeTimeout (auto-release to freelancer if admin doesn't act)
//
// Security:
//   - STATE-BEFORE-SEND: All state updates happen before SendCoins calls
//   - FeeRecipient validated in init()
//   - Self-hire prevention: freelancer != client
//   - Input validation: title/description length, milestone amounts > 0
//   - Auto-refund: prevents permanent fund locking
//   - Dispute timeout: prevents permanent dispute locking
//
// Render() contract:
//   Home — Render(""):
//     # Escrow Contracts
//     | ID | Title | Client | Freelancer | Status | Total |
//
//   Detail — Render("contract/ID"):
//     # Title
//     **Client:** g1...
//     **Freelancer:** g1...
//     **Status:** active
//     ## Milestones
//     - **Milestone Title** — 1000000 ugnot [funded]

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
)

// ── Constants ────────────────────────────────────────────────

const (
	AdminAddress    = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0" // samcrew-core-test1 multisig
	FeeRecipient    = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0" // Samourai Coop multisig
	PlatformFeePct  = 2  // 2%
	CancelFeePct    = 5  // 5% cancellation fee
	AutoRefundBlks  = int64(864000)  // ~30 days at 3s/block
	AutoResolveBlks = int64(806400)  // ~28 days at 3s/block
	MaxTitleLen        = 200
	MaxDescLen         = 5000
	MaxMilestones      = 20
	MaxContracts       = 500
	MinMilestoneAmount = int64(1000) // 0.001 GNOT — prevents fee evasion via truncation
)

// ── Types ────────────────────────────────────────────────────

type ContractStatus string

const (
	StatusActive    ContractStatus = "active"
	StatusCompleted ContractStatus = "completed"
	StatusDisputed  ContractStatus = "disputed"
	StatusCancelled ContractStatus = "cancelled"
)

type MilestoneStatus string

const (
	MsPending   MilestoneStatus = "pending"
	MsFunded    MilestoneStatus = "funded"
	MsCompleted MilestoneStatus = "completed"
	MsReleased  MilestoneStatus = "released"
	MsDisputed  MilestoneStatus = "disputed"
	MsRefunded  MilestoneStatus = "refunded"
)

type Contract struct {
	ID          string
	Client      address
	Freelancer  address
	Title       string
	Description string
	Status      ContractStatus
	CreatedAt   int64 // block height
	Milestones  []Milestone
}

type Milestone struct {
	ID               int
	Title            string
	Amount           int64 // ugnot
	Status           MilestoneStatus
	FundedAt         int64           // block height (0 if not funded)
	CompletedAt      int64           // block height (0 if not completed)
	DisputedAt       int64           // block height (0 if not disputed)
	PreDisputeStatus MilestoneStatus // status before dispute (MsFunded or MsCompleted)
}

// ── State ────────────────────────────────────────────────────

var (
	contracts *avl.Tree // id -> *Contract
	nextID    int
	paused    bool
)

func init() {
	contracts = avl.NewTree()

	// Validate FeeRecipient at init — prevents fund-trapping panics later
	if len(FeeRecipient) == 0 {
		panic("FeeRecipient cannot be empty")
	}
}

// ── Emergency Pause ────────────────────────────────────────

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

// Pause halts all write operations. Admin only.
func Pause(cur realm) {
	caller := unsafe.PreviousRealm().Address()
	if caller != address(AdminAddress) {
		panic("only admin can pause")
	}
	paused = true
}

// Unpause resumes normal operations. Admin only.
func Unpause(cur realm) {
	caller := unsafe.PreviousRealm().Address()
	if caller != address(AdminAddress) {
		panic("only admin can unpause")
	}
	paused = false
}

// IsPaused returns the current pause state.
func IsPaused() bool {
	return paused
}

// ── Contract Lifecycle ──────────────────────────────────────

// CreateContract creates a new escrow contract with milestones.
// Milestones format: "title1:amount1,title2:amount2"
func CreateContract(cur realm, freelancer address, title, description, milestones string) string {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	// Validations
	if freelancer == caller {
		panic("cannot hire yourself")
	}
	if len(title) == 0 || len(title) > MaxTitleLen {
		panic(ufmt.Sprintf("title must be 1-%d characters", MaxTitleLen))
	}
	if len(description) > MaxDescLen {
		panic(ufmt.Sprintf("description must be under %d characters", MaxDescLen))
	}
	if contracts.Size() >= MaxContracts {
		panic("contract limit reached")
	}

	ms := parseMilestones(milestones)
	if len(ms) == 0 {
		panic("at least one milestone required")
	}
	if len(ms) > MaxMilestones {
		panic(ufmt.Sprintf("maximum %d milestones allowed", MaxMilestones))
	}

	id := strconv.Itoa(nextID)
	nextID++

	c := &Contract{
		ID:          id,
		Client:      caller,
		Freelancer:  freelancer,
		Title:       sanitizeMilestoneTitle(title),
		Description: sanitizeMilestoneTitle(description),
		Status:      StatusActive,
		CreatedAt:   runtime.ChainHeight(),
		Milestones:  ms,
	}
	contracts.Set(id, c)

	chain.Emit("ContractCreated",
		"id", id,
		"client", caller.String(),
		"freelancer", freelancer.String(),
		"milestones", strconv.Itoa(len(ms)),
	)
	return id
}

// FundMilestone deposits funds for a specific milestone. Client only.
func FundMilestone(cur realm, contractId string, milestoneIdx int) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	c := getContract(contractId)

	if c.Client != caller {
		panic("only client can fund")
	}
	if c.Status != StatusActive {
		panic("contract not active")
	}
	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsPending {
		panic("milestone already funded or processed")
	}

	// Verify coins sent (accumulate to handle multi-entry defensively)
	sent := unsafe.OriginSend()
	sentAmount := int64(0)
	for _, coin := range sent {
		if coin.Denom == "ugnot" {
			sentAmount += coin.Amount
		}
	}
	if sentAmount != ms.Amount {
		panic(ufmt.Sprintf("must send exactly %d ugnot (sent %d)", ms.Amount, sentAmount))
	}

	ms.Status = MsFunded
	ms.FundedAt = runtime.ChainHeight()
	contracts.Set(contractId, c)

	chain.Emit("MilestoneFunded",
		"contractId", contractId,
		"milestone", strconv.Itoa(milestoneIdx),
		"amount", strconv.FormatInt(ms.Amount, 10),
	)
}

// CompleteMilestone marks a milestone as completed. Freelancer only.
func CompleteMilestone(cur realm, contractId string, milestoneIdx int) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	c := getContract(contractId)

	if c.Freelancer != caller {
		panic("only freelancer can mark complete")
	}
	// Only allow completion when contract is Active. Disputed contracts are frozen
	// until ResolveDispute/ClaimDisputeTimeout returns the contract to Active.
	if c.Status != StatusActive {
		panic("contract is " + string(c.Status) + " — cannot complete milestones during dispute")
	}
	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsFunded {
		panic("milestone not funded")
	}

	ms.Status = MsCompleted
	ms.CompletedAt = runtime.ChainHeight()
	contracts.Set(contractId, c)

	chain.Emit("MilestoneCompleted",
		"contractId", contractId,
		"milestone", strconv.Itoa(milestoneIdx),
		"freelancer", caller.String(),
	)
}

// ReleaseFunds releases funds to freelancer after client approves. Client or Admin.
func ReleaseFunds(cur realm, contractId string, milestoneIdx int) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	c := getContract(contractId)

	if c.Client != caller && caller != address(AdminAddress) {
		panic("only client or admin can release")
	}
	// Only allow release when contract is Active. Disputed contracts are frozen
	// until ResolveDispute/ClaimDisputeTimeout returns the contract to Active.
	if c.Status != StatusActive {
		panic("contract is " + string(c.Status) + " — cannot release funds during dispute")
	}
	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsCompleted {
		panic("milestone not completed")
	}

	// Calculate fees
	platformAmount := (ms.Amount * int64(PlatformFeePct)) / 100
	freelancerAmount := ms.Amount - platformAmount

	// STATE-BEFORE-SEND: update all state before any coin transfers
	ms.Status = MsReleased
	if allMilestonesReleased(c) {
		c.Status = StatusCompleted
	}
	contracts.Set(contractId, c)

	// Transfer funds
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	realmAddr := unsafe.CurrentRealm().Address()

	bnk.SendCoins(realmAddr, c.Freelancer, chain.Coins{chain.NewCoin("ugnot", freelancerAmount)})
	if platformAmount > 0 {
		bnk.SendCoins(realmAddr, address(FeeRecipient), chain.Coins{chain.NewCoin("ugnot", platformAmount)})
	}

	chain.Emit("FundsReleased",
		"contractId", contractId,
		"milestone", strconv.Itoa(milestoneIdx),
		"freelancer", c.Freelancer.String(),
		"amount", strconv.FormatInt(freelancerAmount, 10),
		"fee", strconv.FormatInt(platformAmount, 10),
	)
}

// ── Disputes ────────────────────────────────────────────────

// RaiseDispute escalates a milestone to admin arbitration. Client or Freelancer.
func RaiseDispute(cur realm, contractId string, milestoneIdx int) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	c := getContract(contractId)

	if c.Client != caller && c.Freelancer != caller {
		panic("only client or freelancer can dispute")
	}
	if c.Status == StatusCancelled || c.Status == StatusCompleted {
		panic("contract is " + string(c.Status))
	}
	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsFunded && ms.Status != MsCompleted {
		panic("can only dispute funded or completed milestones")
	}

	// Capture pre-dispute status so ClaimDisputeTimeout can resolve fairly:
	// if work was delivered (MsCompleted), pay freelancer; if not (MsFunded), refund client.
	ms.PreDisputeStatus = ms.Status
	ms.Status = MsDisputed
	ms.DisputedAt = runtime.ChainHeight()
	c.Status = StatusDisputed
	contracts.Set(contractId, c)

	chain.Emit("DisputeRaised",
		"contractId", contractId,
		"milestone", strconv.Itoa(milestoneIdx),
		"raisedBy", caller.String(),
	)
}

// ResolveDispute resolves a dispute. Admin only.
// refundClient=true refunds to client, false pays freelancer.
func ResolveDispute(cur realm, contractId string, milestoneIdx int, refundClient bool) {
	caller := unsafe.PreviousRealm().Address()
	if caller != address(AdminAddress) {
		panic("only admin can resolve disputes")
	}

	c := getContract(contractId)
	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsDisputed {
		panic("milestone not in dispute")
	}

	// STATE-BEFORE-SEND: update state before transfers
	if refundClient {
		ms.Status = MsRefunded
	} else {
		ms.Status = MsReleased
	}
	// Reset contract status if no other milestones are disputed
	c.Status = StatusActive
	for _, m := range c.Milestones {
		if m.Status == MsDisputed {
			c.Status = StatusDisputed
			break
		}
	}
	if allMilestonesReleased(c) {
		c.Status = StatusCompleted
	}
	contracts.Set(contractId, c)

	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	realmAddr := unsafe.CurrentRealm().Address()

	if refundClient {
		bnk.SendCoins(realmAddr, c.Client, chain.Coins{chain.NewCoin("ugnot", ms.Amount)})
	} else {
		platformAmount := (ms.Amount * int64(PlatformFeePct)) / 100
		freelancerAmount := ms.Amount - platformAmount
		bnk.SendCoins(realmAddr, c.Freelancer, chain.Coins{chain.NewCoin("ugnot", freelancerAmount)})
		if platformAmount > 0 {
			bnk.SendCoins(realmAddr, address(FeeRecipient), chain.Coins{chain.NewCoin("ugnot", platformAmount)})
		}
	}

	resolution := "released-to-freelancer"
	if refundClient {
		resolution = "refunded-to-client"
	}
	chain.Emit("DisputeResolved",
		"contractId", contractId,
		"milestone", strconv.Itoa(milestoneIdx),
		"resolution", resolution,
	)
}

// ── Cancellation ────────────────────────────────────────────

// CancelContract cancels an active contract. Client only.
// Funded milestones are refunded minus cancellation fee.
func CancelContract(cur realm, contractId string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	c := getContract(contractId)

	if c.Client != caller {
		panic("only client can cancel")
	}
	if c.Status != StatusActive {
		panic("contract not active")
	}

	// STATE-BEFORE-SEND: update all state before transfers.
	// Track which milestones are NEWLY transitioned so we only pay those,
	// preventing double-refund of milestones already resolved via ResolveDispute.
	c.Status = StatusCancelled
	var newlyRefunded []int
	var newlyReleased []int
	for i := range c.Milestones {
		if c.Milestones[i].Status == MsFunded {
			c.Milestones[i].Status = MsRefunded
			newlyRefunded = append(newlyRefunded, i)
		} else if c.Milestones[i].Status == MsCompleted {
			c.Milestones[i].Status = MsReleased
			newlyReleased = append(newlyReleased, i)
		}
		// Already-terminal milestones (MsRefunded from ResolveDispute, MsReleased from
		// ReleaseFunds) are NOT added to the payment lists — their funds were already
		// distributed in the original operation.
	}
	contracts.Set(contractId, c)

	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	realmAddr := unsafe.CurrentRealm().Address()

	for _, i := range newlyRefunded {
		ms := c.Milestones[i]
		// Refund funded milestones minus cancellation fee
		fee := (ms.Amount * int64(CancelFeePct)) / 100
		refund := ms.Amount - fee
		if refund > 0 {
			bnk.SendCoins(realmAddr, c.Client, chain.Coins{chain.NewCoin("ugnot", refund)})
		}
		// Cancellation fee goes to freelancer as compensation for lost opportunity
		if fee > 0 {
			bnk.SendCoins(realmAddr, c.Freelancer, chain.Coins{chain.NewCoin("ugnot", fee)})
		}
	}
	for _, i := range newlyReleased {
		ms := c.Milestones[i]
		// Pay freelancer for completed work (full amount minus platform fee)
		platformAmount := (ms.Amount * int64(PlatformFeePct)) / 100
		freelancerAmount := ms.Amount - platformAmount
		bnk.SendCoins(realmAddr, c.Freelancer, chain.Coins{chain.NewCoin("ugnot", freelancerAmount)})
		if platformAmount > 0 {
			bnk.SendCoins(realmAddr, address(FeeRecipient), chain.Coins{chain.NewCoin("ugnot", platformAmount)})
		}
	}
}

// ── Timeouts (permissionless) ───────────────────────────────

// ClaimRefund refunds a funded milestone that has timed out.
// Anyone can call — permissionless, prevents fund locking.
func ClaimRefund(cur realm, contractId string, milestoneIdx int) {
	c := getContract(contractId)

	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsFunded {
		panic("milestone not funded")
	}
	if ms.FundedAt == 0 {
		panic("milestone has no funding record")
	}

	elapsed := runtime.ChainHeight() - ms.FundedAt
	if elapsed < AutoRefundBlks {
		panic(ufmt.Sprintf("too early: %d blocks remaining", AutoRefundBlks-elapsed))
	}

	// STATE-BEFORE-SEND
	ms.Status = MsRefunded
	// Update contract status if all milestones are now terminal
	if allMilestonesTerminal(c) {
		c.Status = StatusCancelled
	}
	contracts.Set(contractId, c)

	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	bnk.SendCoins(
		unsafe.CurrentRealm().Address(),
		c.Client,
		chain.Coins{chain.NewCoin("ugnot", ms.Amount)},
	)
}

// ClaimDisputeTimeout auto-resolves a dispute that admin hasn't acted on after
// AutoResolveBlks (~28 days). Resolution follows the pre-dispute status:
//   - If the milestone was MsCompleted (freelancer delivered work) before dispute,
//     funds go to freelancer (minus platform fee). This prevents griefing where
//     a client disputes after delivery and simply waits out the clock.
//   - If the milestone was MsFunded (work not yet delivered) before dispute,
//     funds are refunded to client.
// Anyone can call (permissionless safety valve).
func ClaimDisputeTimeout(cur realm, contractId string, milestoneIdx int) {
	c := getContract(contractId)

	if milestoneIdx < 0 || milestoneIdx >= len(c.Milestones) {
		panic("invalid milestone index")
	}

	ms := &c.Milestones[milestoneIdx]
	if ms.Status != MsDisputed {
		panic("milestone not in dispute")
	}
	if ms.DisputedAt == 0 {
		panic("milestone has no dispute record")
	}

	elapsed := runtime.ChainHeight() - ms.DisputedAt
	if elapsed < AutoResolveBlks {
		panic(ufmt.Sprintf("too early: %d blocks remaining", AutoResolveBlks-elapsed))
	}

	// Resolve based on pre-dispute status — fair to both parties.
	payFreelancer := ms.PreDisputeStatus == MsCompleted

	// STATE-BEFORE-SEND
	if payFreelancer {
		ms.Status = MsReleased
	} else {
		ms.Status = MsRefunded
	}
	// Reset contract status
	c.Status = StatusActive
	for _, m := range c.Milestones {
		if m.Status == MsDisputed {
			c.Status = StatusDisputed
			break
		}
	}
	if allMilestonesReleased(c) {
		c.Status = StatusCompleted
	} else if allMilestonesTerminal(c) {
		c.Status = StatusCancelled
	}
	contracts.Set(contractId, c)

	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	realmAddr := unsafe.CurrentRealm().Address()

	if payFreelancer {
		// Work was delivered — pay freelancer minus platform fee
		platformAmount := (ms.Amount * int64(PlatformFeePct)) / 100
		freelancerAmount := ms.Amount - platformAmount
		bnk.SendCoins(realmAddr, c.Freelancer, chain.Coins{chain.NewCoin("ugnot", freelancerAmount)})
		if platformAmount > 0 {
			bnk.SendCoins(realmAddr, address(FeeRecipient), chain.Coins{chain.NewCoin("ugnot", platformAmount)})
		}
		chain.Emit("DisputeTimedOut",
			"contractId", contractId,
			"milestone", strconv.Itoa(milestoneIdx),
			"resolution", "paid-freelancer-work-delivered",
		)
	} else {
		// Work never delivered — refund client in full
		bnk.SendCoins(realmAddr, c.Client, chain.Coins{chain.NewCoin("ugnot", ms.Amount)})
		chain.Emit("DisputeTimedOut",
			"contractId", contractId,
			"milestone", strconv.Itoa(milestoneIdx),
			"resolution", "refunded-client-no-delivery",
		)
	}
}

// ── Render ───────────────────────────────────────────────────

func Render(path string) string {
	if path == "" {
		return renderHome()
	}
	if strings.HasPrefix(path, "contract/") {
		id := strings.TrimPrefix(path, "contract/")
		return renderContract(id)
	}
	if path == "stats" {
		return renderStats()
	}
	return "# 404\nNot found: " + path
}

func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# Escrow Contracts\n\n")
	sb.WriteString("Milestone-based escrow for freelance services on Gno.\n\n")

	if contracts.Size() == 0 {
		sb.WriteString("*No contracts yet.*\n")
		return sb.String()
	}

	sb.WriteString("| ID | Title | Client | Freelancer | Status | Total |\n")
	sb.WriteString("| --- | --- | --- | --- | --- | --- |\n")

	contracts.Iterate("", "", func(key string, value interface{}) bool {
		c := value.(*Contract)
		total := int64(0)
		for _, ms := range c.Milestones {
			total += ms.Amount
		}
		sb.WriteString(ufmt.Sprintf("| %s | [%s](:contract/%s) | %s | %s | %s | %d ugnot |\n",
			c.ID, c.Title, c.ID, truncAddr(c.Client), truncAddr(c.Freelancer),
			string(c.Status), total))
		return false
	})

	return sb.String()
}

func renderContract(id string) string {
	val, exists := contracts.Get(id)
	if !exists {
		return "# 404\nContract not found: " + id
	}
	c := val.(*Contract)

	var sb strings.Builder
	sb.WriteString("# " + c.Title + "\n\n")
	if len(c.Description) > 0 {
		sb.WriteString(c.Description + "\n\n")
	}
	sb.WriteString("**ID:** " + c.ID + "\n")
	sb.WriteString("**Client:** " + c.Client.String() + "\n")
	sb.WriteString("**Freelancer:** " + c.Freelancer.String() + "\n")
	sb.WriteString("**Status:** " + string(c.Status) + "\n")
	sb.WriteString("**Created:** block " + strconv.FormatInt(c.CreatedAt, 10) + "\n\n")

	total := int64(0)
	for _, ms := range c.Milestones {
		total += ms.Amount
	}
	sb.WriteString("**Total Value:** " + strconv.FormatInt(total, 10) + " ugnot\n\n")

	sb.WriteString("## Milestones\n\n")
	for _, ms := range c.Milestones {
		sb.WriteString(ufmt.Sprintf("- **%s** — %d ugnot [%s]",
			ms.Title, ms.Amount, string(ms.Status)))
		if ms.FundedAt > 0 {
			sb.WriteString(ufmt.Sprintf(" (funded block %d)", ms.FundedAt))
		}
		if ms.CompletedAt > 0 {
			sb.WriteString(ufmt.Sprintf(" (completed block %d)", ms.CompletedAt))
		}
		if ms.DisputedAt > 0 {
			sb.WriteString(ufmt.Sprintf(" (disputed block %d)", ms.DisputedAt))
		}
		sb.WriteString("\n")
	}

	return sb.String()
}

func renderStats() string {
	var sb strings.Builder
	sb.WriteString("# Escrow Stats\n\n")

	totalContracts := contracts.Size()
	active, completed, disputed, cancelled := 0, 0, 0, 0
	totalValue := int64(0)

	contracts.Iterate("", "", func(key string, value interface{}) bool {
		c := value.(*Contract)
		switch c.Status {
		case StatusActive:
			active++
		case StatusCompleted:
			completed++
		case StatusDisputed:
			disputed++
		case StatusCancelled:
			cancelled++
		}
		for _, ms := range c.Milestones {
			totalValue += ms.Amount
		}
		return false
	})

	sb.WriteString(ufmt.Sprintf("**Total Contracts:** %d\n", totalContracts))
	sb.WriteString(ufmt.Sprintf("**Active:** %d | **Completed:** %d | **Disputed:** %d | **Cancelled:** %d\n", active, completed, disputed, cancelled))
	sb.WriteString(ufmt.Sprintf("**Total Value:** %d ugnot\n", totalValue))

	return sb.String()
}

// ── Helpers ──────────────────────────────────────────────────

func getContract(id string) *Contract {
	val, exists := contracts.Get(id)
	if !exists {
		panic("contract not found: " + id)
	}
	return val.(*Contract)
}

func allMilestonesReleased(c *Contract) bool {
	for _, m := range c.Milestones {
		if m.Status != MsReleased {
			return false
		}
	}
	return true
}

// allMilestonesTerminal returns true if every milestone is in a final state
// (released, refunded, or pending — pending with no funds is terminal).
func allMilestonesTerminal(c *Contract) bool {
	for _, m := range c.Milestones {
		if m.Status == MsFunded || m.Status == MsCompleted || m.Status == MsDisputed {
			return false
		}
	}
	return true
}

// parseMilestones parses "title1:amount1,title2:amount2" into Milestone slice.
// Invalid entries cause a panic (not silently skipped).
func parseMilestones(input string) []Milestone {
	var result []Milestone
	parts := strings.Split(input, ",")
	for i, p := range parts {
		p = strings.TrimSpace(p)
		if len(p) == 0 {
			continue
		}
		kv := strings.SplitN(p, ":", 2)
		if len(kv) != 2 {
			panic(ufmt.Sprintf("invalid milestone format at position %d: expected 'title:amount'", i))
		}
		title := strings.TrimSpace(kv[0])
		if len(title) == 0 {
			panic(ufmt.Sprintf("empty milestone title at position %d", i))
		}
		if len(title) > MaxTitleLen {
			panic(ufmt.Sprintf("milestone title too long at position %d: %d/%d chars", i, len(title), MaxTitleLen))
		}
		title = sanitizeMilestoneTitle(title)
		amount, err := strconv.ParseInt(strings.TrimSpace(kv[1]), 10, 64)
		if err != nil || amount <= 0 {
			panic(ufmt.Sprintf("invalid milestone amount at position %d: must be positive integer", i))
		}
		// Minimum milestone amount prevents fee evasion via integer truncation.
		// At 2% fee, amounts < 50 ugnot would pay 0 fee.
		if amount < MinMilestoneAmount {
			panic(ufmt.Sprintf("milestone amount too small at position %d: minimum %d ugnot", i, MinMilestoneAmount))
		}
		result = append(result, Milestone{
			ID:     i,
			Title:  title,
			Amount: amount,
			Status: MsPending,
		})
	}
	return result
}

func truncAddr(addr address) string {
	s := addr.String()
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

// sanitizeMilestoneTitle strips markdown special characters to prevent injection
// in gnoweb Render output.
func sanitizeMilestoneTitle(s string) string {
	var out strings.Builder
	for _, c := range s {
		switch c {
		case '[', ']', '(', ')', '#', '*', '`', '!', '<', '>', '|', '\\', '_', '~', '\n', '\r', '\t':
			continue // strip markdown-sensitive characters and control whitespace
		default:
			out.WriteRune(c)
		}
	}
	return out.String()
}

package gnobuilders_badges_v2

// gnobuilders_badges — GRC721 badge collection for GnoBuilders quests.
//
// Features:
//   - Admin-only minting (backend triggers mint after quest verification)
//   - Two badge types: Quest badges (transferable) and Rank badges (soulbound)
//   - Per-quest deduplication (one badge per quest per user)
//   - Standard GRC721: BalanceOf, OwnerOf, TokenURI, TransferFrom, Approve
//   - Render() contract for badge gallery display
//
// Security:
//   - Only admin can mint (prevents self-minting)
//   - Soulbound badges: TransferFrom panics for rank badges
//   - Owner can add/remove admins
//   - Token ID format: "{address}:{questId}" (globally unique)

import (
	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
)

// ── Constants ────────────────────────────────────────────────

const (
	CollectionName   = "GnoBuilders Badges"
	CollectionSymbol = "GNOBADGE"
	MaxAdmins        = 10
)

// ── Types ────────────────────────────────────────────────────

type Badge struct {
	TokenID   string  // "{address}:{questId}"
	Owner     address
	QuestID   string
	TokenURI  string  // IPFS CID or URL to badge metadata JSON
	Soulbound bool    // true for rank badges (non-transferable)
	MintedAt  int64   // block height
}

// ── State ────────────────────────────────────────────────────

var (
	badges      *avl.Tree // tokenID -> *Badge
	ownerIndex  *avl.Tree // address -> comma-separated tokenIDs (secondary index)
	balances    *avl.Tree // address -> int (badge count)
	approvals   *avl.Tree // tokenID -> approved address
	opApprove   *avl.Tree // "owner:operator" -> bool (approval for all)
	admins      *avl.Tree // address -> bool
	// Owner is set at package load time via OriginCaller() — this captures the
	// deployer address (samcrew-core-test1 multisig on testnet).
	owner = unsafe.OriginCaller()
	totalMinted uint64
	paused      bool
)

func init() {
	badges = avl.NewTree()
	ownerIndex = avl.NewTree()
	balances = avl.NewTree()
	approvals = avl.NewTree()
	opApprove = avl.NewTree()
	admins = avl.NewTree()

	admins.Set(owner.String(), true)
}

// ── Emergency Pause ────────────────────────────────────────

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

func Pause(cur realm) {
	assertCallerIsOwner()
	paused = true
}

func Unpause(cur realm) {
	assertCallerIsOwner()
	paused = false
}

func IsPaused() bool { return paused }

// ── GRC721 Standard ─────────────────────────────────────────

func Name() string   { return CollectionName }
func Symbol() string { return CollectionSymbol }

func TotalSupply() uint64 { return totalMinted }

func BalanceOf(addr address) uint64 {
	val, exists := balances.Get(addr.String())
	if !exists {
		return 0
	}
	return uint64(val.(int))
}

func OwnerOf(tokenID string) address {
	val, exists := badges.Get(tokenID)
	if !exists {
		panic("token not found: " + tokenID)
	}
	return val.(*Badge).Owner
}

func TokenURI(tokenID string) string {
	val, exists := badges.Get(tokenID)
	if !exists {
		panic("token not found: " + tokenID)
	}
	return val.(*Badge).TokenURI
}

func Approve(cur realm, approved address, tokenID string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	val, exists := badges.Get(tokenID)
	if !exists {
		panic("token not found")
	}
	badge := val.(*Badge)
	if badge.Owner != caller {
		panic("only owner can approve")
	}
	if badge.Soulbound {
		panic("soulbound badges cannot be approved for transfer")
	}
	approvals.Set(tokenID, approved.String())

	// GRC721 Approval event
	chain.Emit("Approval",
		"owner", caller.String(),
		"approved", approved.String(),
		"tokenId", tokenID,
	)
}

func SetApprovalForAll(cur realm, operator address, approved bool) {
	assertNotPaused()
	if operator == "" {
		panic("operator address cannot be empty")
	}
	caller := unsafe.PreviousRealm().Address()
	if operator == caller {
		panic("cannot approve self")
	}
	key := caller.String() + ":" + operator.String()
	if approved {
		opApprove.Set(key, true)
	} else {
		opApprove.Remove(key)
	}
}

func IsApprovedForAll(ownerAddr address, operator address) bool {
	key := ownerAddr.String() + ":" + operator.String()
	_, exists := opApprove.Get(key)
	return exists
}

func GetApproved(tokenID string) address {
	val, exists := approvals.Get(tokenID)
	if !exists {
		return ""
	}
	return address(val.(string))
}

func TransferFrom(cur realm, from address, to address, tokenID string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	val, exists := badges.Get(tokenID)
	if !exists {
		panic("token not found")
	}
	badge := val.(*Badge)

	// Soulbound check
	if badge.Soulbound {
		panic("soulbound badges cannot be transferred")
	}

	// Auth check
	if badge.Owner != caller {
		approved := GetApproved(tokenID)
		if approved != caller && !IsApprovedForAll(from, caller) {
			panic("not authorized to transfer")
		}
	}

	if badge.Owner != from {
		panic("from address is not the owner")
	}

	// Transfer
	badge.Owner = to
	badges.Set(tokenID, badge)
	approvals.Remove(tokenID) // Clear approval

	// Update balances and owner index
	removeFromOwnerIndex(from, tokenID)
	addToOwnerIndex(to, tokenID)
	decBalance(from)
	incBalance(to)

	// GRC721 Transfer event
	chain.Emit("Transfer",
		"from", from.String(),
		"to", to.String(),
		"tokenId", tokenID,
	)
}

// ── Minting (Admin Only) ────────────────────────────────────

// MintQuestBadge mints a quest completion badge to a user.
// Token ID is "{address}:{questId}" to enforce one badge per quest per user.
// Quest badges are transferable by default.
func MintQuestBadge(cur realm, to address, questID string, tokenURI string) string {
	assertNotPaused()
	assertCallerIsAdmin()
	if len(questID) == 0 {
		panic("questID cannot be empty")
	}
	if containsChar(questID, ',') || containsChar(questID, ':') {
		panic("questID must not contain ',' or ':'")
	}

	tokenID := to.String() + ":" + questID

	// Check dedup
	if _, exists := badges.Get(tokenID); exists {
		panic("badge already minted for this quest: " + tokenID)
	}

	badge := &Badge{
		TokenID:   tokenID,
		Owner:     to,
		QuestID:   questID,
		TokenURI:  tokenURI,
		Soulbound: false,
		MintedAt:  runtime.ChainHeight(),
	}

	badges.Set(tokenID, badge)
	addToOwnerIndex(to, tokenID)
	incBalance(to)
	totalMinted++

	// GRC721 Transfer event from zero address (mint convention)
	chain.Emit("Transfer",
		"from", "",
		"to", to.String(),
		"tokenId", tokenID,
	)
	chain.Emit("QuestBadgeMinted",
		"to", to.String(),
		"questId", questID,
		"tokenId", tokenID,
	)

	return tokenID
}

// MintRankBadge mints a soulbound rank badge to a user.
// Token ID is "{address}:rank:{tier}" to enforce one rank badge per tier per user.
// Rank badges are NON-transferable (soulbound).
func MintRankBadge(cur realm, to address, tier int, tokenURI string) string {
	assertNotPaused()
	assertCallerIsAdmin()

	tokenID := to.String() + ":rank:" + strconv.Itoa(tier)

	// Check dedup
	if _, exists := badges.Get(tokenID); exists {
		panic("rank badge already minted for tier " + strconv.Itoa(tier))
	}

	badge := &Badge{
		TokenID:   tokenID,
		Owner:     to,
		QuestID:   "rank:" + strconv.Itoa(tier),
		TokenURI:  tokenURI,
		Soulbound: true,
		MintedAt:  runtime.ChainHeight(),
	}

	badges.Set(tokenID, badge)
	addToOwnerIndex(to, tokenID)
	incBalance(to)
	totalMinted++

	chain.Emit("Transfer",
		"from", "",
		"to", to.String(),
		"tokenId", tokenID,
	)
	chain.Emit("RankBadgeMinted",
		"to", to.String(),
		"tier", strconv.Itoa(tier),
		"tokenId", tokenID,
	)

	return tokenID
}

// UpdateTokenURI allows an admin to update the metadata URI of a badge.
// This is critical because realm code is immutable once deployed — if badge
// metadata needs correction (e.g., broken IPFS CID), this is the only mechanism.
func UpdateTokenURI(cur realm, tokenID string, newURI string) {
	assertNotPaused()
	assertCallerIsAdmin()
	val, exists := badges.Get(tokenID)
	if !exists {
		panic("token not found: " + tokenID)
	}
	badge := val.(*Badge)
	badge.TokenURI = newURI
	badges.Set(tokenID, badge)
}

// ── Burn / Revoke ───────────────────────────────────────────

// BurnBadge permanently removes a badge. Admin-only for soulbound badges,
// owner or admin for transferable badges.
func BurnBadge(cur realm, tokenID string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	val, exists := badges.Get(tokenID)
	if !exists {
		panic("token not found: " + tokenID)
	}
	badge := val.(*Badge)

	if badge.Soulbound {
		// Soulbound: admin-only burn (revocation)
		assertCallerIsAdmin()
	} else {
		// Transferable: owner or admin can burn
		isAdmin := false
		if _, aok := admins.Get(caller.String()); aok {
			isAdmin = true
		}
		if badge.Owner != caller && !isAdmin {
			panic("only badge owner or admin can burn")
		}
	}

	badgeOwner := badge.Owner
	badges.Remove(tokenID)
	approvals.Remove(tokenID)
	removeFromOwnerIndex(badgeOwner, tokenID)
	decBalance(badgeOwner)
	if totalMinted > 0 {
		totalMinted--
	}

	// GRC721 Transfer event to zero address (burn convention)
	chain.Emit("Transfer",
		"from", badgeOwner.String(),
		"to", "",
		"tokenId", tokenID,
	)
}

// ── Admin Management ────────────────────────────────────────

func AddAdmin(cur realm, addr address) {
	assertCallerIsOwner()
	if addr == "" {
		panic("address cannot be empty")
	}
	if admins.Size() >= MaxAdmins {
		panic("admin limit reached")
	}
	admins.Set(addr.String(), true)
}

func RemoveAdmin(cur realm, addr address) {
	assertCallerIsOwner()
	if addr == owner {
		panic("cannot remove owner")
	}
	if _, exists := admins.Get(addr.String()); !exists {
		panic("address is not an admin: " + addr.String())
	}
	admins.Remove(addr.String())
}

// TransferOwnership transfers realm ownership. The old owner remains as admin
// (the new owner can call RemoveAdmin to revoke). This is intentional to prevent
// accidental lockout during multi-step ownership transfers.
func TransferOwnership(cur realm, newOwner address) {
	assertCallerIsOwner()
	if newOwner == "" {
		panic("address cannot be empty")
	}
	if newOwner == owner {
		panic("already owner")
	}
	admins.Set(newOwner.String(), true)
	owner = newOwner
}

func IsAdmin(addr address) bool {
	_, exists := admins.Get(addr.String())
	return exists
}

func GetOwner() address { return owner }

// ── Queries ─────────────────────────────────────────────────

// GetBadge returns badge info as a pipe-delimited string.
func GetBadge(tokenID string) string {
	val, exists := badges.Get(tokenID)
	if !exists {
		return ""
	}
	b := val.(*Badge)
	sb := strconv.FormatBool(b.Soulbound)
	return ufmt.Sprintf("%s|%s|%s|%s|%s|%d",
		b.TokenID, b.Owner, b.QuestID, b.TokenURI, sb, b.MintedAt)
}

// GetUserBadges returns all badge token IDs for a user as comma-separated string.
// Uses the ownerIndex for O(1) lookup instead of full table scan.
func GetUserBadges(addr address) string {
	val, exists := ownerIndex.Get(addr.String())
	if !exists {
		return ""
	}
	return val.(string)
}

// GetUserBadgeDetails returns full badge details for a user as a multi-line string.
// Each line: tokenID|owner|questID|tokenURI|soulbound|mintedAt
// This avoids N+1 queries from the frontend — one call returns all badge data.
func GetUserBadgeDetails(addr address) string {
	tokenIDsStr := GetUserBadges(addr)
	if tokenIDsStr == "" {
		return ""
	}

	var lines []string
	for _, tokenID := range strings.Split(tokenIDsStr, ",") {
		info := GetBadge(tokenID)
		if info != "" {
			lines = append(lines, info)
		}
	}
	return strings.Join(lines, "\n")
}

// ── Render ──────────────────────────────────────────────────

func Render(path string) string {
	if path == "" {
		return renderHome()
	}
	if strings.HasPrefix(path, "badge/") {
		tokenID := strings.TrimPrefix(path, "badge/")
		return renderBadge(tokenID)
	}
	if strings.HasPrefix(path, "user/") {
		addr := strings.TrimPrefix(path, "user/")
		return renderUserBadges(addr)
	}
	return "# 404\nPage not found: " + path
}

func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# GnoBuilders Badges\n\n")
	sb.WriteString(ufmt.Sprintf("**Collection:** %s (%s)\n", CollectionName, CollectionSymbol))
	sb.WriteString(ufmt.Sprintf("**Total Minted:** %d\n", totalMinted))
	sb.WriteString(ufmt.Sprintf("**Owner:** %s\n", owner))
	sb.WriteString(ufmt.Sprintf("**Admins:** %d\n\n", admins.Size()))

	// Recent badges (last 20)
	count := 0
	sb.WriteString("## Recent Badges\n\n")
	sb.WriteString("| Token | Quest | Owner | Soulbound |\n")
	sb.WriteString("|-------|-------|-------|-----------|\n")
	badges.ReverseIterate("", "", func(key string, value any) bool {
		if count >= 20 {
			return true
		}
		b := value.(*Badge)
		soul := ""
		if b.Soulbound {
			soul = "yes"
		}
		sb.WriteString(ufmt.Sprintf("| %s | %s | %s | %s |\n",
			truncStr(b.TokenID, 30), b.QuestID, truncAddr(b.Owner), soul))
		count++
		return false
	})

	return sb.String()
}

func renderBadge(tokenID string) string {
	val, exists := badges.Get(tokenID)
	if !exists {
		return "# Badge Not Found\nNo badge with ID: " + tokenID
	}
	b := val.(*Badge)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Badge: %s\n\n", b.QuestID))
	sb.WriteString(ufmt.Sprintf("**Token ID:** %s\n", b.TokenID))
	sb.WriteString(ufmt.Sprintf("**Owner:** %s\n", b.Owner))
	sb.WriteString(ufmt.Sprintf("**Quest:** %s\n", b.QuestID))
	sb.WriteString(ufmt.Sprintf("**Soulbound:** %s\n", strconv.FormatBool(b.Soulbound)))
	sb.WriteString(ufmt.Sprintf("**Minted at block:** %d\n", b.MintedAt))
	if b.TokenURI != "" {
		sb.WriteString(ufmt.Sprintf("**Metadata:** %s\n", b.TokenURI))
	}
	return sb.String()
}

func renderUserBadges(addr string) string {
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Badges for %s\n\n", addr))

	// Use ownerIndex for O(1) lookup instead of full table scan
	tokenIDsStr := GetUserBadges(address(addr))
	if tokenIDsStr == "" {
		sb.WriteString("*No badges yet.*\n")
		return sb.String()
	}

	tokenIDs := strings.Split(tokenIDsStr, ",")
	for _, tokenID := range tokenIDs {
		val, exists := badges.Get(tokenID)
		if !exists {
			continue
		}
		b := val.(*Badge)
		soul := ""
		if b.Soulbound {
			soul = " (soulbound)"
		}
		sb.WriteString(ufmt.Sprintf("- **%s** — %s%s (block %d)\n",
			b.QuestID, truncStr(b.TokenURI, 40), soul, b.MintedAt))
	}

	return sb.String()
}

// ── Helpers ─────────────────────────────────────────────────

func assertCallerIsAdmin() {
	caller := unsafe.PreviousRealm().Address()
	if _, exists := admins.Get(caller.String()); !exists {
		panic("unauthorized: caller " + caller.String() + " is not an admin")
	}
}

func assertCallerIsOwner() {
	caller := unsafe.PreviousRealm().Address()
	if caller != owner {
		panic("unauthorized: caller " + caller.String() + " is not the owner")
	}
}

func incBalance(addr address) {
	val, exists := balances.Get(addr.String())
	if !exists {
		balances.Set(addr.String(), 1)
	} else {
		balances.Set(addr.String(), val.(int)+1)
	}
}

func decBalance(addr address) {
	val, exists := balances.Get(addr.String())
	if !exists {
		return
	}
	n := val.(int) - 1
	if n <= 0 {
		balances.Remove(addr.String())
	} else {
		balances.Set(addr.String(), n)
	}
}

func truncAddr(addr address) string {
	s := addr.String()
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

func truncStr(s string, maxLen int) string {
	if len(s) > maxLen {
		return s[:maxLen-3] + "..."
	}
	return s
}

// ── Owner Index Management ──────────────────────────────────

func addToOwnerIndex(addr address, tokenID string) {
	key := addr.String()
	val, exists := ownerIndex.Get(key)
	if !exists {
		ownerIndex.Set(key, tokenID)
	} else {
		ownerIndex.Set(key, val.(string)+","+tokenID)
	}
}

func containsChar(s string, ch rune) bool {
	for _, c := range s {
		if c == ch {
			return true
		}
	}
	return false
}

func removeFromOwnerIndex(addr address, tokenID string) {
	key := addr.String()
	val, exists := ownerIndex.Get(key)
	if !exists {
		return
	}
	ids := strings.Split(val.(string), ",")
	var remaining []string
	for _, id := range ids {
		if id != tokenID {
			remaining = append(remaining, id)
		}
	}
	if len(remaining) == 0 {
		ownerIndex.Remove(key)
	} else {
		ownerIndex.Set(key, strings.Join(remaining, ","))
	}
}

// Package tokenfactory — Samouraï Coop Token Factory
//
// A curated GRC20 token factory with on-chain platform fees, event emission,
// input validation, and faucet rate limiting.
//
// Forked from gno.land/r/demo/defi/grc20factory with improvements.
// Uses the standard gno.land/p/demo/tokens/grc20 package and registers
// tokens with gno.land/r/demo/defi/grc20reg for full ecosystem compatibility.
//
// Improvements over upstream:
//   - On-chain 2.5% platform fee on Mint and initial supply
//   - chain.Emit events for all state-changing operations
//   - Symbol validation (1-10 uppercase alphanumeric)
//   - Faucet rate limiting (~24h cooldown per address)
//   - Optional token metadata (description, website, IPFS logo)
//
// All original function signatures are preserved for 100% API compatibility.
package tokenfactory_v2

import (
	"chain"
	"chain/runtime"

	"chain/runtime/unsafe"
	"gno.land/p/demo/tokens/grc20"
	"gno.land/p/nt/avl/v0"
	p "gno.land/p/nt/avl/v0/pager"
	"gno.land/p/nt/avl/v0/rotree"
	"gno.land/p/nt/mux/v0"
	"gno.land/p/nt/ownable/v0"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/r/demo/defi/grc20reg"
)

// ── Fee Configuration ────────────────────────────────────────

// Platform fee: 2.5% (25/1000). Applied to Mint and initial supply.
// Fee goes to Samouraï Coop multisig for development & maintenance.
var (
	feeRate      int64   = 25 // 25/1000 = 2.5%
	feeRecipient address = "g1pavqfezrge9kgkrkrahqm982yhw5j45v0zw27v"
)

// ── State ────────────────────────────────────────────────────

var (
	instances        avl.Tree // symbol → *instance
	pager            = p.NewPager(rotree.Wrap(&instances, nil), 20, false)
	faucetCooldowns  avl.Tree // "SYMBOL:addr" → int64 (block height)
	tokenMetas       avl.Tree // symbol → *TokenMeta
)

// Faucet cooldown: ~24h at ~2min blocks = 720 blocks.
const faucetCooldownBlocks int64 = 720

type instance struct {
	token  *grc20.Token
	ledger *grc20.PrivateLedger
	admin  *ownable.Ownable
	faucet int64 // per-request amount. disabled if 0.
}

// TokenMeta holds optional metadata for a token.
type TokenMeta struct {
	Description string
	Website     string
	LogoIPFS    string // "ipfs://Qm..."
}

// ── Event Constants ──────────────────────────────────────────

const (
	EventTokenCreated = "TokenCreated"
	EventFaucetClaim  = "FaucetClaim"
	EventMetaUpdated  = "MetaUpdated"
)

// ── Token Creation ───────────────────────────────────────────

// New creates a new GRC20 token with the caller as admin.
// If initialMint > 0, a 2.5% platform fee is applied.
func New(cur realm, name, symbol string, decimals int, initialMint, faucet int64) {
	caller := unsafe.PreviousRealm().Address()
	NewWithAdmin(cur, name, symbol, decimals, initialMint, faucet, caller)
}

// NewWithAdmin creates a new GRC20 token with a specified admin address.
// If initialMint > 0, a 2.5% platform fee is applied.
func NewWithAdmin(cur realm, name, symbol string, decimals int, initialMint, faucet int64, admin address) {
	// ── Validation ──
	validateSymbol(symbol)
	validateName(name)
	validateDecimals(decimals)

	exists := instances.Has(symbol)
	if exists {
		panic("token already exists")
	}

	token, ledger := grc20.NewToken(0, cur, name, symbol, decimals)

	if initialMint > 0 {
		fee := applyFee(ledger, admin, initialMint)
		chain.Emit(
			grc20.MintEvent,
			"symbol", symbol,
			"to", string(admin),
			"amount", ufmt.Sprintf("%d", initialMint),
			"fee", ufmt.Sprintf("%d", fee),
		)
	}

	inst := instance{
		token:  token,
		ledger: ledger,
		admin:  ownable.NewWithAddress(admin),
		faucet: faucet,
	}
	instances.Set(symbol, &inst)

	// Register with ecosystem registry for GnoSwap/Gnoscan discoverability
	grc20reg.Register(cross(cur), token, symbol)

	chain.Emit(
		EventTokenCreated,
		"symbol", symbol,
		"name", name,
		"decimals", ufmt.Sprintf("%d", decimals),
		"initialMint", ufmt.Sprintf("%d", initialMint),
		"admin", string(admin),
		"faucet", ufmt.Sprintf("%d", faucet),
	)
}

// ── Read-Only Accessors ──────────────────────────────────────

// Bank returns the standard *grc20.Token for ecosystem interop.
func Bank(symbol string) *grc20.Token {
	inst := mustGetInstance(symbol)
	return inst.token
}

func TotalSupply(symbol string) int64 {
	inst := mustGetInstance(symbol)
	return inst.token.ReadonlyTeller().TotalSupply()
}

func HasAddr(symbol string, owner address) bool {
	inst := mustGetInstance(symbol)
	return inst.token.HasAddr(owner)
}

func BalanceOf(symbol string, owner address) int64 {
	inst := mustGetInstance(symbol)
	return inst.token.ReadonlyTeller().BalanceOf(owner)
}

func Allowance(symbol string, owner, spender address) int64 {
	inst := mustGetInstance(symbol)
	return inst.token.ReadonlyTeller().Allowance(owner, spender)
}

// GetFeeConfig returns the current fee rate (per-mille) and recipient address.
func GetFeeConfig() (int64, address) {
	return feeRate, feeRecipient
}

// GetTokenMeta returns the metadata for a token, or nil if not set.
func GetTokenMeta(symbol string) *TokenMeta {
	v, exists := tokenMetas.Get(symbol)
	if !exists {
		return nil
	}
	return v.(*TokenMeta)
}

// ── State-Changing Operations ────────────────────────────────

func Transfer(cur realm, symbol string, to address, amount int64) {
	inst := mustGetInstance(symbol)
	caller := unsafe.PreviousRealm().Address()
	teller := inst.ledger.ImpersonateTeller(caller)
	checkErr(teller.Transfer(0, cur, to, amount))

	chain.Emit(
		grc20.TransferEvent,
		"symbol", symbol,
		"from", string(caller),
		"to", string(to),
		"amount", ufmt.Sprintf("%d", amount),
	)
}

func Approve(cur realm, symbol string, spender address, amount int64) {
	inst := mustGetInstance(symbol)
	caller := unsafe.PreviousRealm().Address()
	teller := inst.ledger.ImpersonateTeller(caller)
	checkErr(teller.Approve(0, cur, spender, amount))

	chain.Emit(
		grc20.ApprovalEvent,
		"symbol", symbol,
		"owner", string(caller),
		"spender", string(spender),
		"amount", ufmt.Sprintf("%d", amount),
	)
}

func TransferFrom(cur realm, symbol string, from, to address, amount int64) {
	inst := mustGetInstance(symbol)
	caller := unsafe.PreviousRealm().Address()
	teller := inst.ledger.ImpersonateTeller(caller)
	checkErr(teller.TransferFrom(0, cur, from, to, amount))

	chain.Emit(
		grc20.TransferEvent,
		"symbol", symbol,
		"from", string(from),
		"to", string(to),
		"amount", ufmt.Sprintf("%d", amount),
		"spender", string(caller),
	)
}

// Mint creates new tokens. Admin only. 2.5% platform fee applied.
func Mint(cur realm, symbol string, to address, amount int64) {
	inst := mustGetInstance(symbol)
	inst.admin.AssertOwnedBy(cur.Previous().Address())

	fee := applyFee(inst.ledger, to, amount)

	chain.Emit(
		grc20.MintEvent,
		"symbol", symbol,
		"to", string(to),
		"amount", ufmt.Sprintf("%d", amount),
		"fee", ufmt.Sprintf("%d", fee),
	)
}

// Burn destroys tokens. Admin only.
func Burn(cur realm, symbol string, from address, amount int64) {
	inst := mustGetInstance(symbol)
	inst.admin.AssertOwnedBy(cur.Previous().Address())
	checkErr(inst.ledger.Burn(from, amount))

	chain.Emit(
		grc20.BurnEvent,
		"symbol", symbol,
		"from", string(from),
		"amount", ufmt.Sprintf("%d", amount),
	)
}

// Faucet mints free tokens if enabled. Rate-limited to ~1 claim per 24h per address.
func Faucet(cur realm, symbol string) {
	inst := mustGetInstance(symbol)
	if inst.faucet == 0 {
		panic("faucet disabled for this token")
	}

	caller := unsafe.PreviousRealm().Address()

	// Rate limiting: per-address cooldown
	key := symbol + ":" + string(caller)
	if v, exists := faucetCooldowns.Get(key); exists {
		lastBlock := v.(int64)
		if runtime.ChainHeight()-lastBlock < faucetCooldownBlocks {
			panic("faucet: cooldown active (try again in ~24h)")
		}
	}

	checkErr(inst.ledger.Mint(caller, inst.faucet))
	faucetCooldowns.Set(key, runtime.ChainHeight())

	chain.Emit(
		EventFaucetClaim,
		"symbol", symbol,
		"to", string(caller),
		"amount", ufmt.Sprintf("%d", inst.faucet),
		"block", ufmt.Sprintf("%d", runtime.ChainHeight()),
	)
}

// ── Admin Functions ──────────────────────────────────────────

func DropInstanceOwnership(cur realm, symbol string) {
	inst := mustGetInstance(symbol)
	checkErr(inst.admin.DropOwnership(0, cur))
}

func TransferInstanceOwnership(cur realm, symbol string, newOwner address) {
	inst := mustGetInstance(symbol)
	checkErr(inst.admin.TransferOwnership(0, cur, newOwner))
}

// SetTokenMeta sets optional metadata for a token. Admin only.
// Lengths: description ≤ 280, website ≤ 128, logo ≤ 100 chars.
func SetTokenMeta(cur realm, symbol, description, website, logo string) {
	inst := mustGetInstance(symbol)
	inst.admin.AssertOwnedBy(cur.Previous().Address())

	if len(description) > 280 {
		panic("description too long (max 280 chars)")
	}
	if len(website) > 128 {
		panic("website too long (max 128 chars)")
	}
	if len(logo) > 100 {
		panic("logo URI too long (max 100 chars)")
	}

	tokenMetas.Set(symbol, &TokenMeta{
		Description: description,
		Website:     website,
		LogoIPFS:    logo,
	})

	chain.Emit(
		EventMetaUpdated,
		"symbol", symbol,
	)
}

// ── Pagination ───────────────────────────────────────────────

func ListTokens(pageNumber, pageSize int) []*grc20.Token {
	page := pager.GetPageWithSize(pageNumber, pageSize)

	tokens := make([]*grc20.Token, len(page.Items))
	for i := range page.Items {
		tokens[i] = page.Items[i].Value.(*instance).token
	}

	return tokens
}

// ── Render ───────────────────────────────────────────────────

func Render(path string) string {
	router := mux.NewRouter()
	router.HandleFunc("", renderHome)
	router.HandleFunc("{symbol}", renderToken)
	router.HandleFunc("{symbol}/balance/{address}", renderBalance)
	return router.Render(path)
}

func renderHome(res *mux.ResponseWriter, req *mux.Request) {
	out := ufmt.Sprintf("# Samcrew Token Factory (%d tokens)\n\n", instances.Size())
	out += ufmt.Sprintf("*Platform fee: %d.%d%% → `%s`*\n\n", feeRate/10, feeRate%10, string(feeRecipient))

	page := pager.MustGetPageByPath(req.RawPath)

	for _, item := range page.Items {
		token := item.Value.(*instance).token
		out += "- " + ufmt.Sprintf(
			"[%s ($%s)](/r/samcrew/tokenfactory_v2:%s)",
			token.GetName(), token.GetSymbol(), token.GetSymbol(),
		) + "\n"
	}
	out += "\n"
	out += page.Picker(req.Path)

	res.Write(out)
}

func renderToken(res *mux.ResponseWriter, req *mux.Request) {
	symbol := req.GetVar("symbol")
	inst := mustGetInstance(symbol)

	out := inst.token.RenderHome()
	out += ufmt.Sprintf("- **Admin**: %s\n", string(inst.admin.Owner()))

	if inst.faucet > 0 {
		out += ufmt.Sprintf("- **Faucet**: %d per claim (~24h cooldown)\n", inst.faucet)
	}

	// Show metadata if set
	if meta := GetTokenMeta(symbol); meta != nil {
		out += "\n### Metadata\n"
		if meta.Description != "" {
			out += ufmt.Sprintf("- **Description**: %s\n", meta.Description)
		}
		if meta.Website != "" {
			out += ufmt.Sprintf("- **Website**: %s\n", meta.Website)
		}
		if meta.LogoIPFS != "" {
			out += ufmt.Sprintf("- **Logo**: %s\n", meta.LogoIPFS)
		}
	}

	res.Write(out)
}

func renderBalance(res *mux.ResponseWriter, req *mux.Request) {
	symbol := req.GetVar("symbol")
	addr := req.GetVar("address")

	inst := mustGetInstance(symbol)
	balance := inst.token.CallerTeller().BalanceOf(address(addr))

	out := ufmt.Sprintf("%s balance: %d\n", addr, balance)
	res.Write(out)
}

// ── Internal Helpers ─────────────────────────────────────────

// applyFee mints tokens to the recipient and to the fee recipient.
// Returns the fee amount.
func applyFee(ledger *grc20.PrivateLedger, to address, amount int64) int64 {
	fee := amount * feeRate / 1000
	// Mint full amount to recipient
	checkErr(ledger.Mint(to, amount))
	// Mint fee as additional supply to fee recipient
	if fee > 0 {
		checkErr(ledger.Mint(feeRecipient, fee))
	}
	return fee
}

func mustGetInstance(symbol string) *instance {
	t, exists := instances.Get(symbol)
	if !exists {
		panic("token instance does not exist")
	}
	return t.(*instance)
}

func checkErr(err error) {
	if err != nil {
		panic(err.Error())
	}
}

// ── Validation ───────────────────────────────────────────────

func validateSymbol(symbol string) {
	if len(symbol) < 1 || len(symbol) > 10 {
		panic("symbol must be 1-10 characters")
	}
	for _, c := range symbol {
		if !((c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9')) {
			panic("symbol must be uppercase alphanumeric (A-Z, 0-9)")
		}
	}
}

func validateName(name string) {
	if len(name) < 1 || len(name) > 64 {
		panic("name must be 1-64 characters")
	}
}

func validateDecimals(decimals int) {
	if decimals < 0 || decimals > 18 {
		panic("decimals must be 0-18")
	}
}

package memba_feedback_v2

// memba_dao_channels — Social feed realm for MembaDAO.
//
// Provides Discord-like channels with threads, replies, and moderation.
// The Render() output MUST match the regex patterns in parser.ts (frontend).
//
// Render() contract (from parser.ts):
//
//   Home — Render(""):
//     # BoardName
//     description
//     ## Channels
//     - [#name](:_channel/name) 📢 (N threads)
//
//   Channel — Render("channelName"):
//     # #channelName
//     ### [Title](:channel/id)
//     by g1addr... | N replies | block H
//
//   Thread — Render("channel/id"):
//     # Title
//     body
//     ---
//     *Posted by g1addr at block H*
//     ## Replies
//     **g1addr...** (block H)
//     reply body
//     ---
//
//   ACL — Render("__acl/channel"):
//     read:role1,role2
//     write:role1,role2,role3
//     type:text
//
// Security:
//   - All write operations require membership (AddMember by owner)
//   - PostThread/PostReply check caller's roles against channel WriteRoles
//   - CreateChannel/RemoveThread restricted to owner only
//   - FlagThread requires membership (prevents sybil flagging by non-members)
//   - EditThread/DeleteThread require membership + original author check
//
// Moderation: flag → threshold (3) → auto-hide → DAO vote → remove

import (
	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
)

// ── Constants ────────────────────────────────────────────────

const (
	MaxPostLen        = 5000
	MaxTitleLen       = 200
	MaxChannels       = 20
	MaxThreadsPerChan = 500
	FlagThreshold     = 3 // flags before auto-hide

	// AAA-1 B1 — render-DoS bounds for replies (mirrors MaxThreadsPerChan).
	// renderThread must never iterate the monotonic reply counter (post+delete
	// reply spam would inflate it without bound → unbounded render scan →
	// thread permanently unrenderable past maxGasQuery). The live-reply index
	// (replyLive/replyLiveIDs) caps the live set, and renderThread paginates a
	// fixed window over it, so render cost is bounded regardless of churn.
	MaxRepliesPerThread = 500 // live (non-deleted) replies per thread
	ReplyPageSize       = 50  // replies rendered per page
)

// ── Types ────────────────────────────────────────────────────

type ChannelType string

const (
	ChannelText          ChannelType = "text"
	ChannelAnnouncements ChannelType = "announcements"
	ChannelReadonly      ChannelType = "readonly"
)

type Channel struct {
	Name        string
	Description string
	Type        ChannelType
	Archived    bool
	ReadRoles   []string // roles that can read
	WriteRoles  []string // roles that can write
}

type Thread struct {
	ID        uint64
	Channel   string
	Title     string
	Body      string
	Author    address
	BlockH    int64
	Edited    bool
	EditedAt  int64
	Deleted   bool
	FlagCount int
	Hidden    bool
}

type Reply struct {
	ID       uint64
	ThreadID uint64
	Channel  string
	Body     string
	Author   address
	BlockH   int64
	Edited   bool
}

// ── State ────────────────────────────────────────────────────

var (
	channels      *avl.Tree // name -> *Channel
	threads       *avl.Tree // "channel/id" -> *Thread
	replies       *avl.Tree // "channel/threadId/replyId" -> *Reply
	threadCount   *avl.Tree // channel -> uint64 (next thread ID, monotonic)
	threadLive    *avl.Tree // channel -> uint64 (currently live (non-deleted) threads)
	threadLiveIDs *avl.Tree // channel -> []uint64 (live thread IDs, ascending) — bounds renderChannel
	replyCount    *avl.Tree // "channel/threadId" -> uint64 (next reply ID, monotonic)
	replyLive     *avl.Tree // "channel/threadId" -> uint64 (currently live (non-deleted) replies)
	replyLiveIDs  *avl.Tree // "channel/threadId" -> []uint64 (live reply IDs, ascending) — bounds renderThread
	threadTomb    *avl.Tree // channel -> []uint64 (soft-deleted thread IDs awaiting hard-GC via SweepTombstones) — B2
	flags         *avl.Tree // "channel/threadId" -> *avl.Tree (flagger addr -> bool)
	channelOrder  []string  // ordered channel names

	// Membership: address -> comma-separated roles (e.g., "admin,dev")
	members *avl.Tree
	paused  bool
	// Owner is set at package load time via OriginCaller() — this captures the
	// deployer address (samcrew-core-test1 multisig on testnet).
	owner = unsafe.OriginCaller()
)

func init() {
	channels = avl.NewTree()
	threads = avl.NewTree()
	replies = avl.NewTree()
	threadCount = avl.NewTree()
	threadLive = avl.NewTree()
	threadLiveIDs = avl.NewTree()
	replyCount = avl.NewTree()
	replyLive = avl.NewTree()
	replyLiveIDs = avl.NewTree()
	threadTomb = avl.NewTree()
	flags = avl.NewTree()
	channelOrder = []string{}
	members = avl.NewTree()
	members.Set(owner.String(), "admin")

	// Public feedback board: anyone can post in the open channels (WriteRoles
	// "*"); the frontend reads the "general" channel. "announcements" stays
	// admin-write-only for official responses. Read is open everywhere.
	addChannel("general", "Community feedback — anyone can post", ChannelText,
		[]string{"*"}, []string{"*"})
	addChannel("feature-requests", "Propose and discuss new features", ChannelText,
		[]string{"*"}, []string{"*"})
	addChannel("bugs", "Report bugs and issues", ChannelText,
		[]string{"*"}, []string{"*"})
	addChannel("announcements", "Official Memba announcements — admin-write-only", ChannelAnnouncements,
		[]string{"*"}, []string{"admin"})
}

// ── Channel Management ───────────────────────────────────────

func addChannel(name, description string, ctype ChannelType, readRoles, writeRoles []string) {
	ch := &Channel{
		Name:        name,
		Description: description,
		Type:        ctype,
		Archived:    false,
		ReadRoles:   readRoles,
		WriteRoles:  writeRoles,
	}
	channels.Set(name, ch)
	threadCount.Set(name, uint64(0))
	threadLive.Set(name, uint64(0))
	channelOrder = append(channelOrder, name)
}

// ── Membership Management ───────────────────────────────────

// AddMember adds an address with specified roles. Only the owner can call this.
// roles is a comma-separated list (e.g., "admin,dev" or "member").
func AddMember(cur realm, addr address, roles string) {
	assertCallerIsOwner()
	if addr == "" {
		panic("address cannot be empty")
	}
	if len(roles) == 0 {
		panic("roles cannot be empty")
	}
	if !isValidRoles(roles) {
		panic("invalid roles: must be comma-separated alphanumeric only")
	}
	members.Set(addr.String(), roles)

	chain.Emit("MemberAdded",
		"address", addr.String(),
		"roles", roles,
	)
}

// RemoveMember removes an address from the membership. Only the owner can call this.
func RemoveMember(cur realm, addr address) {
	assertCallerIsOwner()
	if addr == owner {
		panic("cannot remove owner")
	}
	if _, exists := members.Get(addr.String()); !exists {
		panic("address is not a member: " + addr.String())
	}
	members.Remove(addr.String())

	chain.Emit("MemberRemoved", "address", addr.String())
}

// UpdateMemberRoles updates the roles for an existing member. Only the owner can call this.
func UpdateMemberRoles(cur realm, addr address, newRoles string) {
	assertCallerIsOwner()
	if _, exists := members.Get(addr.String()); !exists {
		panic("address is not a member: " + addr.String())
	}
	if len(newRoles) == 0 {
		panic("roles cannot be empty")
	}
	if !isValidRoles(newRoles) {
		panic("invalid roles: must be comma-separated alphanumeric only")
	}
	members.Set(addr.String(), newRoles)

	chain.Emit("MemberRolesUpdated", "address", addr.String(), "roles", newRoles)
}

// TransferOwnership transfers realm ownership to a new address. Only the current owner can call this.
// The new owner gets "admin" added to their existing roles (not overwritten).
// The old owner is demoted from "admin" to "member".
func TransferOwnership(cur realm, newOwner address) {
	assertCallerIsOwner()
	if newOwner == "" {
		panic("address cannot be empty")
	}
	if newOwner == owner {
		panic("new owner is the same as current owner")
	}
	prevOwner := owner
	// Preserve existing roles for new owner, ensure they have admin
	existingRoles := GetMemberRoles(newOwner)
	if existingRoles == "" {
		members.Set(newOwner.String(), "admin")
	} else if !hasRole(newOwner, "admin") {
		members.Set(newOwner.String(), existingRoles+",admin")
	}
	// Remove "admin" from old owner's roles, keep other roles.
	// If no roles remain, set to "member".
	oldRoles := GetMemberRoles(owner)
	var kept []string
	for _, r := range strings.Split(oldRoles, ",") {
		r = strings.TrimSpace(r)
		if r != "admin" && r != "" {
			kept = append(kept, r)
		}
	}
	if len(kept) == 0 {
		members.Set(owner.String(), "member")
	} else {
		members.Set(owner.String(), strings.Join(kept, ","))
	}
	owner = newOwner

	chain.Emit("OwnershipTransferred",
		"previousOwner", prevOwner.String(),
		"newOwner", newOwner.String(),
	)
}

// SyncMembers allows the owner to batch-sync membership from the DAO.
// addresses and rolesList are comma-separated, with roles pipe-delimited per address.
// Example: SyncMembers("g1a,g1b", "admin,dev|member")
func SyncMembers(cur realm, addresses string, rolesList string) {
	assertCallerIsOwner()
	addrs := strings.Split(addresses, ",")
	roles := strings.Split(rolesList, "|")
	if len(addrs) != len(roles) {
		panic("addresses and roles count mismatch")
	}
	synced := 0
	for i, addr := range addrs {
		addr = strings.TrimSpace(addr)
		if addr == "" {
			continue
		}
		role := strings.TrimSpace(roles[i])
		if !isValidRoles(role) {
			panic("invalid roles in entry " + strconv.Itoa(i))
		}
		members.Set(addr, role)
		synced++
	}

	chain.Emit("MembersSynced", "count", strconv.Itoa(synced))
}

// PurgeNonMembers removes all members not in the provided comma-separated list.
// The owner is never purged.
func PurgeNonMembers(cur realm, keepAddresses string) {
	assertCallerIsOwner()
	keep := make(map[string]bool)
	for _, addr := range strings.Split(keepAddresses, ",") {
		keep[strings.TrimSpace(addr)] = true
	}
	keep[owner.String()] = true // owner is never purged
	var toRemove []string
	members.Iterate("", "", func(key string, _ interface{}) bool {
		if !keep[key] {
			toRemove = append(toRemove, key)
		}
		return false
	})
	for _, addr := range toRemove {
		members.Remove(addr)
	}

	chain.Emit("MembersPurged", "count", strconv.Itoa(len(toRemove)))
}

// IsMember returns whether an address is a member.
func IsMember(addr address) bool {
	_, exists := members.Get(addr.String())
	return exists
}

// GetMemberRoles returns the roles for a member (comma-separated) or empty string.
func GetMemberRoles(addr address) string {
	val, exists := members.Get(addr.String())
	if !exists {
		return ""
	}
	return val.(string)
}

// GetOwner returns the current realm owner address.
func GetOwner() address {
	return owner
}

// ── Emergency Pause ────────────────────────────────────────
//
// Pause policy (AAA-1 B3 — one policy, enforced everywhere):
//   While paused, every member-facing content write is blocked via
//   assertNotPaused() — PostThread, PostReply, EditThread, DeleteThread/Reply,
//   FlagThread, RemoveThread/Reply, and SweepTombstones.
//
//   Owner-only governance (AddMember/RemoveMember/UpdateMemberRoles/SyncMembers/
//   PurgeNonMembers/TransferOwnership/CreateChannel) is intentionally NOT gated:
//   pause halts user activity during an incident, but the owner must stay able to
//   fix membership/ownership while paused. This realm holds no funds, so there is
//   no value-exit exemption to carve out.

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

func PauseRealm(cur realm) {
	assertCallerIsOwner()
	paused = true
	chain.Emit("RealmPaused", "by", owner.String())
}

func UnpauseRealm(cur realm) {
	assertCallerIsOwner()
	paused = false
	chain.Emit("RealmUnpaused", "by", owner.String())
}

func IsPaused() bool { return paused }

// ── Channel Management ───────────────────────────────────────

// CreateChannel adds a new channel. Only the owner (admin) can create channels.
func CreateChannel(cur realm, name, description string, ctype string) {
	assertCallerIsOwner()

	if len(channelOrder) >= MaxChannels {
		panic(ufmt.Sprintf("max channels reached: %d", MaxChannels))
	}
	if _, exists := channels.Get(name); exists {
		panic("channel already exists: " + name)
	}
	if !isValidChannelName(name) {
		panic("invalid channel name: must be 1-50 lowercase alphanumeric characters or hyphens, no leading underscore")
	}

	ct := ChannelText
	switch ctype {
	case "announcements":
		ct = ChannelAnnouncements
	case "readonly":
		ct = ChannelReadonly
	}

	addChannel(name, description, ct,
		[]string{"admin", "dev", "ops", "member"},
		[]string{"admin", "dev", "ops", "member"})

	chain.Emit("ChannelCreated", "name", name, "type", string(ct))
}

// ── Post Management ─────────────────────────────────────────

// PostThread creates a new thread in a channel.
// Caller must be a member with a role listed in the channel's WriteRoles.
func PostThread(cur realm, channel, title, body string) uint64 {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	// Validate membership and channel write access
	ch := getChannel(channel)
	assertCallerHasWriteAccess(caller, ch)
	if ch.Archived {
		panic("channel is archived")
	}
	// Cap on LIVE (non-deleted) threads so deleted threads free up slots.
	if getLiveThreadCount(channel) >= MaxThreadsPerChan {
		panic(ufmt.Sprintf("channel live thread limit reached: %d — delete old threads to make room", MaxThreadsPerChan))
	}
	if len(title) == 0 || len(title) > MaxTitleLen {
		panic(ufmt.Sprintf("title must be 1-%d characters", MaxTitleLen))
	}
	if len(body) > MaxPostLen {
		panic(ufmt.Sprintf("body too long: %d/%d chars", len(body), MaxPostLen))
	}

	// Get next ID
	nextID := getThreadCount(channel)
	key := channel + "/" + strconv.FormatUint(nextID, 10)

	t := &Thread{
		ID:      nextID,
		Channel: channel,
		Title:   title,
		Body:    body,
		Author:  caller,
		BlockH:  runtime.ChainHeight(),
	}
	threads.Set(key, t)
	threadCount.Set(channel, nextID+1)
	threadLive.Set(channel, getLiveThreadCount(channel)+1)
	addLiveThreadID(channel, nextID)
	replyCount.Set(key, uint64(0))

	chain.Emit("ThreadPosted",
		"channel", channel,
		"threadId", strconv.FormatUint(nextID, 10),
		"author", caller.String(),
	)

	return nextID
}

// PostReply adds a reply to a thread.
// Caller must be a member with a role listed in the channel's WriteRoles.
func PostReply(cur realm, channel string, threadID uint64, body string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	// Validate membership and channel write access
	ch := getChannel(channel)
	assertCallerHasWriteAccess(caller, ch)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	tval, texists := threads.Get(threadKey)
	if !texists {
		panic("thread not found")
	}
	thread := tval.(*Thread)
	if thread.Deleted {
		panic("cannot reply to a deleted thread")
	}
	if thread.Hidden {
		panic("cannot reply to a hidden thread")
	}

	if len(body) == 0 || len(body) > MaxPostLen {
		panic(ufmt.Sprintf("reply must be 1-%d characters", MaxPostLen))
	}

	// B1: bound the LIVE reply set so renderThread stays under the gas budget.
	// Deleting replies frees slots (mirrors MaxThreadsPerChan / getLiveThreadCount).
	if getLiveReplyCount(threadKey) >= MaxRepliesPerThread {
		panic(ufmt.Sprintf("thread reply limit reached: %d — older replies must be removed", MaxRepliesPerThread))
	}

	nextReplyID := getReplyCount(threadKey)
	replyKey := threadKey + "/" + strconv.FormatUint(nextReplyID, 10)

	r := &Reply{
		ID:       nextReplyID,
		ThreadID: threadID,
		Channel:  channel,
		Body:     body,
		Author:   caller,
		BlockH:   runtime.ChainHeight(),
	}
	replies.Set(replyKey, r)
	replyCount.Set(threadKey, nextReplyID+1)
	// Track the live reply so renderThread iterates only live IDs (bounded set),
	// never the monotonic counter.
	addLiveReplyID(threadKey, nextReplyID)
	replyLive.Set(threadKey, getLiveReplyCount(threadKey)+1)

	chain.Emit("ReplyPosted",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"replyId", strconv.FormatUint(nextReplyID, 10),
		"author", caller.String(),
	)
}

// dropReply hard-removes a reply: deletes the node (storage reclaimed — B2),
// drops it from the live index, and decrements the live count. Shared by
// DeleteReply and RemoveReply. renderThread only walks the live index, so a
// removed reply is never looked up — no tombstone is needed.
func dropReply(threadKey, replyKey string, replyID uint64) {
	replies.Remove(replyKey)
	removeLiveReplyID(threadKey, replyID)
	if live := getLiveReplyCount(threadKey); live > 0 {
		replyLive.Set(threadKey, live-1)
	}
}

// DeleteReply lets the reply's author delete it. Caller must be a member and the
// original author. The reply node is hard-removed (B2 state-shrink) and a slot is
// freed under MaxRepliesPerThread (B1).
func DeleteReply(cur realm, channel string, threadID, replyID uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	replyKey := threadKey + "/" + strconv.FormatUint(replyID, 10)
	rval, exists := replies.Get(replyKey)
	if !exists {
		panic("reply not found")
	}
	if rval.(*Reply).Author != caller {
		panic("only the author can delete")
	}

	dropReply(threadKey, replyKey, replyID)

	chain.Emit("ReplyDeleted",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"replyId", strconv.FormatUint(replyID, 10),
		"author", caller.String(),
	)
}

// RemoveReply permanently removes a reply (moderation — admin role only). Hard-
// removes the node like DeleteReply, bounding renderThread (B1) + reclaiming
// storage (B2).
func RemoveReply(cur realm, channel string, threadID, replyID uint64) {
	assertCallerIsAdminRole()
	caller := unsafe.PreviousRealm().Address()

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	replyKey := threadKey + "/" + strconv.FormatUint(replyID, 10)
	if _, exists := replies.Get(replyKey); !exists {
		panic("reply not found")
	}

	dropReply(threadKey, replyKey, replyID)

	chain.Emit("ReplyRemoved",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"replyId", strconv.FormatUint(replyID, 10),
		"admin", caller.String(),
	)
}

// EditThread allows the original author to edit their thread. Caller must be a member.
func EditThread(cur realm, channel string, threadID uint64, newBody string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if t.Author != caller {
		panic("only the author can edit")
	}
	if t.Deleted {
		panic("cannot edit a deleted thread")
	}
	if t.Hidden {
		panic("cannot edit a hidden thread")
	}
	if len(newBody) > MaxPostLen {
		panic("body too long")
	}

	t.Body = newBody
	t.Edited = true
	t.EditedAt = runtime.ChainHeight()
	threads.Set(threadKey, t)

	chain.Emit("ThreadEdited",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"author", caller.String(),
	)
}

// DeleteThread soft-deletes a thread (marks as deleted). Caller must be a member and the original author.
func DeleteThread(cur realm, channel string, threadID uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if t.Author != caller {
		panic("only the author can delete")
	}
	if t.Deleted {
		panic("thread already deleted")
	}

	t.Deleted = true
	t.Title = "[Deleted]"
	t.Body = ""
	threads.Set(threadKey, t)
	// Free a slot for new threads
	live := getLiveThreadCount(channel)
	if live > 0 {
		threadLive.Set(channel, live-1)
	}
	removeLiveThreadID(channel, threadID)
	enqueueThreadTomb(channel, threadID) // B2: queue for hard-GC via SweepTombstones

	chain.Emit("ThreadDeleted",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"author", caller.String(),
	)
}

// ── Moderation ──────────────────────────────────────────────

// FlagThread flags a thread for moderation review.
// After FlagThreshold flags, the thread is auto-hidden.
// Caller must be a member (any role) to flag content.
func FlagThread(cur realm, channel string, threadID uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)
	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)

	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if t.Deleted {
		panic("cannot flag a deleted thread")
	}
	if t.Hidden {
		panic("thread is already hidden")
	}

	// Track unique flaggers
	var flagTree *avl.Tree
	if fval, fexists := flags.Get(threadKey); fexists {
		flagTree = fval.(*avl.Tree)
	} else {
		flagTree = avl.NewTree()
	}

	if _, already := flagTree.Get(caller.String()); already {
		panic("already flagged")
	}
	flagTree.Set(caller.String(), true)
	flags.Set(threadKey, flagTree)

	// Update thread flag count and auto-hide.
	// Dynamic threshold: max(FlagThreshold, 5% of members), scales with DAO size.
	t.FlagCount = flagTree.Size()
	dynamicThreshold := FlagThreshold
	fivePct := members.Size() / 20
	if fivePct > dynamicThreshold {
		dynamicThreshold = fivePct
	}
	wasHidden := t.Hidden
	if t.FlagCount >= dynamicThreshold {
		t.Hidden = true
	}
	threads.Set(threadKey, t)

	chain.Emit("ThreadFlagged",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"flagger", caller.String(),
		"flagCount", strconv.Itoa(t.FlagCount),
	)
	if !wasHidden && t.Hidden {
		chain.Emit("ThreadAutoHidden",
			"channel", channel,
			"threadId", strconv.FormatUint(threadID, 10),
		)
	}
}

// UnhideThread allows the owner or an admin to clear flags and un-hide a thread.
func UnhideThread(cur realm, channel string, threadID uint64) {
	assertCallerIsAdminRole()
	caller := unsafe.PreviousRealm().Address()
	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)

	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}
	t := val.(*Thread)
	t.Hidden = false
	t.FlagCount = 0
	threads.Set(threadKey, t)
	// Clear flag tree
	flags.Remove(threadKey)

	chain.Emit("ThreadUnhidden",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"admin", caller.String(),
	)
}

// RemoveThread permanently removes a thread (moderation action — admin role only).
func RemoveThread(cur realm, channel string, threadID uint64) {
	assertCallerIsAdminRole()
	caller := unsafe.PreviousRealm().Address()
	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if !t.Deleted {
		live := getLiveThreadCount(channel)
		if live > 0 {
			threadLive.Set(channel, live-1)
		}
		removeLiveThreadID(channel, threadID)
		enqueueThreadTomb(channel, threadID) // B2: queue for hard-GC (skip if already tombstoned)
	}
	t.Deleted = true
	t.Hidden = true
	t.Title = "[Removed by moderation]"
	t.Body = ""
	threads.Set(threadKey, t)

	chain.Emit("ThreadRemoved",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"admin", caller.String(),
	)
}

// SweepTombstones hard-removes up to `limit` soft-deleted threads in a channel
// (and all of their remaining reply state), reclaiming AVL storage so that
// post+delete spam can no longer accrete permanent state (B2).
//
// Permissionless GC by design: anyone may call it. Released storage deposits go
// to the calling tx per the chain's deposit policy (an explicit caller bounty);
// on restricted-denom chains (e.g. test12/test13 `restricted_denoms=["ugnot"]`)
// they route to the StorageFeeCollector instead — so this is a state-shrink/
// hygiene primitive, not a user-refund path (see plan B2 / Q11).
//
// Bounded + idempotent: each soft-deleted thread holds at most
// MaxRepliesPerThread reply nodes, so keep `limit` small (1–5) to stay well
// within block gas; re-running drains the next batch and stops at 0.
// Returns the number of threads swept.
func SweepTombstones(cur realm, channel string, limit int) int {
	assertNotPaused()
	if limit <= 0 {
		return 0
	}

	tomb := getThreadTomb(channel)
	n := limit
	if n > len(tomb) {
		n = len(tomb)
	}

	for i := 0; i < n; i++ {
		threadKey := channel + "/" + strconv.FormatUint(tomb[i], 10)
		// Collect-then-remove: read the live reply IDs (a stored slice) and remove
		// each reply node — we never iterate the tree we mutate (AVL footgun).
		for _, rid := range getLiveReplyIDs(threadKey) {
			replies.Remove(threadKey + "/" + strconv.FormatUint(rid, 10))
		}
		replyLiveIDs.Remove(threadKey)
		replyLive.Remove(threadKey)
		replyCount.Remove(threadKey)
		flags.Remove(threadKey)
		threads.Remove(threadKey)
	}

	// Drop the processed prefix; copy the tail into a fresh slice to avoid aliasing.
	remaining := append([]uint64{}, tomb[n:]...)
	if len(remaining) == 0 {
		threadTomb.Remove(channel)
	} else {
		threadTomb.Set(channel, remaining)
	}

	if n > 0 {
		chain.Emit("TombstonesSwept",
			"channel", channel,
			"count", strconv.Itoa(n),
		)
	}
	return n
}

// GetTombstoneCount returns how many soft-deleted threads in a channel are still
// awaiting hard-GC (read-only; lets ops/indexers decide when to call SweepTombstones).
func GetTombstoneCount(channel string) int {
	return len(getThreadTomb(channel))
}

// ── Render ───────────────────────────────────────────────────
// CRITICAL: Output format MUST match parser.ts regex patterns.

func Render(path string) string {
	if path == "" {
		return renderHome()
	}
	if strings.HasPrefix(path, "__acl/") {
		channelName := strings.TrimPrefix(path, "__acl/")
		return renderACL(channelName)
	}
	if strings.HasPrefix(path, "__member/") {
		addr := strings.TrimPrefix(path, "__member/")
		roles := GetMemberRoles(address(addr))
		if roles == "" {
			return "not found"
		}
		return "roles:" + roles
	}
	if strings.HasPrefix(path, "_channel/") {
		channelName := strings.TrimPrefix(path, "_channel/")
		return renderChannel(channelName)
	}

	// Check for "channel/threadId" pattern, optionally with a "?page=N" suffix
	// for reply pagination (B1).
	parts := strings.SplitN(path, "/", 2)
	if len(parts) == 2 {
		idPart := parts[1]
		page := uint64(0)
		if qi := strings.IndexByte(idPart, '?'); qi >= 0 {
			page = parsePageQuery(idPart[qi+1:])
			idPart = idPart[:qi]
		}
		threadID, err := strconv.ParseUint(idPart, 10, 64)
		if err == nil {
			return renderThread(parts[0], threadID, page)
		}
	}

	// Try as channel name directly
	if _, exists := channels.Get(path); exists {
		return renderChannel(path)
	}

	return "# 404\nPage not found: " + path
}

// renderHome produces the board home page.
// Format: parser.ts parseBoardHome() expects:
//   - [#name](:_channel/name) 📢 (N threads)
func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# MembaDAO Channels\n\n")
	sb.WriteString("Community discussion channels for the Memba ecosystem.\n\n")
	sb.WriteString(ufmt.Sprintf("**Owner:** %s | **Members:** %d\n\n", owner, members.Size()))
	sb.WriteString("## Channels\n\n")

	for _, name := range channelOrder {
		val, exists := channels.Get(name)
		if !exists {
			continue
		}
		ch := val.(*Channel)
		if ch.Archived {
			continue
		}

		count := getThreadCount(name)
		typeIcon := ""
		switch ch.Type {
		case ChannelAnnouncements:
			typeIcon = " 📢"
		case ChannelReadonly:
			typeIcon = " 🔒"
		}

		sb.WriteString(ufmt.Sprintf("- [#%s](:_channel/%s)%s (%d threads)\n",
			name, name, typeIcon, count))
	}

	return sb.String()
}

// renderChannel produces a channel's thread list.
// Format: parser.ts parseThreadList() expects:
//   ### [Title](:channel/id)
//   by g1addr... | N replies | block H
func renderChannel(channelName string) string {
	if _, exists := channels.Get(channelName); !exists {
		return "# 404\nChannel not found: " + channelName
	}

	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# #%s\n\n", channelName))

	// Iterate the LIVE thread-ID index (bounded by getLiveThreadCount), newest
	// first. Never loop over the monotonic threadCount — a post+delete spam
	// loop inflates it without bound (gas DoS); deleted IDs are not in this index.
	ids := getLiveThreadIDs(channelName)
	if len(ids) == 0 {
		sb.WriteString("*No threads yet. Be the first to post!*\n")
		return sb.String()
	}

	for i := len(ids) - 1; i >= 0; i-- {
		threadKey := channelName + "/" + strconv.FormatUint(ids[i], 10)
		val, exists := threads.Get(threadKey)
		if !exists {
			continue
		}
		t := val.(*Thread)
		if t.Hidden || t.Deleted {
			continue
		}

		// Count live (non-deleted) replies — matches what renderThread shows.
		rCount := getLiveReplyCount(threadKey)
		authorStr := truncAddr(t.Author)

		sb.WriteString(ufmt.Sprintf("### [%s](:%s/%d)\n", sanitizeForRender(t.Title), channelName, t.ID))
		sb.WriteString(ufmt.Sprintf("by %s | %d replies | block %d\n\n", authorStr, rCount, t.BlockH))
	}

	return sb.String()
}

// renderThread produces a single thread with replies.
// Format: parser.ts parseThreadDetail() expects:
//   # Title
//   body
//   ---
//   *Posted by g1addr at block H* *(edited at block M)*
//   ## Replies
//   **g1addr...** (block H) *(edited)*
//   reply body
//   ---
func renderThread(channelName string, threadID, page uint64) string {
	threadKey := channelName + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		return "# 404\nThread not found"
	}

	t := val.(*Thread)

	// Suppress content for hidden (flag-auto-hidden or admin-hidden) and
	// soft-deleted threads. renderChannel omits these from the list, but the
	// direct path Render("channel/id") must not leak the original title/body.
	if t.Hidden || t.Deleted {
		return "# Thread unavailable\n\n*This thread has been hidden or removed.*\n"
	}

	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# %s\n\n", sanitizeForRender(t.Title)))
	sb.WriteString(sanitizeForRender(t.Body) + "\n\n")
	sb.WriteString("---\n\n")
	sb.WriteString(ufmt.Sprintf("*Posted by %s at block %d*", string(t.Author), t.BlockH))
	if t.Edited {
		sb.WriteString(ufmt.Sprintf(" *(edited at block %d)*", t.EditedAt))
	}
	sb.WriteString("\n\n")

	// B1: render only LIVE replies (bounded by MaxRepliesPerThread), paginated to
	// a fixed window so render cost is O(ReplyPageSize) regardless of total churn.
	// Never iterate the monotonic replyCount — that is the render-DoS surface.
	liveIDs := getLiveReplyIDs(threadKey) // ascending (oldest→newest), <= MaxRepliesPerThread
	total := uint64(len(liveIDs))
	if total > 0 {
		totalPages := (total + ReplyPageSize - 1) / ReplyPageSize
		// page 1 = oldest window … totalPages = newest. Default (0) and any
		// out-of-range value snap to the newest page (most-recent replies).
		if page == 0 || page > totalPages {
			page = totalPages
		}
		start := (page - 1) * ReplyPageSize
		end := start + ReplyPageSize
		if end > total {
			end = total
		}

		sb.WriteString("## Replies\n\n")
		if totalPages > 1 {
			sb.WriteString(ufmt.Sprintf(
				"*Showing %d–%d of %d • page %d/%d — older: `?page=%d`, newer: `?page=%d`*\n\n",
				start+1, end, total, page, totalPages, pageClamp(page-1, totalPages), pageClamp(page+1, totalPages)))
		}

		for i := start; i < end; i++ {
			replyKey := threadKey + "/" + strconv.FormatUint(liveIDs[i], 10)
			rval, rexists := replies.Get(replyKey)
			if !rexists {
				continue // live index never points at a removed reply, but stay safe
			}
			r := rval.(*Reply)
			authorStr := truncAddr(r.Author)
			editStr := ""
			if r.Edited {
				editStr = " *(edited)*"
			}
			sb.WriteString(ufmt.Sprintf("**%s** (block %d)%s\n\n", authorStr, r.BlockH, editStr))
			sb.WriteString(sanitizeForRender(r.Body) + "\n\n")
			sb.WriteString("---\n\n")
		}
	}

	return sb.String()
}

// parsePageQuery extracts the page number from a "?page=N" query string (also
// tolerates extra &-separated params). Returns 0 (= default/newest) on absence
// or parse error.
func parsePageQuery(q string) uint64 {
	for _, kv := range strings.Split(q, "&") {
		if strings.HasPrefix(kv, "page=") {
			if n, err := strconv.ParseUint(strings.TrimPrefix(kv, "page="), 10, 64); err == nil {
				return n
			}
		}
	}
	return 0
}

// pageClamp keeps a page link within [1, totalPages].
func pageClamp(p, totalPages uint64) uint64 {
	if p < 1 {
		return 1
	}
	if p > totalPages {
		return totalPages
	}
	return p
}

// renderACL produces the ACL response for a channel.
// Format: parser.ts parseACL() expects:
//   read:role1,role2
//   write:role1,role2,role3
//   type:text
func renderACL(channelName string) string {
	val, exists := channels.Get(channelName)
	if !exists {
		return "not found"
	}
	ch := val.(*Channel)

	var sb strings.Builder
	sb.WriteString("read:" + strings.Join(ch.ReadRoles, ",") + "\n")
	sb.WriteString("write:" + strings.Join(ch.WriteRoles, ",") + "\n")
	sb.WriteString("type:" + string(ch.Type) + "\n")

	return sb.String()
}

// ── Helpers ──────────────────────────────────────────────────

func getChannel(name string) *Channel {
	val, exists := channels.Get(name)
	if !exists {
		panic("channel not found: " + name)
	}
	return val.(*Channel)
}

func getThreadCount(channel string) uint64 {
	val, exists := threadCount.Get(channel)
	if !exists {
		return 0
	}
	return val.(uint64)
}

// getLiveThreadCount returns the number of non-deleted threads in a channel.
// Unlike getThreadCount (monotonic ID counter), this decreases when threads
// are deleted, so deleted threads free up slots under MaxThreadsPerChan.
func getLiveThreadCount(channel string) uint64 {
	val, exists := threadLive.Get(channel)
	if !exists {
		return 0
	}
	return val.(uint64)
}

// ── Live thread-ID index ─────────────────────────────────────
// renderChannel must iterate only live (non-deleted) thread IDs, never the
// monotonic threadCount: a member can post+delete in a loop to inflate
// threadCount without bound (the live cap only limits live threads), turning
// renderChannel into an unbounded O(threadCount) scan (gas DoS). This index
// stays bounded by getLiveThreadCount (<= MaxThreadsPerChan).

func getLiveThreadIDs(channel string) []uint64 {
	if val, exists := threadLiveIDs.Get(channel); exists {
		return val.([]uint64)
	}
	return nil
}

func addLiveThreadID(channel string, id uint64) {
	threadLiveIDs.Set(channel, append(getLiveThreadIDs(channel), id))
}

func removeLiveThreadID(channel string, id uint64) {
	ids := getLiveThreadIDs(channel)
	for i, x := range ids {
		if x == id {
			threadLiveIDs.Set(channel, append(ids[:i], ids[i+1:]...))
			return
		}
	}
}

// ── Live reply-ID index ──────────────────────────────────────
// Same rationale as the thread index, one level down: renderThread must iterate
// only live reply IDs (bounded by MaxRepliesPerThread), never the monotonic
// replyCount, or a member can post+delete replies in a loop to make a thread
// unrenderable. Keyed by "channel/threadId".

func getLiveReplyCount(threadKey string) uint64 {
	if val, exists := replyLive.Get(threadKey); exists {
		return val.(uint64)
	}
	return 0
}

func getLiveReplyIDs(threadKey string) []uint64 {
	if val, exists := replyLiveIDs.Get(threadKey); exists {
		return val.([]uint64)
	}
	return nil
}

func addLiveReplyID(threadKey string, id uint64) {
	replyLiveIDs.Set(threadKey, append(getLiveReplyIDs(threadKey), id))
}

func removeLiveReplyID(threadKey string, id uint64) {
	ids := getLiveReplyIDs(threadKey)
	for i, x := range ids {
		if x == id {
			replyLiveIDs.Set(threadKey, append(ids[:i], ids[i+1:]...))
			return
		}
	}
}

// ── Thread tombstone queue (B2 hard-GC) ──────────────────────
// Soft-deleted thread IDs awaiting permanent removal by SweepTombstones. A queue
// (not a scan of the threads tree) keeps the sweep O(limit) — it never walks the
// unbounded set of past tombstones.

func getThreadTomb(channel string) []uint64 {
	if val, exists := threadTomb.Get(channel); exists {
		return val.([]uint64)
	}
	return nil
}

func enqueueThreadTomb(channel string, id uint64) {
	threadTomb.Set(channel, append(getThreadTomb(channel), id))
}

func getReplyCount(threadKey string) uint64 {
	val, exists := replyCount.Get(threadKey)
	if !exists {
		return 0
	}
	return val.(uint64)
}

func truncAddr(addr address) string {
	s := string(addr)
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

// isValidRoles validates a comma-separated role list contains only safe characters.
// Allowed: a-z, A-Z, 0-9, hyphen, comma. No spaces, no markdown chars, no null bytes.
func isValidRoles(s string) bool {
	if len(s) > 200 {
		return false
	}
	for _, c := range s {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '-' || c == ',') {
			return false
		}
	}
	return true
}

// sanitizeForRender strips markdown-sensitive characters to prevent injection.
func sanitizeForRender(s string) string {
	var out strings.Builder
	for _, c := range s {
		switch c {
		case '[', ']', '(', ')', '#', '*', '`', '!', '<', '>', '|', '\\', '_', '~', '\n', '\r', '\t':
			continue
		default:
			out.WriteRune(c)
		}
	}
	return out.String()
}

// ── ACL Enforcement ─────────────────────────────────────────

func assertCallerIsOwner() {
	caller := unsafe.PreviousRealm().Address()
	if caller != owner {
		panic("unauthorized: caller " + caller.String() + " is not the owner")
	}
}

func assertCallerIsMember(caller address) {
	if _, exists := members.Get(caller.String()); !exists {
		panic("unauthorized: caller " + caller.String() + " is not a member")
	}
}

// assertCallerHasWriteAccess checks that the caller is a member AND has at least
// one role that matches the channel's WriteRoles.
func assertCallerHasWriteAccess(caller address, ch *Channel) {
	// Public channels (WriteRoles contains "*") accept posts from any caller —
	// this is a public feedback board. Non-public channels keep role-based control
	// (e.g. announcements stays admin-only). Mainnet should add rate-limiting.
	for _, wr := range ch.WriteRoles {
		if wr == "*" {
			return
		}
	}
	rolesStr, exists := members.Get(caller.String())
	if !exists {
		panic("unauthorized: caller " + caller.String() + " is not a member")
	}

	callerRoles := strings.Split(rolesStr.(string), ",")
	for _, cr := range callerRoles {
		cr = strings.TrimSpace(cr)
		for _, wr := range ch.WriteRoles {
			if cr == wr {
				return // Access granted
			}
		}
	}

	panic("unauthorized: caller " + caller.String() + " lacks write access to channel " + ch.Name)
}

func hasRole(caller address, role string) bool {
	rolesStr, exists := members.Get(caller.String())
	if !exists {
		return false
	}
	callerRoles := strings.Split(rolesStr.(string), ",")
	for _, cr := range callerRoles {
		if strings.TrimSpace(cr) == role {
			return true
		}
	}
	return false
}

// assertCallerIsAdminRole checks that the caller is a member with the "admin" role.
// Used for moderation actions (RemoveThread, UnhideThread) so any admin can moderate,
// not just the single owner.
func assertCallerIsAdminRole() {
	caller := unsafe.PreviousRealm().Address()
	if !hasRole(caller, "admin") {
		panic("unauthorized: caller " + caller.String() + " does not have admin role")
	}
}

// isValidChannelName validates that a channel name contains only
// lowercase alphanumeric characters and hyphens, and does not start with underscore.
func isValidChannelName(name string) bool {
	if len(name) == 0 || len(name) > 50 {
		return false
	}
	if name[0] == '_' {
		return false // Prevent collision with __acl/, __member/ paths
	}
	for _, c := range name {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-') {
			return false
		}
	}
	return true
}

package memba_nft_v2

import (
	"chain"
	"chain/runtime/unsafe"
	"math/overflow"
