// Admin operations — multisig-gated controls.
//
// assertAdmin() is the single authorization gate; caller = unsafe.PreviousRealm().Address().
// AdminDelist is pause-exempt (moderation can always remove content).
// SetFeeRecipient changes where platform fees flow (default = AdminAddress).

import (
	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/samcrew/grc721"
)

func assertAdmin() {
	if unsafe.PreviousRealm().Address() != address(AdminAddress) {
		panic("admin only")
	}
}

// Pause halts new trade operations (ListNFT, BuyNFT, MakeOffer, AcceptOffer).
// Value-exit paths (DelistNFT, CancelOffer, ClaimExpiredOffer) remain available.
func Pause(cur realm) {
	assertAdmin()
	paused = true
	chain.Emit("MarketPaused", "by", unsafe.PreviousRealm().Address().String())
}

// Unpause resumes normal operations.
func Unpause(cur realm) {
	assertAdmin()
	paused = false
	chain.Emit("MarketUnpaused", "by", unsafe.PreviousRealm().Address().String())
}

// AdminDelist force-removes any listing. Pause-exempt (moderation).
func AdminDelist(cur realm, collectionID string, tid grc721.TokenID) {
	assertAdmin()
	key := listingKey(collectionID, string(tid))
	if _, exists := listings.Get(key); !exists {
		panic("not listed: " + key)
	}
	listings.Remove(key)
	removeFromOrder(key)
	chain.Emit("AdminDelisted",
		"collection", collectionID,
		"tokenId", string(tid),
		"admin", unsafe.PreviousRealm().Address().String(),
	)
}

// SetFeeRecipient updates the address that receives platform fees.
func SetFeeRecipient(cur realm, addr address) {
	assertAdmin()
	feeRecipient = addr
	chain.Emit("FeeRecipientChanged", "newRecipient", addr.String())
}

package memba_nft_market_v2

// NFT Marketplace v2 — General-purpose NFT trading for the Memba ecosystem on test13.
//
// Supports the memba_nft_v2 collection realm via cross-realm MarketTransfer.
// Platform fee: 2.5% to AdminAddress multisig.
// Royalty: clamped to MaxRoyaltyBPS (10%), returned by nft.RoyaltyInfo().
//
// Security:
//   - CEI (Checks-Effects-Interactions) in all payment flows
//   - IsUserCall guard on BuyNFT and MakeOffer (payment-bearing fns)
//   - Offer escrow with OfferTimeoutBlk safety valve (ClaimExpiredOffer)
//   - MinOfferLifetimeBlk prevents instant-cancel front-run
//   - Only original lister can delist (pause-exempt exit)
//   - Self-buy prevention
//   - Defense-in-depth royalty clamp even when collection enforces its own cap

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/samcrew/grc721"
	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"

	nft "gno.land/r/samcrew/memba_nft_v2"
)

// ── Types ─────────────────────────────────────────────────────────────────────

// Listing represents a fixed-price sale order.
type Listing struct {
	CollectionID string
	TokenID      string
	Seller       address
	Price        int64
	CreatedBlk   int64
}

// Sale records a completed transaction for the salesLog.
type Sale struct {
	CollectionID string
	TokenID      string
	Seller       address
	Buyer        address
	Price        int64
	Fee          int64
	Royalty      int64
	Blk          int64
}

// ── State ─────────────────────────────────────────────────────────────────────

var (
	listings     *avl.Tree // listingKey -> *Listing
	offers       *avl.Tree // offerKey   -> *Offer
	salesLog     *avl.Tree // itoa(saleId) -> *Sale
	listingOrder []string  // insertion-ordered listing keys (pagination)
	nextSaleId   int64
	totalVolume  int64
	paused       bool
	feeRecipient = address(AdminAddress)
)

func init() {
	listings = avl.NewTree()
	offers = avl.NewTree()
	salesLog = avl.NewTree()
}

// ── Key helpers ───────────────────────────────────────────────────────────────

func listingKey(collectionID, tokenID string) string {
	return collectionID + ":" + tokenID
}

func offerKey(collectionID, tokenID string, buyer address) string {
	return collectionID + ":" + tokenID + ":" + string(buyer)
}

func itoa(n int64) string { return strconv.FormatInt(n, 10) }

// sumUgnot returns the total ugnot in a coin set.
func sumUgnot(coins chain.Coins) int64 {
	for _, c := range coins {
		if c.Denom == "ugnot" {
			return c.Amount
		}
	}
	return 0
}

// removeFromOrder removes a key from the ordered listing slice (O(n)).
func removeFromOrder(key string) {
	for i, k := range listingOrder {
		if k == key {
			listingOrder = append(listingOrder[:i], listingOrder[i+1:]...)
			return
		}
	}
}

// countListingsBySeller counts a seller's open listings. Bounded by MaxListings.
func countListingsBySeller(seller address) int {
	n := 0
	listings.Iterate("", "", func(_ string, v interface{}) bool {
		if v.(*Listing).Seller == seller {
			n++
		}
		return false
	})
	return n
}

// countOffersByBuyer counts a buyer's open offers. Bounded by MaxOffers.
func countOffersByBuyer(buyer address) int {
	n := 0
	offers.Iterate("", "", func(_ string, v interface{}) bool {
		if v.(*Offer).Buyer == buyer {
			n++
		}
		return false
	})
	return n
}

// ── List / Delist ─────────────────────────────────────────────────────────────

// ListNFT lists an NFT for fixed-price sale.
// PREREQUISITE: Owner must call nft.SetApprovalForAll(marketplace, true) first so
// MarketTransfer can execute on behalf of the seller.
func ListNFT(cur realm, collectionID string, tid grc721.TokenID, price int64) {
	if paused {
		panic("market paused")
	}
	seller := unsafe.PreviousRealm().Address()

	if price < MinPrice {
		panic(ufmt.Sprintf("price must be >= %d ugnot", MinPrice))
	}
	if price > MaxPrice {
		panic(ufmt.Sprintf("price must be <= %d ugnot", MaxPrice))
	}
	if listings.Size() >= MaxListings {
		panic("marketplace listing limit reached")
	}
	if countListingsBySeller(seller) >= MaxListingsPerAddr {
		panic("seller listing limit reached")
	}

	key := listingKey(collectionID, string(tid))
	if _, exists := listings.Get(key); exists {
		panic("already listed: " + key)
	}

	// Effects
	listings.Set(key, &Listing{
		CollectionID: collectionID,
		TokenID:      string(tid),
		Seller:       seller,
		Price:        price,
		CreatedBlk:   runtime.ChainHeight(),
	})
	listingOrder = append(listingOrder, key)

	chain.Emit("NFTListed",
		"collection", collectionID,
		"tokenId", string(tid),
		"seller", seller.String(),
		"price", itoa(price),
	)
}

// DelistNFT removes a listing. Only the original lister can delist. Pause-exempt
// (value-exit: unwinds the seller's position).
func DelistNFT(cur realm, collectionID string, tid grc721.TokenID) {
	caller := unsafe.PreviousRealm().Address()
	key := listingKey(collectionID, string(tid))

	val, exists := listings.Get(key)
	if !exists {
		panic("not listed: " + key)
	}
	l := val.(*Listing)
	if l.Seller != caller {
		panic("only seller can delist")
	}

	// Effects
	listings.Remove(key)
	removeFromOrder(key)

	chain.Emit("NFTDelisted",
		"collection", collectionID,
		"tokenId", string(tid),
		"seller", caller.String(),
	)
}

// ── Buy ───────────────────────────────────────────────────────────────────────

// BuyNFT purchases a listed NFT atomically (CEI order).
//
// CEI:
//   Checks  — paused / IsUserCall / listed / self-buy / payment amount
//   Effects — remove listing from state, record sale, update volume
//   Interactions — cross-call MarketTransfer, then banker payouts (seller last)
func BuyNFT(cur realm, collectionID string, tid grc721.TokenID) {
	if paused {
		panic("market paused")
	}
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	key := listingKey(collectionID, string(tid))
	v, ok := listings.Get(key)
	if !ok {
		panic("listing not found")
	}
	l := v.(*Listing)
	buyer := unsafe.PreviousRealm().Address()
	if buyer == l.Seller {
		panic("cannot buy own listing")
	}
	if sumUgnot(unsafe.OriginSend()) != l.Price {
		panic("incorrect payment")
	}

	royRecip, royAmt := nft.RoyaltyInfo(collectionID, tid, l.Price)
	fee, royalty, sellerAmt := splitProceeds(l.Price, royAmt)

	// Effects (before cross-call + sends)
	seller := l.Seller
	price := l.Price
	listings.Remove(key)
	removeFromOrder(key)
	recordSale(collectionID, string(tid), seller, buyer, price, fee, royalty)
	totalVolume += price

	// Interactions
	nft.MarketTransfer(cross(cur), collectionID, seller, buyer, tid)
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	self := unsafe.CurrentRealm().Address()
	if royalty > 0 {
		bnk.SendCoins(self, royRecip, chain.Coins{chain.NewCoin("ugnot", royalty)})
	}
	if fee > 0 {
		bnk.SendCoins(self, feeRecipient, chain.Coins{chain.NewCoin("ugnot", fee)})
	}
	bnk.SendCoins(self, seller, chain.Coins{chain.NewCoin("ugnot", sellerAmt)}) // seller last

	chain.Emit("PurchaseConfirmed",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", buyer.String(),
		"seller", seller.String(),
		"price", itoa(price),
		"fee", itoa(fee),
		"royalty", itoa(royalty),
		"royaltyRecipient", royRecip.String(),
		"sellerAmount", itoa(sellerAmt),
	)
}

// ── splitProceeds ─────────────────────────────────────────────────────────────

// splitProceeds computes the three-way split of a sale price.
// royaltyAmount comes pre-computed from nft.RoyaltyInfo (already the actual
// amount, not bps). We clamp it defensively against MaxRoyaltyBPS.
func splitProceeds(price, royaltyAmount int64) (fee, royalty, seller int64) {
	if price < MinPrice {
		panic("price below minimum")
	}
	if price > MaxPrice {
		panic("price above maximum")
	}
	fee = price * FeeBPS / 10000
	royalty = royaltyAmount
	if royalty < 0 {
		royalty = 0
	}
	maxRoy := price * MaxRoyaltyBPS / 10000
	if royalty > maxRoy {
		royalty = maxRoy // defense-in-depth clamp
	}
	if fee+royalty >= price {
		panic("fee plus royalty exceeds price")
	}
	seller = price - fee - royalty
	if seller <= 0 {
		panic("seller amount not positive")
	}
	return
}

// ── recordSale ────────────────────────────────────────────────────────────────

func recordSale(collectionID, tokenID string, seller, buyer address, price, fee, royalty int64) {
	nextSaleId++
	salesLog.Set(itoa(nextSaleId), &Sale{
		CollectionID: collectionID,
		TokenID:      tokenID,
		Seller:       seller,
		Buyer:        buyer,
		Price:        price,
		Fee:          fee,
		Royalty:      royalty,
		Blk:          runtime.ChainHeight(),
	})
}

// ── IsPaused ─────────────────────────────────────────────────────────────────

func IsPaused() bool { return paused }

// ── truncAddr / truncPath (render helpers) ────────────────────────────────────

func truncAddr(addr address) string {
	s := string(addr)
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

func truncPath(path string) string {
	parts := strings.Split(path, "/")
	if len(parts) > 2 {
		return parts[len(parts)-1]
	}
	return path
}

package memba_nft_market_v2

// Offer management — escrowed buyer offers on any listed NFT.
//
// Lifecycle:
//   MakeOffer      — buyer sends ugnot, funds held in escrow by this realm
//   CancelOffer    — buyer cancels (pause-exempt; must wait MinOfferLifetimeBlk)
//   AcceptOffer    — listing seller accepts; settles atomically via MarketTransfer + payouts
//   ClaimExpiredOffer — anyone claims refund after OfferTimeoutBlk (safety valve)
//
// Pause policy: MakeOffer + AcceptOffer are blocked while paused (new escrow /
// new settlement). CancelOffer + ClaimExpiredOffer are pause-exempt (value-exit).

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/samcrew/grc721"
	"gno.land/p/nt/ufmt/v0"

	nft "gno.land/r/samcrew/memba_nft_v2"
)

// Offer is an escrowed buy proposal on a specific (collection, token) pair.
type Offer struct {
	CollectionID string
	TokenID      string
	Buyer        address
	Amount       int64 // ugnot held in escrow
	CreatedBlk   int64
}

// MakeOffer places an offer with escrowed funds.
// Caller must send ugnot with the transaction; funds are held by this realm.
func MakeOffer(cur realm, collectionID string, tid grc721.TokenID) {
	if paused {
		panic("market paused")
	}
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	buyer := unsafe.PreviousRealm().Address()
	amt := sumUgnot(unsafe.OriginSend())
	if amt < MinPrice {
		panic("offer below minimum")
	}

	if offers.Size() >= MaxOffers {
		panic("offer limit reached")
	}
	if countOffersByBuyer(buyer) >= MaxOffersPerAddr {
		panic("buyer offer limit reached")
	}

	key := offerKey(collectionID, string(tid), buyer)
	if _, exists := offers.Get(key); exists {
		panic("offer already exists, cancel first")
	}

	// Effects
	offers.Set(key, &Offer{
		CollectionID: collectionID,
		TokenID:      string(tid),
		Buyer:        buyer,
		Amount:       amt,
		CreatedBlk:   runtime.ChainHeight(),
	})

	chain.Emit("OfferMade",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", buyer.String(),
		"amount", itoa(amt),
	)
}

// CancelOffer allows the offerer to reclaim escrowed funds.
// Pause-exempt (value-exit). Must wait MinOfferLifetimeBlk to prevent front-run.
func CancelOffer(cur realm, collectionID string, tid grc721.TokenID) {
	caller := unsafe.PreviousRealm().Address()
	key := offerKey(collectionID, string(tid), caller)

	val, exists := offers.Get(key)
	if !exists {
		panic("offer not found")
	}
	o := val.(*Offer)

	age := runtime.ChainHeight() - o.CreatedBlk
	if age < MinOfferLifetimeBlk {
		panic(ufmt.Sprintf("offer too new to cancel: %d blocks remaining", MinOfferLifetimeBlk-age))
	}

	// Effects
	amt := o.Amount
	offers.Remove(key)

	// Interactions
	refund(cur, caller, amt)

	chain.Emit("OfferCancelled",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", caller.String(),
		"amount", itoa(amt),
	)
}

// ClaimExpiredOffer returns escrowed funds when an offer has exceeded OfferTimeoutBlk.
// Pause-exempt (safety-valve: prevents permanent escrow lock).
// Anyone can call on behalf of the buyer, but funds always go to the buyer.
func ClaimExpiredOffer(cur realm, collectionID string, tid grc721.TokenID, buyer address) {
	key := offerKey(collectionID, string(tid), buyer)

	val, exists := offers.Get(key)
	if !exists {
		panic("offer not found")
	}
	o := val.(*Offer)

	age := runtime.ChainHeight() - o.CreatedBlk
	if age < OfferTimeoutBlk {
		panic(ufmt.Sprintf("offer not yet expired: %d blocks remaining", OfferTimeoutBlk-age))
	}

	// Effects
	amt := o.Amount
	offers.Remove(key)

	// Interactions
	refund(cur, buyer, amt)

	chain.Emit("OfferExpiredClaimed",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", buyer.String(),
		"amount", itoa(amt),
	)
}

// AcceptOffer allows the listing seller to accept a buyer's escrowed offer.
// Requires an active listing (seller must have listed first).
// Settles atomically: cross-call MarketTransfer then pay royalty, fee, seller (seller last).
func AcceptOffer(cur realm, collectionID string, tid grc721.TokenID, buyer address) {
	if paused {
		panic("market paused")
	}
	seller := unsafe.PreviousRealm().Address()

	listKey := listingKey(collectionID, string(tid))
	lv, listed := listings.Get(listKey)
	if !listed {
		panic("AcceptOffer requires an active listing — list the NFT first")
	}
	l := lv.(*Listing)
	if l.Seller != seller {
		panic("only the listing seller can accept offers")
	}

	if buyer == seller {
		panic("cannot accept own offer")
	}

	oKey := offerKey(collectionID, string(tid), buyer)
	ov, exists := offers.Get(oKey)
	if !exists {
		panic("offer not found")
	}
	o := ov.(*Offer)

	royRecip, royAmt := nft.RoyaltyInfo(collectionID, tid, o.Amount)
	fee, royalty, sellerAmt := splitProceeds(o.Amount, royAmt)

	// Effects (before cross-call + sends)
	amt := o.Amount
	offers.Remove(oKey)
	listings.Remove(listKey)
	removeFromOrder(listKey)
	recordSale(collectionID, string(tid), seller, buyer, amt, fee, royalty)
	totalVolume += amt

	// Interactions
	nft.MarketTransfer(cross(cur), collectionID, seller, buyer, tid)
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	self := unsafe.CurrentRealm().Address()
	if royalty > 0 {
		bnk.SendCoins(self, royRecip, chain.Coins{chain.NewCoin("ugnot", royalty)})
	}
	if fee > 0 {
		bnk.SendCoins(self, feeRecipient, chain.Coins{chain.NewCoin("ugnot", fee)})
	}
	bnk.SendCoins(self, seller, chain.Coins{chain.NewCoin("ugnot", sellerAmt)}) // seller last

	chain.Emit("OfferAccepted",
		"collection", collectionID,
		"tokenId", string(tid),
		"seller", seller.String(),
		"buyer", buyer.String(),
		"amount", itoa(amt),
		"fee", itoa(fee),
		"royalty", itoa(royalty),
		"sellerAmount", itoa(sellerAmt),
	)
	chain.Emit("TokenSold",
		"collection", collectionID,
		"tokenId", string(tid),
		"seller", seller.String(),
		"buyer", buyer.String(),
		"price", itoa(amt),
	)
}

// refund sends escrowed ugnot back to a recipient from this realm's balance.
func refund(cur realm, to address, amt int64) {
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	bnk.SendCoins(unsafe.CurrentRealm().Address(), to, chain.Coins{chain.NewCoin("ugnot", amt)})
}

package memba_nft_market_v2

// Render — public read-only views.
//
// Routes:
//   ""       — home: active listings count + volume
//   "stats"  — platform fee, totals
//   "sales"  — recent sales (up to 20)
//   *        — 404

import (
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

func Render(path string) string {
	switch path {
	case "":
		return renderHome()
	case "stats":
		return renderStats()
	case "sales":
		return renderSales()
	default:
		return "# 404\nNot found: " + path
	}
}

func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# NFT Marketplace\n\n")
	sb.WriteString(ufmt.Sprintf("**Active Listings:** %d\n", listings.Size()))
	volGnot := ufmt.Sprintf("%d.%06d", totalVolume/1_000_000, totalVolume%1_000_000)
	sb.WriteString(ufmt.Sprintf("**Total Volume:** %s GNOT\n", volGnot))

	if len(listingOrder) == 0 {
		sb.WriteString("\n*No active listings.*\n")
		return sb.String()
	}

	const homePageCap = 50

	sb.WriteString("\n| # | Collection | Token | Price | Seller |\n")
	sb.WriteString("|---|-----------|-------|-------|--------|\n")
	shown := 0
	for i, key := range listingOrder {
		if shown >= homePageCap {
			break
		}
		val, exists := listings.Get(key)
		if !exists {
			continue
		}
		l := val.(*Listing)
		priceGnot := ufmt.Sprintf("%d.%06d", l.Price/1_000_000, l.Price%1_000_000)
		sb.WriteString(ufmt.Sprintf("| %d | %s | %s | %s GNOT | %s |\n",
			i+1, truncPath(l.CollectionID), l.TokenID, priceGnot, truncAddr(l.Seller)))
		shown++
	}
	if len(listingOrder) > homePageCap {
		sb.WriteString(ufmt.Sprintf("\n*… showing first %d of %d listings.*\n", homePageCap, len(listingOrder)))
	}
	return sb.String()
}

func renderStats() string {
	var sb strings.Builder
	sb.WriteString("# Marketplace Stats\n\n")
	sb.WriteString(ufmt.Sprintf("**Active Listings:** %d\n", listings.Size()))
	sb.WriteString(ufmt.Sprintf("**Total Sales:** %d\n", salesLog.Size()))
	volGnot := ufmt.Sprintf("%d.%06d", totalVolume/1_000_000, totalVolume%1_000_000)
	sb.WriteString(ufmt.Sprintf("**Total Volume:** %s GNOT\n", volGnot))
	sb.WriteString(ufmt.Sprintf("**Active Offers:** %d\n", offers.Size()))
	sb.WriteString("**Platform Fee:** 2.50%\n")
	sb.WriteString(ufmt.Sprintf("**Max Royalty:** %d%%\n", MaxRoyaltyBPS/100))
	return sb.String()
}

func renderSales() string {
	var sb strings.Builder
	sb.WriteString("# Recent Sales\n\n")
	if salesLog.Size() == 0 {
		sb.WriteString("*No sales yet.*\n")
		return sb.String()
	}

	sb.WriteString("| Sale | Collection | Token | Price | Seller | Buyer |\n")
	sb.WriteString("|------|-----------|-------|-------|--------|-------|\n")

	count := 0
	salesLog.ReverseIterate("", "", func(key string, val interface{}) bool {
		s := val.(*Sale)
		priceGnot := ufmt.Sprintf("%d.%06d", s.Price/1_000_000, s.Price%1_000_000)
		sb.WriteString(ufmt.Sprintf("| %s | %s | %s | %s GNOT | %s | %s |\n",
			key, truncPath(s.CollectionID), s.TokenID, priceGnot,
			truncAddr(s.Seller), truncAddr(s.Buyer)))
		count++
		return count >= 20
	})
	return sb.String()
}

// Package memba_collections is the canonical, multi-collection NFT registry
// for the Memba open marketplace + launchpad. It is the ONE irreversible
// realm: it holds every launched collection's internal grc721 ledger, so it
// can never be redeployed without orphaning NFTs. The full frozen ABI lives
// in Memba/docs/planning/CANONICAL_COLLECTION_ABI.md (v3, build-ready).
//
// Design anchors:
//   - grc721 Reader/Writer split: the realm holds the concrete *metadataNFT
//     behind the unexported membaNFT interface; writes derive the caller from
//     unsafe.PreviousRealm().Address() inside crossing wrappers.
//   - Royalty is enforced IN-REALM as BPS (never grc721's percent/100 path).
//   - MarketTransfer is the ONLY token-movement path; only registered engines
//     may call it (the moat). There is no public TransferFrom/gift/airdrop.
//   - Both ugnot and GRC20 mint payments transit the realm via a per-denom
//     proceeds ledger; CEI ordering is frozen (effects before interactions).
package memba_collections

import (
	"chain"
	"chain/runtime/unsafe"
	"strconv"

	"gno.land/p/samcrew/grc721"
	"gno.land/p/nt/avl/v0"
)

// ── Tunable bounds (constants — permanent) ──────────────────────────────────
const (
	MaxRoyaltyBPS        = 1000                 // 10% hard ceiling (defensive)
	DefaultRoyaltyBPS    = 500                  // 5% applied when creator passes RoyaltySentinel
	MinCreatorRoyaltyBPS = 0                    // creators may opt fully out
	MinMintPrice         = 1000                 // 0.001 GNOT — anti-truncation
	MaxPriceUgnot        = 1_000_000_000_000_000 // 1e15
	MaxPrimaryFeeBPS     = 2000                 // 20% — bounds primaryFeeBPS so MaxPriceUgnot*bps < MaxInt64
	RoyaltySentinel      = -1                   // CreateCollection royaltyBPS sentinel → DefaultRoyaltyBPS
	MaxSlugLen           = 64
)

// AdminAddress is the Samouraï 2-of-2 multisig (samcrew-core-test1). Seeds
// platformAdmin, pauser, and feeRecipient at genesis; all three are mutable.
const AdminAddress = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0"

// ── Platform state (mutable; platformAdmin → memba_dao executor on mainnet) ─
var (
	platformAdmin        address
	pendingPlatformAdmin address
	pauser               address // SEPARATE fast-pause role (multisig)
	feeRecipient         address // createFee + primaryFee sink (DAO treasury)
	createFee            int64   // anti-spam launch fee
	primaryFeeBPS        int64   // platform cut on primary mints (default 0; <= MaxPrimaryFeeBPS)
	maxCreatorRoyaltyBPS int64   // creator-set royalty cap (default 750)
	allowedDenoms        = avl.NewTree() // denom key -> bool (curated mint tokens; seed "ugnot")
	registeredMarkets    = avl.NewTree() // marketAddr string -> bool (DRAIN KEY)
	paused               bool            // global pause
	collections          = avl.NewTree() // collectionID "creator/slug" -> *collection
)

func init() {
	platformAdmin = address(AdminAddress)
	pauser = address(AdminAddress)
	feeRecipient = address(AdminAddress)
	createFee = 1_000_000 // 1 GNOT
	primaryFeeBPS = 0
	maxCreatorRoyaltyBPS = 750
	allowedDenoms.Set("ugnot", true)
}

// membaNFT is the subset of *grc721.metadataNFT the realm calls (verified
// against grc721_metadata.gno). NO royalty methods — royalty is in-realm.
// Burn takes no caller (wrapper own-checks); SetTokenURI returns (bool, error).
type membaNFT interface {
	Name() string
	Symbol() string
	TokenCount() int64
	BalanceOf(owner address) (int64, error)
	OwnerOf(tid grc721.TokenID) (address, error)
	GetApproved(tid grc721.TokenID) (address, error)
	IsApprovedForAll(owner, operator address) bool
	TokenURI(tid grc721.TokenID) (string, error)
	Mint(to address, tid grc721.TokenID) error
	Approve(caller, to address, tid grc721.TokenID) error
	SetApprovalForAll(caller, operator address, approved bool) error
	TransferFrom(caller, from, to address, tid grc721.TokenID) error
	SetTokenURI(caller address, tid grc721.TokenID, tURI grc721.TokenURI) (bool, error)
	Burn(tid grc721.TokenID) error
}

type royalty struct {
	recip address
	bps   int64
}

type collection struct {
	nft          membaNFT // *grc721.metadataNFT (internal ledger)
	creator      address  // immutable record of who launched it
	admin        address  // mutable (2-step; platformAdmin break-glass)
	pendingAdmin address
	// royalty — ALL in-realm, BPS
	royaltyRecip address
	royaltyBPS   int64
	tokenRoyalty *avl.Tree // tokenId -> royalty (per-token override; PRESENCE wins)
	// mint config
	phase              int    // 0 draft, 1 allowlist, 2 public, 3 closed
	allowlistRoot      string // hex sha256 root (tagged-hash; leaf=sha256(0x00‖addr.String()‖":"‖maxQty))
	mintPrice          int64  // [MinMintPrice, MaxPriceUgnot]
	payDenom           string // "" / "ugnot" = native; else an allowedDenoms key
	maxSupply          int64  // 0 = unlimited; gate on nextAutoTokenID (NOT TokenCount)
	maxPerWallet       int64  // 0 = unlimited (UX guard)
	mintStartBlock     int64  // 0 = open; else mint allowed only at/after this height
	mintCooldownBlocks int64  // 0 = none; per-wallet cooldown
	mintedByWallet     *avl.Tree // minter -> count
	lastMintBlock      *avl.Tree // minter -> last mint height
	nextAutoTokenID    int64     // sequential id for ALL mints; ALSO the supply counter
	mintCustody        address   // fixed-at-create creator sink for withdrawn proceeds
	proceeds           *avl.Tree // denom -> accrued creatorAmt
	meta               *avl.Tree // extensible per-collection flags (platformAdmin)
	paused             bool      // per-collection pause
	mintGuard          bool      // reentrancy guard for mint + withdraw + refund
}

// ── Helpers ─────────────────────────────────────────────────────────────────

func mustGet(id string) *collection {
	v, ok := collections.Get(id)
	if !ok {
		panic("collection not found: " + id)
	}
	return v.(*collection)
}

func caller() address { return unsafe.PreviousRealm().Address() }

func assertPlatformAdmin() {
	if caller() != platformAdmin {
		panic("platform admin only")
	}
}

func assertCollectionAdmin(c *collection) {
	if caller() != c.admin {
		panic("collection admin only")
	}
}

func assertNotPaused(c *collection) {
	if paused || c.paused {
		panic("paused")
	}
}

func itoa(n int64) string { return strconv.FormatInt(n, 10) }

// validSlug enforces the frozen charset ^[a-z0-9-]{1,64}$ (B-2). Rejecting
// '/' and ':' prevents collectionID ("creator/slug") namespace spoofing.
func validSlug(s string) bool {
	if len(s) == 0 || len(s) > MaxSlugLen {
		return false
	}
	for i := 0; i < len(s); i++ {
		c := s[i]
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-') {
			return false
		}
	}
	return true
}

// ── Launchpad: CreateCollection + 2-step collection admin transfer ──────────

// CreateCollection launches a new collection. Open + fee-gated: anyone may
// call it, paying createFee in ugnot. royaltyBPS == RoyaltySentinel(-1) uses
// DefaultRoyaltyBPS; otherwise it is clamped to [MinCreatorRoyaltyBPS,
// maxCreatorRoyaltyBPS]. name/symbol are COSMETIC only — identity is the
// derived collectionID = caller/slug.
func CreateCollection(cur realm, slug, name, symbol string, royaltyBPS int64, royaltyRecip, mintCustody address, maxSupply, maxPerWallet int64) string {
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	return createCollectionInternal(cur, caller(), unsafe.OriginSend(), slug, name, symbol, royaltyBPS, royaltyRecip, mintCustody, maxSupply, maxPerWallet)
}

// createCollectionInternal holds the full create logic with the caller and
// sent coins passed explicitly, so it is unit-testable without the IsUserCall
// guard (which is unreachable for a direct test-body cross-call).
func createCollectionInternal(cur realm, cr address, sentCoins chain.Coins, slug, name, symbol string, royaltyBPS int64, royaltyRecip, mintCustody address, maxSupply, maxPerWallet int64) string {
	if paused {
		panic("paused")
	}
	if !validSlug(slug) {
		panic("invalid slug: must match ^[a-z0-9-]{1,64}$")
	}
	id := cr.String() + "/" + slug
	if _, ok := collections.Get(id); ok {
		panic("collection exists: " + id)
	}
	// createFee gate (native ugnot). Any ugnot beyond createFee is refunded to
	// the creator — including the entire envelope when createFee==0, so a free
	// create never traps attached funds (LOW stuck-funds trap).
	sent := sumDenom(sentCoins, "ugnot")
	if createFee > 0 {
		if sent < createFee {
			panic("insufficient createFee")
		}
		sendNative(cur, feeRecipient, createFee)
	}
	if over := sent - createFee; over > 0 {
		sendNative(cur, cr, over)
	}
	// royalty resolution
	rbps := royaltyBPS
	if rbps == RoyaltySentinel {
		rbps = DefaultRoyaltyBPS
	}
	if rbps < MinCreatorRoyaltyBPS {
		rbps = MinCreatorRoyaltyBPS
	}
	if rbps > maxCreatorRoyaltyBPS {
		rbps = maxCreatorRoyaltyBPS
	}
	if mintCustody == "" {
		mintCustody = cr
	}
	if royaltyRecip == "" {
		royaltyRecip = cr
	}
	c := &collection{
		nft:             grc721.NewNFTWithMetadata(0, cur, name, symbol),
		creator:         cr,
		admin:           cr,
		royaltyRecip:    royaltyRecip,
		royaltyBPS:      rbps,
		tokenRoyalty:    avl.NewTree(),
		maxSupply:       maxSupply,
		maxPerWallet:    maxPerWallet,
		mintedByWallet:  avl.NewTree(),
		lastMintBlock:   avl.NewTree(),
		mintCustody:     mintCustody,
		proceeds:        avl.NewTree(),
		meta:            avl.NewTree(),
	}
	collections.Set(id, c)
	chain.Emit("CollectionCreated",
		"collectionID", id,
		"creator", cr.String(),
		"name", name,
		"symbol", symbol,
		"royaltyBPS", itoa(rbps),
		"royaltyRecip", royaltyRecip.String(),
		"maxSupply", itoa(maxSupply),
		"createFee", itoa(createFee),
		"block", itoa(chainHeight()),
	)
	return id
}

// SetCollectionAdmin proposes a new collection admin (step 1 of 2).
func SetCollectionAdmin(cur realm, id string, newAdmin address) {
	c := mustGet(id)
	assertCollectionAdmin(c)
	c.pendingAdmin = newAdmin
	chain.Emit("CollectionAdminTransferred", "collectionID", id, "pending", newAdmin.String())
}

// AcceptCollectionAdmin completes the transfer (step 2 of 2).
func AcceptCollectionAdmin(cur realm, id string) {
	c := mustGet(id)
	if caller() != c.pendingAdmin {
		panic("not pending admin")
	}
	c.admin = c.pendingAdmin
	c.pendingAdmin = ""
	chain.Emit("CollectionAdminAccepted", "collectionID", id, "admin", c.admin.String())
}

package memba_collections

import (
	"chain"
)

// phase constants
const (
	PhaseDraft     = 0
	PhaseAllowlist = 1
	PhasePublic    = 2
	PhaseClosed    = 3
)

// SetMintPhase sets the sale phase and (for the allowlist phase) the Merkle
// root. Admin only. Emits MintPhaseSet with the root for off-chain indexers.
func SetMintPhase(cur realm, id string, phase int, allowlistRoot string) {
	c := mustGet(id)
	assertCollectionAdmin(c)
	if phase < PhaseDraft || phase > PhaseClosed {
		panic("invalid phase")
	}
	c.phase = phase
	c.allowlistRoot = allowlistRoot
	chain.Emit("MintPhaseSet",
		"collectionID", id,
		"phase", itoa(int64(phase)),
		"allowlistRoot", allowlistRoot,
		"block", itoa(chainHeight()),
	)
}

// SetMintConfig sets the full mint configuration. Admin only. payDenom must be
// native ("" / "ugnot") or a currently-allowed denom. mintPrice (when > 0)
// must be in [MinMintPrice, MaxPriceUgnot]. maxSupply cannot be set below the
// number already minted. Emits MintConfigChanged carrying every cap (E-2).
func SetMintConfig(cur realm, id string, mintPrice int64, payDenom string, maxSupply, maxPerWallet, mintStartBlock, mintCooldownBlocks int64) {
	c := mustGet(id)
	assertCollectionAdmin(c)

	if !isNativeDenom(payDenom) {
		if _, ok := allowedDenoms.Get(payDenom); !ok {
			panic("denom not allowed: " + payDenom)
		}
	}
	if mintPrice != 0 && (mintPrice < MinMintPrice || mintPrice > MaxPriceUgnot) {
		panic("mint price out of range")
	}
	if maxSupply != 0 && maxSupply < c.nextAutoTokenID {
		panic("maxSupply below minted count")
	}
	if maxPerWallet < 0 || mintStartBlock < 0 || mintCooldownBlocks < 0 {
		panic("negative config value")
	}

	c.mintPrice = mintPrice
	c.payDenom = payDenom
	c.maxSupply = maxSupply
	c.maxPerWallet = maxPerWallet
	c.mintStartBlock = mintStartBlock
	c.mintCooldownBlocks = mintCooldownBlocks

	chain.Emit("MintConfigChanged",
		"collectionID", id,
		"mintPrice", itoa(mintPrice),
		"payDenom", payDenom,
		"maxSupply", itoa(maxSupply),
		"maxPerWallet", itoa(maxPerWallet),
		"mintStartBlock", itoa(mintStartBlock),
		"mintCooldownBlocks", itoa(mintCooldownBlocks),
		"block", itoa(chainHeight()),
	)
}

package memba_collections

import (
	"chain"
)

// ── Market registry (DRAIN KEY) ─────────────────────────────────────────────

// RegisterMarket authorizes a marketplace realm to call MarketTransfer. This
// is a drain key: platformAdmin only, event-logged.
func RegisterMarket(cur realm, market address) {
	assertPlatformAdmin()
	registeredMarkets.Set(market.String(), true)
	chain.Emit("MarketRegistered", "market", market.String())
}

func UnregisterMarket(cur realm, market address) {
	assertPlatformAdmin()
	registeredMarkets.Remove(market.String())
	chain.Emit("MarketUnregistered", "market", market.String())
}

// ── Pause ────────────────────────────────────────────────────────────────────

func assertPauserOrAdmin() {
	cr := caller()
	if cr != pauser && cr != platformAdmin {
		panic("pauser or platform admin only")
	}
}

// Pause halts the whole registry. The fast pauser role OR platformAdmin.
func Pause(cur realm) {
	assertPauserOrAdmin()
	paused = true
	chain.Emit("Paused")
}

func Unpause(cur realm) {
	assertPauserOrAdmin()
	paused = false
	chain.Emit("Unpaused")
}

// PauseCollection / UnpauseCollection pause a single collection. Collection
// admin, pauser, or platformAdmin.
func PauseCollection(cur realm, id string) {
	c := mustGet(id)
	cr := caller()
	if cr != c.admin && cr != pauser && cr != platformAdmin {
		panic("not authorized to pause collection")
	}
	c.paused = true
	chain.Emit("CollectionPaused", "collectionID", id)
}

func UnpauseCollection(cur realm, id string) {
	c := mustGet(id)
	cr := caller()
	if cr != c.admin && cr != pauser && cr != platformAdmin {
		panic("not authorized to unpause collection")
	}
	c.paused = false
	chain.Emit("CollectionUnpaused", "collectionID", id)
}

func IsPaused() bool { return paused }

// ── Platform params (each change individually event-logged, E-1) ─────────────

func SetCreateFee(cur realm, newFee int64) {
	assertPlatformAdmin()
	if newFee < 0 {
		panic("negative fee")
	}
	old := createFee
	createFee = newFee
	chain.Emit("CreateFeeSet", "old", itoa(old), "new", itoa(newFee), "block", itoa(chainHeight()))
}

func SetPrimaryFeeBPS(cur realm, bps int64) {
