	if bps < 0 || bps > MaxPrimaryFeeBPS {
		panic("primaryFeeBPS out of range")
	}
	old := primaryFeeBPS
	primaryFeeBPS = bps
	chain.Emit("PrimaryFeeBPSSet", "old", itoa(old), "new", itoa(bps), "block", itoa(chainHeight()))
