	c.meta.Set(key, value)
	chain.Emit("CollectionMetaSet", "collectionID", id, "key", key, "value", value)
}

func GetCollectionMeta(id, key string) string {
	c := mustGet(id)
	if v, ok := c.meta.Get(key); ok {
		return v.(string)
	}
	return ""
}

package memba_collections

import (
	"crypto/sha256"
	"encoding/hex"
)

// Merkle allowlist verifier (frozen, §5).
//   leaf = sha256(0x00 ‖ addr.String() ‖ ":" ‖ itoa(maxQty))   (bech32 string form, S-5)
//   node = sha256(0x01 ‖ sortedConcat(l, r))                    (domain-separated, sorted-pair)
// The sorted pair makes the proof order-independent and second-preimage safe.

func leafHash(addr address, maxQty int64) []byte {
	data := append([]byte{0x00}, []byte(addr.String()+":"+itoa(maxQty))...)
	h := sha256.Sum256(data)
	return h[:]
}

func parentHash(a, b []byte) []byte {
	var lo, hi []byte
	if compareBytes(a, b) <= 0 {
		lo, hi = a, b
	} else {
		lo, hi = b, a
	}
	data := make([]byte, 0, 1+len(lo)+len(hi))
	data = append(data, 0x01)
	data = append(data, lo...)
	data = append(data, hi...)
	h := sha256.Sum256(data)
	return h[:]
}

func compareBytes(a, b []byte) int {
	n := len(a)
	if len(b) < n {
		n = len(b)
	}
	for i := 0; i < n; i++ {
		if a[i] != b[i] {
			if a[i] < b[i] {
				return -1
			}
			return 1
		}
	}
	if len(a) < len(b) {
		return -1
	}
	if len(a) > len(b) {
		return 1
	}
	return 0
}

// verifyAllowlist reconstructs the leaf from (addr, maxQty), folds the proof,
// and checks the computed root against the hex-encoded `root`. A single-leaf
// tree (empty proof) is valid when leaf == root. An empty root rejects.
func verifyAllowlist(root string, addr address, maxQty int64, proof []string) bool {
	if root == "" {
		return false
	}
	cur := leafHash(addr, maxQty)
	for _, sibHex := range proof {
		sib, err := hex.DecodeString(sibHex)
		if err != nil {
			return false
		}
		cur = parentHash(cur, sib)
	}
	return hex.EncodeToString(cur) == root
}

package memba_collections

import (
	"chain"
	"chain/runtime/unsafe"
	"math/overflow"
	"strings"

	"gno.land/p/samcrew/grc721"
)

// ── proceeds ledger + small helpers ─────────────────────────────────────────

func walletCount(c *collection, who address) int64 {
	if v, ok := c.mintedByWallet.Get(who.String()); ok {
		return v.(int64)
	}
	return 0
}

func proceedsOf(c *collection, key string) int64 {
	if v, ok := c.proceeds.Get(key); ok {
		return v.(int64)
	}
	return 0
}

func creditProceeds(c *collection, denom string, amt int64) {
	key := denomKey(denom)
	c.proceeds.Set(key, proceedsOf(c, key)+amt)
}

func assertDenomAllowed(denom string) {
	if isNativeDenom(denom) {
		return
	}
	if _, ok := allowedDenoms.Get(denom); !ok {
		panic("denom not allowed: " + denom)
	}
}

func boolStr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

// mintChecks enforces the non-supply gating: maxPerWallet, mintStartBlock,
// per-wallet cooldown. Supply is gated inside mintToken (on nextAutoTokenID).
func mintChecks(c *collection, minter address) {
	if c.maxPerWallet > 0 && walletCount(c, minter)+1 > c.maxPerWallet {
		panic("per-wallet mint limit reached")
	}
	h := chainHeight()
	if c.mintStartBlock > 0 && h < c.mintStartBlock {
		panic("mint not started")
	}
	if c.mintCooldownBlocks > 0 {
		if v, ok := c.lastMintBlock.Get(minter.String()); ok {
			if h-v.(int64) < c.mintCooldownBlocks {
				panic("mint cooldown active")
			}
		}
	}
}

// mintToken performs the raw mint: supply gate on the mint-count (nextAutoTokenID,
// NOT TokenCount — Burn never reopens a slot, S-2), auto-assigns the sequential
// tid, sets the URI, and bumps the counter. Returns the tid string.
func mintToken(cur realm, c *collection, to address, tokenURI string) string {
	if c.maxSupply > 0 && c.nextAutoTokenID >= c.maxSupply {
		panic("max supply reached")
	}
	tidStr := itoa(c.nextAutoTokenID)
	tid := grc721.TokenID(tidStr)
	if err := c.nft.Mint(to, tid); err != nil {
		panic(err.Error())
	}
	if tokenURI != "" {
		if _, err := c.nft.SetTokenURI(to, tid, grc721.TokenURI(tokenURI)); err != nil {
			panic(err.Error())
		}
	}
	c.nextAutoTokenID++
	return tidStr
}

// ── Admin mint (no payment) ─────────────────────────────────────────────────

// Mint is the admin no-pay mint. Auto-assigns the next sequential tid.
func Mint(cur realm, id string, to address, tokenURI string) string {
	c := mustGet(id)
	assertCollectionAdmin(c)
	assertNotPaused(c)
	tid := mintToken(cur, c, to, tokenURI)
	chain.Emit("Mint",
		"collectionID", id,
		"tokenId", tid,
		"minter", caller().String(),
		"to", to.String(),
		"block", itoa(chainHeight()),
	)
	return tid
}

// ── Public + allowlist paid mints ───────────────────────────────────────────

// MintPublic mints in the public phase, paying mintPrice in payDenom.
func MintPublic(cur realm, id, tokenURI string) string {
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	return mintPublicInternal(cur, id, caller(), unsafe.OriginSend(), tokenURI)
}

func mintPublicInternal(cur realm, id string, minter address, sent chain.Coins, tokenURI string) string {
	c := mustGet(id)
	if c.phase != PhasePublic {
		panic("not in public phase")
	}
	return paidMint(cur, c, id, minter, sent, tokenURI, PhasePublic, false)
}

// MintAllowlist mints in the allowlist phase. The caller proves membership via
// a Merkle proof of (caller, maxQty); per-wallet quantity is enforced.
//
// `proof` is the comma-separated list of hex-encoded sibling hashes. It MUST
// cross the ABI as a single string: a vm/MsgCall arg cannot encode a []string
// (the VM only converts scalars and base64 []byte — gno convert.go), so a
// []string proof param would make this entrypoint uncallable from a wallet.
func MintAllowlist(cur realm, id string, proof string, maxQty int64, tokenURI string) string {
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	return mintAllowlistInternal(cur, id, caller(), unsafe.OriginSend(), splitProof(proof), maxQty, tokenURI)
}

// splitProof parses the comma-joined hex sibling list into the []string the
// in-realm verifier expects. An empty string yields no siblings (a single-leaf
// allowlist, where leaf must equal root).
func splitProof(proof string) []string {
	if proof == "" {
		return nil
	}
	return strings.Split(proof, ",")
}

func mintAllowlistInternal(cur realm, id string, minter address, sent chain.Coins, proof []string, maxQty int64, tokenURI string) string {
	c := mustGet(id)
	if c.phase != PhaseAllowlist {
		panic("not in allowlist phase")
	}
	if !verifyAllowlist(c.allowlistRoot, minter, maxQty, proof) {
		panic("invalid allowlist proof")
	}
	if walletCount(c, minter)+1 > maxQty {
		panic("allowlist quantity exceeded")
	}
	return paidMint(cur, c, id, minter, sent, tokenURI, PhaseAllowlist, true)
}

// paidMint is the shared CEI-ordered paid-mint path (B-1):
//   Checks → guard, !paused, gating, denom re-check (E-5), native amount.
//   Effects → mint token, bump counters, credit proceeds (BEFORE any teller).
//   Interactions → native fee/refund, or grc20 pull + fee (RealmTeller).
func paidMint(cur realm, c *collection, id string, minter address, sent chain.Coins, tokenURI string, phase int, isAllowlist bool) string {
	if c.mintGuard {
		panic("reentrancy")
	}
	c.mintGuard = true
	defer func() { c.mintGuard = false }()

	// ── Checks ──
	assertNotPaused(c)
	mintChecks(c, minter)
	denom := c.payDenom
	assertDenomAllowed(denom) // E-5: re-check at mint time
	price := c.mintPrice

	platformCut := overflow.Mul64p(price, primaryFeeBPS) / 10000
	creatorAmt := price - platformCut

	var paid int64
	native := isNativeDenom(denom)
	if native {
		paid = sumDenom(sent, "ugnot")
		if paid < price {
			panic("insufficient payment")
		}
	} else if sumDenom(sent, "ugnot") > 0 {
		// Reject ugnot attached to a grc20-priced mint: it would otherwise
		// enter the realm untracked and un-withdrawable (LOW stuck-funds trap).
		panic("no native payment on a grc20 mint")
	}

	// ── Effects (before any value movement) ──
	tid := mintToken(cur, c, minter, tokenURI)
	c.mintedByWallet.Set(minter.String(), walletCount(c, minter)+1)
	c.lastMintBlock.Set(minter.String(), chainHeight())
	creditProceeds(c, denom, creatorAmt)

	// ── Interactions ──
	if native {
		if platformCut > 0 {
			sendNative(cur, feeRecipient, platformCut)
		}
		if over := paid - price; over > 0 {
			sendNative(cur, minter, over)
		}
	} else {
		teller := grc20Teller(cur, denom)
		if err := teller.TransferFrom(0, cur, minter, selfAddr(), price); err != nil {
			panic(err.Error())
		}
		if platformCut > 0 {
			if err := teller.Transfer(0, cur, feeRecipient, platformCut); err != nil {
				panic(err.Error())
			}
		}
	}

	isSelf := minter == c.admin || minter == c.royaltyRecip
	evName := "MintPublic"
	if isAllowlist {
		evName = "MintAllowlist"
	}
	chain.Emit(evName,
		"collectionID", id,
		"tokenId", tid,
		"minter", minter.String(),
		"payer", minter.String(),
		"price", itoa(price),
		"denom", denomKey(denom),
		"primaryFee", itoa(platformCut),
		"creatorAmt", itoa(creatorAmt),
		"phase", itoa(int64(phase)),
		"isSelfMint", boolStr(isSelf),
		"mintedAfter", itoa(walletCount(c, minter)),
		"block", itoa(chainHeight()),
	)
	return tid
}

// ── Proceeds withdrawal ─────────────────────────────────────────────────────

// WithdrawProceeds sends a collection's accrued proceeds in `denom` to its
// fixed mintCustody. CEI: zero the ledger entry BEFORE sending.
func WithdrawProceeds(cur realm, id, denom string) {
	c := mustGet(id)
	assertCollectionAdmin(c)
	if c.mintGuard {
		panic("reentrancy")
	}
	c.mintGuard = true
	defer func() { c.mintGuard = false }()

	key := denomKey(denom)
	amt := proceedsOf(c, key)
	if amt <= 0 {
		panic("no proceeds")
	}
	c.proceeds.Set(key, int64(0)) // CEI: zero first

	if isNativeDenom(denom) {
		sendNative(cur, c.mintCustody, amt)
	} else {
		teller := grc20Teller(cur, denom)
		if err := teller.Transfer(0, cur, c.mintCustody, amt); err != nil {
			panic(err.Error())
		}
	}
	chain.Emit("ProceedsWithdrawn",
		"collectionID", id,
		"denom", key,
		"amount", itoa(amt),
		"to", c.mintCustody.String(),
	)
}

package memba_collections

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/demo/tokens/grc20"
	"gno.land/r/demo/defi/grc20reg"
)

func chainHeight() int64 { return runtime.ChainHeight() }

func selfAddr() address { return unsafe.CurrentRealm().Address() }

// denomKey normalizes a payDenom to its proceeds-ledger key (native → "ugnot").
func denomKey(d string) string {
	if isNativeDenom(d) {
		return "ugnot"
	}
	return d
}

// isNativeDenom reports whether a payDenom string means native ugnot.
func isNativeDenom(d string) bool { return d == "" || d == "ugnot" }

// sumDenom totals the coins of a single denom in a coin set.
func sumDenom(coins chain.Coins, denom string) int64 {
	total := int64(0)
	for _, c := range coins {
		if c.Denom == denom {
			total += c.Amount
		}
	}
	return total
}

// sendNative sends ugnot from the realm to `to` via a realm-send banker.
func sendNative(cur realm, to address, amount int64) {
	if amount <= 0 {
		return
	}
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	bnk.SendCoins(unsafe.CurrentRealm().Address(), to, chain.Coins{chain.NewCoin("ugnot", amount)})
}

// grc20Teller resolves a registered token by its grc20reg key and returns a
// RealmTeller (the realm is the spender — frozen B-1). Panics if unknown.
func grc20Teller(cur realm, denom string) grc20.Teller {
	tok := grc20reg.Get(denom)
	if tok == nil {
		panic("unknown grc20 denom: " + denom)
	}
	return tok.RealmTeller(0, cur)
}

package memba_collections

import (
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

const renderPageSize = 50

// CollectionView is a structured read of a collection's public fields.
type CollectionView struct {
	ID           string
	Creator      address
	Admin        address
	Name         string
	Symbol       string
	RoyaltyBPS   int64
	RoyaltyRecip address
	Phase        int
	MintPrice    int64
	PayDenom     string
	MaxSupply    int64
	MaxPerWallet int64
	Minted       int64
	Paused       bool
}

// CollectionInfo returns a structured view of a collection.
func CollectionInfo(id string) CollectionView {
	c := mustGet(id)
	return CollectionView{
		ID:           id,
		Creator:      c.creator,
		Admin:        c.admin,
		Name:         c.nft.Name(),
		Symbol:       c.nft.Symbol(),
		RoyaltyBPS:   c.royaltyBPS,
		RoyaltyRecip: c.royaltyRecip,
		Phase:        c.phase,
		MintPrice:    c.mintPrice,
		PayDenom:     denomKey(c.payDenom),
		MaxSupply:    c.maxSupply,
		MaxPerWallet: c.maxPerWallet,
		Minted:       c.nextAutoTokenID,
		Paused:       c.paused,
	}
}

// MintedBy returns how many tokens an address has minted in a collection.
func MintedBy(id string, who address) int64 {
	return walletCount(mustGet(id), who)
}

// Render mux:
//   ""                 → paginated collection list (?page=N)
//   "collection/<id>"  → collection detail
func Render(path string) string {
	if path == "" || strings.HasPrefix(path, "?") {
		return renderList(parsePage(path))
	}
	if strings.HasPrefix(path, "collection/") {
		return renderCollection(strings.TrimPrefix(path, "collection/"))
	}
	return "# Not found\n\nUnknown path: " + path
}

func parsePage(path string) int {
	idx := strings.Index(path, "page=")
	if idx < 0 {
		return 1
	}
	rest := path[idx+5:]
	if amp := strings.IndexByte(rest, '&'); amp >= 0 {
		rest = rest[:amp]
	}
	n := 0
	for i := 0; i < len(rest); i++ {
		c := rest[i]
		if c < '0' || c > '9' {
			break
		}
		n = n*10 + int(c-'0')
	}
	if n < 1 {
		return 1
	}
	return n
}

func renderList(page int) string {
	var b strings.Builder
	b.WriteString("# Memba Collections\n\n")
	if paused {
		b.WriteString("> ⚠️ Registry is globally paused.\n\n")
	}
	total := collections.Size()
	if total == 0 {
		b.WriteString("_No collections yet._\n")
		return b.String()
	}
	start := (page - 1) * renderPageSize
	end := start + renderPageSize
	i := 0
	shown := 0
	collections.Iterate("", "", func(key string, v any) bool {
		if i >= start && i < end {
			c := v.(*collection)
			b.WriteString(ufmt.Sprintf("- **%s** (%s) — phase %d, minted %d\n",
				c.nft.Name(), key, c.phase, c.nextAutoTokenID))
			shown++
		}
		i++
		return i >= end
	})
	b.WriteString(ufmt.Sprintf("\n_Page %d — %d of %d collections._\n", page, shown, total))
	return b.String()
}

func renderCollection(id string) string {
	v, ok := collections.Get(id)
	if !ok {
		return "# Not found\n\nNo collection: " + id
	}
	c := v.(*collection)
	var b strings.Builder
	b.WriteString(ufmt.Sprintf("# %s (%s)\n\n", c.nft.Name(), c.nft.Symbol()))
	b.WriteString(ufmt.Sprintf("- ID: `%s`\n", id))
	b.WriteString(ufmt.Sprintf("- Creator: %s\n", c.creator.String()))
	b.WriteString(ufmt.Sprintf("- Admin: %s\n", c.admin.String()))
	b.WriteString(ufmt.Sprintf("- Royalty: %d bps → %s\n", c.royaltyBPS, c.royaltyRecip.String()))
	b.WriteString(ufmt.Sprintf("- Phase: %d\n", c.phase))
	b.WriteString(ufmt.Sprintf("- Mint price: %d %s\n", c.mintPrice, denomKey(c.payDenom)))
	b.WriteString(ufmt.Sprintf("- Supply: %d", c.nextAutoTokenID))
	if c.maxSupply > 0 {
		b.WriteString(ufmt.Sprintf(" / %d", c.maxSupply))
	}
	b.WriteString("\n")
	if c.paused {
		b.WriteString("- ⚠️ Paused\n")
	}
	return b.String()
}

package memba_collections

import (
	"chain"
	"math/overflow"

	"gno.land/p/samcrew/grc721"
)

// SetRoyalty updates the collection-default royalty. Admin only; bps must be
// in [MinCreatorRoyaltyBPS, maxCreatorRoyaltyBPS].
func SetRoyalty(cur realm, id string, recip address, bps int64) {
	c := mustGet(id)
	assertCollectionAdmin(c)
	if bps < MinCreatorRoyaltyBPS || bps > maxCreatorRoyaltyBPS {
		panic("royalty out of range")
	}
	c.royaltyRecip, c.royaltyBPS = recip, bps
	chain.Emit("RoyaltySet", "collectionID", id, "bps", itoa(bps), "recip", recip.String())
}

// SetTokenRoyalty sets a per-token royalty override. PRESENCE of the override
// wins over the collection default — even bps==0 means "royalty OFF for this
// token" (S-1). Admin only; bps <= maxCreatorRoyaltyBPS.
func SetTokenRoyalty(cur realm, id string, tid grc721.TokenID, recip address, bps int64) {
	c := mustGet(id)
	assertCollectionAdmin(c)
	if bps < MinCreatorRoyaltyBPS || bps > maxCreatorRoyaltyBPS {
		panic("royalty out of range")
	}
	c.tokenRoyalty.Set(string(tid), royalty{recip: recip, bps: bps})
	chain.Emit("TokenRoyaltySet", "collectionID", id, "tokenId", string(tid), "bps", itoa(bps), "recip", recip.String())
}

// ClearTokenRoyalty removes a per-token override; the token falls back to the
// collection default. Admin only.
func ClearTokenRoyalty(cur realm, id string, tid grc721.TokenID) {
	c := mustGet(id)
	assertCollectionAdmin(c)
	c.tokenRoyalty.Remove(string(tid))
	chain.Emit("TokenRoyaltyCleared", "collectionID", id, "tokenId", string(tid))
}

// resolveRoyalty returns the effective (recip, bps) for a token, applying the
// frozen precedence: per-token override PRESENCE wins (even bps==0); else the
// collection default.
func resolveRoyalty(c *collection, tid grc721.TokenID) (address, int64) {
	if v, ok := c.tokenRoyalty.Get(string(tid)); ok {
		r := v.(royalty)
		return r.recip, r.bps
	}
	return c.royaltyRecip, c.royaltyBPS
}

// RoyaltyInfo returns the royalty recipient and amount owed on a sale. Returns
// ("", 0) when royalty is disabled for the token (bps==0 or recip==""). This
// is a read; marketplace engines call it to settle royalties atomically.
func RoyaltyInfo(id string, tid grc721.TokenID, salePrice int64) (address, int64) {
	c := mustGet(id)
	recip, bps := resolveRoyalty(c, tid)
	if bps == 0 || recip == "" {
		return "", 0
	}
	return recip, overflow.Mul64p(salePrice, bps) / 10000
}

package memba_collections

import (
	"chain"

	"gno.land/p/samcrew/grc721"
)

// ── Owner approvals ─────────────────────────────────────────────────────────

// Approve grants single-token transfer approval. Caller must own/operate.
func Approve(cur realm, id string, operator address, tid grc721.TokenID) {
	c := mustGet(id)
	if err := c.nft.Approve(caller(), operator, tid); err != nil {
		panic(err.Error())
	}
}

// SetApprovalForAll grants/revokes operator approval for all the caller's
// tokens in the collection (this is how a seller authorizes a marketplace).
func SetApprovalForAll(cur realm, id string, operator address, approved bool) {
	c := mustGet(id)
	if err := c.nft.SetApprovalForAll(caller(), operator, approved); err != nil {
		panic(err.Error())
	}
}

// ── Burn ─────────────────────────────────────────────────────────────────────

// Burn destroys a token the caller owns and clears any per-token royalty.
// Burning never reopens a supply slot (nextAutoTokenID only increments, S-2).
func Burn(cur realm, id string, tid grc721.TokenID) {
	c := mustGet(id)
	owner, err := c.nft.OwnerOf(tid)
	if err != nil {
		panic(err.Error())
	}
	if caller() != owner {
		panic("caller is not owner")
	}
	if err := c.nft.Burn(tid); err != nil {
		panic(err.Error())
	}
	c.tokenRoyalty.Remove(string(tid))
	chain.Emit("Burned", "collectionID", id, "tokenId", string(tid), "owner", owner.String())
}

// ── Settlement (registered markets only) ─────────────────────────────────────

func isRegisteredMarket(a address) bool {
	v, ok := registeredMarkets.Get(a.String())
	return ok && v.(bool)
}

// MarketTransfer is the ONLY token-movement path. Only a registered market
// realm may call it; it moves the token via the realm's internal ledger with
// the market as the grc721 caller (the seller must have approved the market).
func MarketTransfer(cur realm, id string, from, to address, tid grc721.TokenID) {
	market := caller()
	if !isRegisteredMarket(market) {
		panic("unauthorized market")
	}
	c := mustGet(id)
	assertNotPaused(c)
	if err := c.nft.TransferFrom(market, from, to, tid); err != nil {
		panic(err.Error())
	}
	chain.Emit("MarketTransfer",
		"collectionID", id,
		"from", from.String(),
		"to", to.String(),
		"tokenId", string(tid),
	)
}

// ── Reads (IGRC721Reader surface + URI) ──────────────────────────────────────

func OwnerOf(id string, tid grc721.TokenID) address {
	o, err := mustGet(id).nft.OwnerOf(tid)
	if err != nil {
		panic(err.Error())
	}
	return o
}

func BalanceOf(id string, owner address) int64 {
	b, err := mustGet(id).nft.BalanceOf(owner)
	if err != nil {
		panic(err.Error())
	}
	return b
}

func GetApproved(id string, tid grc721.TokenID) address {
	a, err := mustGet(id).nft.GetApproved(tid)
	if err != nil {
		return ""
	}
	return a
}

func IsApprovedForAll(id string, owner, operator address) bool {
	return mustGet(id).nft.IsApprovedForAll(owner, operator)
}

func TokenURI(id string, tid grc721.TokenID) string {
	u, err := mustGet(id).nft.TokenURI(tid)
	if err != nil {
		return ""
	}
	return u
}

func TokenCount(id string) int64 { return mustGet(id).nft.TokenCount() }

func IsRegisteredMarket(a address) bool { return isRegisteredMarket(a) }

package memba_nft_market_v3

// Admin operations — multisig-gated controls.
//
// assertAdmin() is the single authorization gate; caller = unsafe.PreviousRealm().Address().
// AdminDelist is pause-exempt (moderation can always remove content).
// SetFeeRecipient changes where platform fees flow (default = AdminAddress).

import (
	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/samcrew/grc721"
)

func assertAdmin() {
	if unsafe.PreviousRealm().Address() != address(AdminAddress) {
		panic("admin only")
	}
}

// Pause halts new trade operations (ListNFT, BuyNFT, MakeOffer, AcceptOffer).
// Value-exit paths (DelistNFT, CancelOffer, ClaimExpiredOffer) remain available.
func Pause(cur realm) {
	assertAdmin()
	paused = true
	chain.Emit("MarketPaused", "by", unsafe.PreviousRealm().Address().String())
}

// Unpause resumes normal operations.
func Unpause(cur realm) {
	assertAdmin()
	paused = false
	chain.Emit("MarketUnpaused", "by", unsafe.PreviousRealm().Address().String())
}

// AdminDelist force-removes any listing. Pause-exempt (moderation).
func AdminDelist(cur realm, collectionID string, tid grc721.TokenID) {
	assertAdmin()
	key := listingKey(collectionID, string(tid))
	if _, exists := listings.Get(key); !exists {
		panic("not listed: " + key)
	}
	listings.Remove(key)
	removeFromOrder(key)
	chain.Emit("AdminDelisted",
		"collection", collectionID,
		"tokenId", string(tid),
		"admin", unsafe.PreviousRealm().Address().String(),
	)
}

// SetFeeRecipient updates the address that receives platform fees.
func SetFeeRecipient(cur realm, addr address) {
	assertAdmin()
	feeRecipient = addr
	chain.Emit("FeeRecipientChanged", "newRecipient", addr.String())
}

package memba_nft_market_v3

// NFT Marketplace v3 — General-purpose NFT trading for the Memba ecosystem on test13.
//
// v3 is a fork of the audited memba_nft_market_v2 engine, repointed at the new
// canonical registry realm `memba_collections` (was `memba_nft_v2`). It keeps the
// proven structure: CEI payment ordering, IsUserCall guards on payable entrypoints,
// escrowed offers, GRC2981-style royalty settlement, and a platform-fee split.
//
// Changes vs v2:
//   1. Platform fee 2.5% → 2.0% (FeeBPS 250 → 200). See params.gno.
//   2. Every settlement event now carries the payment `denom` (forward-compat for
//      the GRC20 settlement desk; "ugnot" today). See SettlementDenom.
//   3. Settlement is reported via ONE canonical `Sale` event per sale, with a
//      `via` field = "buy" | "offer". v2 emitted BOTH `OfferAccepted` AND
//      `TokenSold` on an accepted offer, which double-counted volume in indexers.
//      v3 collapses that to the single `Sale` event (BuyNFT emits via="buy",
//      AcceptOffer emits via="offer"). The legacy `PurchaseConfirmed` /
//      `OfferAccepted` / `TokenSold` event names are intentionally retired.
//   4. Imports `memba_collections` for MarketTransfer / RoyaltyInfo. The collection
//      ABI is identical to v2's (same signatures), so no call-site adaptation was
//      needed beyond the import path.
//
// SCOPE (this engine): fixed-price listings (list/delist), buy, escrowed offers
// (make/cancel/accept/claim-expired), royalty settlement, platform-fee split,
// IsUserCall guards, pause.
//
// PHASE 3+ (deferred): the following are intentionally NOT built in this engine and
// are follow-on initiatives:
//   - Collection offers (offers on any token in a collection, not a specific id)
//   - Sweep (buy N cheapest listings in one tx)
//   - Auctions (timed / English / Dutch)
//   - GRC20 settlement desk (settle in $MEMBA or other GRC20; SettlementDenom is the
//     forward-compat hook already threaded onto every settlement event)
//   - DAO-curated badge (verified-collection curation)
//   - Points → $MEMBA claim (trading-rewards accrual + claim)
//
// Security:
//   - CEI (Checks-Effects-Interactions) in all payment flows
//   - IsUserCall guard on BuyNFT and MakeOffer (payment-bearing fns)
//   - Offer escrow with OfferTimeoutBlk safety valve (ClaimExpiredOffer)
//   - MinOfferLifetimeBlk prevents instant-cancel front-run
//   - Only original lister can delist (pause-exempt exit)
//   - Self-buy prevention
//   - Defense-in-depth royalty clamp even when collection enforces its own cap

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/samcrew/grc721"
	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"

	nft "gno.land/r/samcrew/memba_collections" // v3 change #4: canonical registry (was memba_nft_v2)
)

// ── Types ─────────────────────────────────────────────────────────────────────

// Listing represents a fixed-price sale order.
type Listing struct {
	CollectionID string
	TokenID      string
	Seller       address
	Price        int64
	CreatedBlk   int64
}

// Sale records a completed transaction for the salesLog.
type Sale struct {
	CollectionID string
	TokenID      string
	Seller       address
	Buyer        address
	Price        int64
	Fee          int64
	Royalty      int64
	Blk          int64
}

// ── State ─────────────────────────────────────────────────────────────────────

var (
	listings     *avl.Tree // listingKey -> *Listing
	offers       *avl.Tree // offerKey   -> *Offer
	salesLog     *avl.Tree // itoa(saleId) -> *Sale
	listingOrder []string  // insertion-ordered listing keys (pagination)
	nextSaleId   int64
	totalVolume  int64
	paused       bool
	feeRecipient = address(AdminAddress)
)

func init() {
	listings = avl.NewTree()
	offers = avl.NewTree()
	salesLog = avl.NewTree()
}

// ── Key helpers ───────────────────────────────────────────────────────────────

func listingKey(collectionID, tokenID string) string {
	return collectionID + ":" + tokenID
}

func offerKey(collectionID, tokenID string, buyer address) string {
	return collectionID + ":" + tokenID + ":" + string(buyer)
}

func itoa(n int64) string { return strconv.FormatInt(n, 10) }

// sumUgnot returns the total ugnot in a coin set.
func sumUgnot(coins chain.Coins) int64 {
	for _, c := range coins {
		if c.Denom == "ugnot" {
			return c.Amount
		}
	}
	return 0
}

// removeFromOrder removes a key from the ordered listing slice (O(n)).
func removeFromOrder(key string) {
	for i, k := range listingOrder {
		if k == key {
			listingOrder = append(listingOrder[:i], listingOrder[i+1:]...)
			return
		}
	}
}

// countListingsBySeller counts a seller's open listings. Bounded by MaxListings.
func countListingsBySeller(seller address) int {
	n := 0
	listings.Iterate("", "", func(_ string, v interface{}) bool {
		if v.(*Listing).Seller == seller {
			n++
		}
		return false
	})
	return n
}

// countOffersByBuyer counts a buyer's open offers. Bounded by MaxOffers.
func countOffersByBuyer(buyer address) int {
	n := 0
	offers.Iterate("", "", func(_ string, v interface{}) bool {
		if v.(*Offer).Buyer == buyer {
			n++
		}
		return false
	})
	return n
}

// ── List / Delist ─────────────────────────────────────────────────────────────

// ListNFT lists an NFT for fixed-price sale.
// PREREQUISITE: Owner must call memba_collections.SetApprovalForAll(collectionID,
// marketplace, true) first so MarketTransfer can execute on behalf of the seller.
func ListNFT(cur realm, collectionID string, tid grc721.TokenID, price int64) {
	if paused {
		panic("market paused")
	}
	seller := unsafe.PreviousRealm().Address()

	if price < MinPrice {
		panic(ufmt.Sprintf("price must be >= %d ugnot", MinPrice))
	}
	if price > MaxPrice {
		panic(ufmt.Sprintf("price must be <= %d ugnot", MaxPrice))
	}
	if listings.Size() >= MaxListings {
		panic("marketplace listing limit reached")
	}
	if countListingsBySeller(seller) >= MaxListingsPerAddr {
		panic("seller listing limit reached")
	}

	key := listingKey(collectionID, string(tid))
	if _, exists := listings.Get(key); exists {
		panic("already listed: " + key)
	}

	// Effects
	listings.Set(key, &Listing{
		CollectionID: collectionID,
		TokenID:      string(tid),
		Seller:       seller,
		Price:        price,
		CreatedBlk:   runtime.ChainHeight(),
	})
	listingOrder = append(listingOrder, key)

	chain.Emit("NFTListed",
		"collection", collectionID,
		"tokenId", string(tid),
		"seller", seller.String(),
		"price", itoa(price),
	)
}

// DelistNFT removes a listing. Only the original lister can delist. Pause-exempt
// (value-exit: unwinds the seller's position).
func DelistNFT(cur realm, collectionID string, tid grc721.TokenID) {
	caller := unsafe.PreviousRealm().Address()
	key := listingKey(collectionID, string(tid))

	val, exists := listings.Get(key)
	if !exists {
		panic("not listed: " + key)
	}
	l := val.(*Listing)
	if l.Seller != caller {
		panic("only seller can delist")
	}

	// Effects
	listings.Remove(key)
	removeFromOrder(key)

	chain.Emit("NFTDelisted",
		"collection", collectionID,
		"tokenId", string(tid),
		"seller", caller.String(),
	)
}

// ── Buy ───────────────────────────────────────────────────────────────────────

// BuyNFT purchases a listed NFT atomically (CEI order).
//
// CEI:
//   Checks  — paused / IsUserCall / listed / self-buy / payment amount
//   Effects — remove listing from state, record sale, update volume
//   Interactions — cross-call MarketTransfer, then banker payouts (seller last)
func BuyNFT(cur realm, collectionID string, tid grc721.TokenID) {
	if paused {
		panic("market paused")
	}
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	key := listingKey(collectionID, string(tid))
	v, ok := listings.Get(key)
	if !ok {
		panic("listing not found")
	}
	l := v.(*Listing)
	buyer := unsafe.PreviousRealm().Address()
	if buyer == l.Seller {
		panic("cannot buy own listing")
	}
	if sumUgnot(unsafe.OriginSend()) != l.Price {
		panic("incorrect payment")
	}

	royRecip, royAmt := nft.RoyaltyInfo(collectionID, tid, l.Price)
	fee, royalty, sellerAmt := splitProceeds(l.Price, royAmt)

	// Effects (before cross-call + sends)
	seller := l.Seller
	price := l.Price
	listings.Remove(key)
	removeFromOrder(key)
	recordSale(collectionID, string(tid), seller, buyer, price, fee, royalty)
	totalVolume += price

	// Interactions
	nft.MarketTransfer(cross(cur), collectionID, seller, buyer, tid)
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	self := unsafe.CurrentRealm().Address()
	if royalty > 0 {
		bnk.SendCoins(self, royRecip, chain.Coins{chain.NewCoin("ugnot", royalty)})
	}
	if fee > 0 {
		bnk.SendCoins(self, feeRecipient, chain.Coins{chain.NewCoin("ugnot", fee)})
	}
	bnk.SendCoins(self, seller, chain.Coins{chain.NewCoin("ugnot", sellerAmt)}) // seller last

	// v3 change #3: single canonical settlement event (via="buy").
	emitSale("buy", collectionID, string(tid), seller, buyer, price, fee, royalty, royRecip, sellerAmt)
}

// ── emitSale ──────────────────────────────────────────────────────────────────

// emitSale emits the ONE canonical settlement event for a completed sale.
// v3 change #3: replaces v2's split PurchaseConfirmed / (OfferAccepted + TokenSold)
// events with a single `Sale` event keyed by `via` ("buy" | "offer"), so indexers
// count each sale exactly once. v3 change #2: carries the payment `denom`.
func emitSale(via, collectionID, tokenID string, seller, buyer address, price, fee, royalty int64, royRecip address, sellerAmt int64) {
	chain.Emit("Sale",
		"via", via,
		"collection", collectionID,
		"tokenId", tokenID,
		"seller", seller.String(),
		"buyer", buyer.String(),
		"price", itoa(price),
		"fee", itoa(fee),
		"royalty", itoa(royalty),
		"royaltyRecipient", royRecip.String(),
		"sellerAmount", itoa(sellerAmt),
		"denom", SettlementDenom,
	)
}

// ── splitProceeds ─────────────────────────────────────────────────────────────

// splitProceeds computes the three-way split of a sale price.
// royaltyAmount comes pre-computed from nft.RoyaltyInfo (already the actual
// amount, not bps). We clamp it defensively against MaxRoyaltyBPS.
func splitProceeds(price, royaltyAmount int64) (fee, royalty, seller int64) {
	if price < MinPrice {
		panic("price below minimum")
	}
	if price > MaxPrice {
		panic("price above maximum")
	}
	fee = price * FeeBPS / 10000
	royalty = royaltyAmount
	if royalty < 0 {
		royalty = 0
	}
	maxRoy := price * MaxRoyaltyBPS / 10000
	if royalty > maxRoy {
		royalty = maxRoy // defense-in-depth clamp
	}
	if fee+royalty >= price {
		panic("fee plus royalty exceeds price")
	}
	seller = price - fee - royalty
	if seller <= 0 {
		panic("seller amount not positive")
	}
	return
}

// ── recordSale ────────────────────────────────────────────────────────────────

func recordSale(collectionID, tokenID string, seller, buyer address, price, fee, royalty int64) {
	nextSaleId++
	salesLog.Set(itoa(nextSaleId), &Sale{
		CollectionID: collectionID,
		TokenID:      tokenID,
		Seller:       seller,
		Buyer:        buyer,
		Price:        price,
		Fee:          fee,
		Royalty:      royalty,
		Blk:          runtime.ChainHeight(),
	})
}

// ── IsPaused ─────────────────────────────────────────────────────────────────

func IsPaused() bool { return paused }

// ── truncAddr / truncPath (render helpers) ────────────────────────────────────

func truncAddr(addr address) string {
	s := string(addr)
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

func truncPath(path string) string {
	parts := strings.Split(path, "/")
	if len(parts) > 2 {
		return parts[len(parts)-1]
	}
	return path
}

package memba_nft_market_v3

// Offer management — escrowed buyer offers on any listed NFT.
//
// Lifecycle:
//   MakeOffer      — buyer sends ugnot, funds held in escrow by this realm
//   CancelOffer    — buyer cancels (pause-exempt; must wait MinOfferLifetimeBlk)
//   AcceptOffer    — listing seller accepts; settles atomically via MarketTransfer + payouts
//   ClaimExpiredOffer — anyone claims refund after OfferTimeoutBlk (safety valve)
//
// Pause policy: MakeOffer + AcceptOffer are blocked while paused (new escrow /
// new settlement). CancelOffer + ClaimExpiredOffer are pause-exempt (value-exit).
//
// PHASE 3+ (deferred): collection-wide offers (an offer that matches ANY token in a
// collection rather than a specific token id) are NOT built here — see the deferred
// list in market.gno. This engine only supports per-token offers.

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/samcrew/grc721"
	"gno.land/p/nt/ufmt/v0"

	nft "gno.land/r/samcrew/memba_collections" // v3 change #4: canonical registry (was memba_nft_v2)
)

// Offer is an escrowed buy proposal on a specific (collection, token) pair.
type Offer struct {
	CollectionID string
	TokenID      string
	Buyer        address
	Amount       int64 // ugnot held in escrow
	CreatedBlk   int64
}

// MakeOffer places an offer with escrowed funds.
// Caller must send ugnot with the transaction; funds are held by this realm.
func MakeOffer(cur realm, collectionID string, tid grc721.TokenID) {
	if paused {
		panic("market paused")
	}
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("must be a direct user call")
	}
	buyer := unsafe.PreviousRealm().Address()
	amt := sumUgnot(unsafe.OriginSend())
	if amt < MinPrice {
		panic("offer below minimum")
	}

	if offers.Size() >= MaxOffers {
		panic("offer limit reached")
	}
	if countOffersByBuyer(buyer) >= MaxOffersPerAddr {
		panic("buyer offer limit reached")
	}

	key := offerKey(collectionID, string(tid), buyer)
	if _, exists := offers.Get(key); exists {
		panic("offer already exists, cancel first")
	}

	// Effects
	offers.Set(key, &Offer{
		CollectionID: collectionID,
		TokenID:      string(tid),
		Buyer:        buyer,
		Amount:       amt,
		CreatedBlk:   runtime.ChainHeight(),
	})

	chain.Emit("OfferMade",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", buyer.String(),
		"amount", itoa(amt),
	)
}

// CancelOffer allows the offerer to reclaim escrowed funds.
// Pause-exempt (value-exit). Must wait MinOfferLifetimeBlk to prevent front-run.
func CancelOffer(cur realm, collectionID string, tid grc721.TokenID) {
	caller := unsafe.PreviousRealm().Address()
	key := offerKey(collectionID, string(tid), caller)

	val, exists := offers.Get(key)
	if !exists {
		panic("offer not found")
	}
	o := val.(*Offer)

	age := runtime.ChainHeight() - o.CreatedBlk
	if age < MinOfferLifetimeBlk {
		panic(ufmt.Sprintf("offer too new to cancel: %d blocks remaining", MinOfferLifetimeBlk-age))
	}

	// Effects
	amt := o.Amount
	offers.Remove(key)

	// Interactions
	refund(cur, caller, amt)

	chain.Emit("OfferCancelled",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", caller.String(),
		"amount", itoa(amt),
	)
}

// ClaimExpiredOffer returns escrowed funds when an offer has exceeded OfferTimeoutBlk.
// Pause-exempt (safety-valve: prevents permanent escrow lock).
// Anyone can call on behalf of the buyer, but funds always go to the buyer.
func ClaimExpiredOffer(cur realm, collectionID string, tid grc721.TokenID, buyer address) {
	key := offerKey(collectionID, string(tid), buyer)

	val, exists := offers.Get(key)
	if !exists {
		panic("offer not found")
	}
	o := val.(*Offer)

	age := runtime.ChainHeight() - o.CreatedBlk
	if age < OfferTimeoutBlk {
		panic(ufmt.Sprintf("offer not yet expired: %d blocks remaining", OfferTimeoutBlk-age))
	}

	// Effects
	amt := o.Amount
	offers.Remove(key)

	// Interactions
	refund(cur, buyer, amt)

	chain.Emit("OfferExpiredClaimed",
		"collection", collectionID,
		"tokenId", string(tid),
		"buyer", buyer.String(),
		"amount", itoa(amt),
	)
}

// AcceptOffer allows the listing seller to accept a buyer's escrowed offer.
// Requires an active listing (seller must have listed first).
// Settles atomically: cross-call MarketTransfer then pay royalty, fee, seller (seller last).
func AcceptOffer(cur realm, collectionID string, tid grc721.TokenID, buyer address) {
	if paused {
		panic("market paused")
	}
	seller := unsafe.PreviousRealm().Address()

	listKey := listingKey(collectionID, string(tid))
	lv, listed := listings.Get(listKey)
	if !listed {
		panic("AcceptOffer requires an active listing — list the NFT first")
	}
	l := lv.(*Listing)
	if l.Seller != seller {
		panic("only the listing seller can accept offers")
	}

	if buyer == seller {
		panic("cannot accept own offer")
	}

	oKey := offerKey(collectionID, string(tid), buyer)
	ov, exists := offers.Get(oKey)
	if !exists {
		panic("offer not found")
	}
	o := ov.(*Offer)

	royRecip, royAmt := nft.RoyaltyInfo(collectionID, tid, o.Amount)
	fee, royalty, sellerAmt := splitProceeds(o.Amount, royAmt)

	// Effects (before cross-call + sends)
	amt := o.Amount
	offers.Remove(oKey)
	listings.Remove(listKey)
	removeFromOrder(listKey)
	recordSale(collectionID, string(tid), seller, buyer, amt, fee, royalty)
	totalVolume += amt

	// Interactions
	nft.MarketTransfer(cross(cur), collectionID, seller, buyer, tid)
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	self := unsafe.CurrentRealm().Address()
	if royalty > 0 {
		bnk.SendCoins(self, royRecip, chain.Coins{chain.NewCoin("ugnot", royalty)})
	}
	if fee > 0 {
		bnk.SendCoins(self, feeRecipient, chain.Coins{chain.NewCoin("ugnot", fee)})
	}
	bnk.SendCoins(self, seller, chain.Coins{chain.NewCoin("ugnot", sellerAmt)}) // seller last

	// v3 change #3: ONE canonical settlement event (via="offer"). v2 emitted BOTH
	// OfferAccepted AND TokenSold here, double-counting the sale in indexers.
	emitSale("offer", collectionID, string(tid), seller, buyer, amt, fee, royalty, royRecip, sellerAmt)
}

// refund sends escrowed ugnot back to a recipient from this realm's balance.
func refund(cur realm, to address, amt int64) {
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	bnk.SendCoins(unsafe.CurrentRealm().Address(), to, chain.Coins{chain.NewCoin("ugnot", amt)})
}

